        private async Task HandleAccountMobileVerificationSendAsync(HttpContext context)
        {
            var sessionUser = GetSessionUser(context);
            if (sessionUser == null)
            {
                await Results.Json(
                    new AccountActionResponse(false, "Not signed in."),
                    statusCode: StatusCodes.Status401Unauthorized
                ).ExecuteAsync(context);
                return;
            }

            if (IsStaffAutoLogin(context))
            {
                await Results.Json(
                    new AccountActionResponse(false, "Staff auto-login cannot update customer mobile verification. Please ask the customer to make this change."),
                    statusCode: StatusCodes.Status403Forbidden
                ).ExecuteAsync(context);
                return;
            }

            var request = await context.Request.ReadFromJsonAsync<AccountMobileVerificationSendRequest>();
            var mobileNumber = NormalizeSmsMobileNumber(request?.MobileNumber ?? "", request?.CountryCode ?? "");
            if (string.IsNullOrWhiteSpace(mobileNumber))
            {
                await Results.BadRequest(new AccountActionResponse(false, "Enter a valid mobile number.")).ExecuteAsync(context);
                return;
            }

            if (mobileNumber.StartsWith("7", StringComparison.Ordinal))
            {
                await Results.BadRequest(new AccountActionResponse(false, "This phone number is not reachable for SMS verification.")).ExecuteAsync(context);
                return;
            }

            var connectionString = GetEhbConfigConnectionString();
            if (string.IsNullOrWhiteSpace(connectionString))
            {
                await Results.Problem("Missing EhbConfig connection string.").ExecuteAsync(context);
                return;
            }

            await using var connection = new SqlConnection(connectionString);
            await connection.OpenAsync();

            if (!await IsMobileNumberAvailableForCustomerAsync(connection, sessionUser.CustomerId, mobileNumber))
            {
                await Results.BadRequest(new AccountActionResponse(false, "This mobile number is already used by another account.")).ExecuteAsync(context);
                return;
            }

            if (!await CanSendSmsVerificationAsync(connection, sessionUser.CustomerId))
            {
                await Results.Json(
                    new AccountActionResponse(false, "SMS verification is locked after 3 sends in 10 hours. Please try again later."),
                    statusCode: StatusCodes.Status429TooManyRequests
                ).ExecuteAsync(context);
                return;
            }

            var pin = RandomNumberGenerator.GetInt32(0, 10000).ToString("D4", CultureInfo.InvariantCulture);
            var brandDomain = GetBrandDomainForCustomer(sessionUser.CustomerId);
            var sentStatus = await SendSmsVerificationPinAsync(mobileNumber, pin, brandDomain);

            if (sentStatus.Contains("success", StringComparison.OrdinalIgnoreCase))
            {
                await InsertSmsVerificationAsync(connection, sessionUser.CustomerId, mobileNumber, pin, sentStatus);
                await Results.Ok(new AccountActionResponse(true, "PIN sent.")).ExecuteAsync(context);
                return;
            }

            var message = sentStatus.Contains("is not a mobile number", StringComparison.OrdinalIgnoreCase)
                || sentStatus.Contains("is not a valid phone number", StringComparison.OrdinalIgnoreCase)
                ? $"Please enter a valid phone number. +{mobileNumber} is not a valid number."
                : sentStatus.Contains("is not currently reachable", StringComparison.OrdinalIgnoreCase)
                    ? "This phone number is not currently reachable."
                    : "SMS gateway did not send the PIN.";

            await Results.BadRequest(new AccountActionResponse(false, message)).ExecuteAsync(context);
        }

        private async Task HandleAccountMobileVerificationConfirmAsync(HttpContext context)
        {
            var sessionUser = GetSessionUser(context);
            if (sessionUser == null)
            {
                await Results.Json(
                    new AccountSettingsResponse(false, "Not signed in.", null),
                    statusCode: StatusCodes.Status401Unauthorized
                ).ExecuteAsync(context);
                return;
            }

            if (IsStaffAutoLogin(context))
            {
                await Results.Json(
                    new AccountSettingsResponse(false, "Staff auto-login cannot update customer mobile verification. Please ask the customer to make this change.", null),
                    statusCode: StatusCodes.Status403Forbidden
                ).ExecuteAsync(context);
                return;
            }

            var request = await context.Request.ReadFromJsonAsync<AccountMobileVerificationConfirmRequest>();
            var mobileNumber = NormalizeSmsMobileNumber(request?.MobileNumber ?? "", request?.CountryCode ?? "");
            var pin = Regex.Replace(request?.Pin ?? "", "[^0-9]", "");
            if (string.IsNullOrWhiteSpace(mobileNumber) || pin.Length != 4)
            {
                await Results.BadRequest(new AccountSettingsResponse(false, "Enter the mobile number and 4-digit PIN.", null)).ExecuteAsync(context);
                return;
            }

            var connectionString = GetEhbConfigConnectionString();
            if (string.IsNullOrWhiteSpace(connectionString))
            {
                await Results.Problem("Missing EhbConfig connection string.").ExecuteAsync(context);
                return;
            }

            await using var connection = new SqlConnection(connectionString);
            await connection.OpenAsync();

            if (!await HasMatchingSmsVerificationAsync(connection, sessionUser.CustomerId, mobileNumber, pin))
            {
                await Results.BadRequest(new AccountSettingsResponse(false, "Invalid or expired SMS PIN.", null)).ExecuteAsync(context);
                return;
            }

            const string updateSql = @"
UPDATE dbo.customer_profile
SET status = 1,
    mobile_number = @mobileNumber
WHERE customerID = @customerId";

            await using (var command = new SqlCommand(updateSql, connection))
            {
                command.Parameters.AddWithValue("@mobileNumber", mobileNumber);
                command.Parameters.AddWithValue("@customerId", sessionUser.CustomerId);
                await command.ExecuteNonQueryAsync();
            }

            var settings = await LoadAccountSettingsAsync(connection, sessionUser.CustomerId);
            await Results.Ok(new AccountSettingsResponse(true, "Phone number updated.", settings)).ExecuteAsync(context);
        }

        private static string NormalizeSmsMobileNumber(string mobileNumber, string countryCode)
        {
            var rawMobile = Regex.Replace(mobileNumber ?? "", "[^0-9]", "");
            var rawCountry = Regex.Replace(countryCode ?? "", "[^0-9]", "");
            if (string.IsNullOrWhiteSpace(rawMobile))
            {
                return "";
            }

            if (!string.IsNullOrWhiteSpace(rawCountry) && !rawMobile.StartsWith(rawCountry, StringComparison.Ordinal))
            {
                rawMobile = rawCountry + rawMobile.TrimStart('0');
            }

            return rawMobile.TrimStart('+');
        }

        private static async Task<bool> IsMobileNumberAvailableForCustomerAsync(SqlConnection connection, long customerId, string mobileNumber)
        {
            const string sql = @"
SELECT TOP 1 customerID
FROM dbo.customer_profile
WHERE mobile_number = @mobileNumber
  AND customerID <> @customerId";

            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@mobileNumber", mobileNumber);
            command.Parameters.AddWithValue("@customerId", customerId);
            var result = await command.ExecuteScalarAsync();
            return result == null || result == DBNull.Value;
        }

        private static async Task<bool> CanSendSmsVerificationAsync(SqlConnection connection, long customerId)
        {
            const string sql = @"
SELECT COUNT(*)
FROM dbo.sms_verify
WHERE sent_time >= DATEADD(hh, -10, SYSDATETIME())
  AND customerID = @customerId";

            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@customerId", customerId);
            var count = Convert.ToInt32(await command.ExecuteScalarAsync(), CultureInfo.InvariantCulture);
            return count <= 2;
        }

        private static async Task InsertSmsVerificationAsync(SqlConnection connection, long customerId, string mobileNumber, string verifyCode, string sentStatus)
        {
            const string sql = @"
INSERT INTO dbo.sms_verify (customerID, mobile_number, verify_code, sent_status, sent_time)
VALUES (@customerId, @mobileNumber, @verifyCode, @sentStatus, GETDATE())";

            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@customerId", customerId);
            command.Parameters.AddWithValue("@mobileNumber", mobileNumber);
            command.Parameters.AddWithValue("@verifyCode", verifyCode);
            command.Parameters.AddWithValue("@sentStatus", sentStatus.Length > 1000 ? sentStatus[..1000] : sentStatus);
            await command.ExecuteNonQueryAsync();
        }

        private static async Task<bool> HasMatchingSmsVerificationAsync(SqlConnection connection, long customerId, string mobileNumber, string verifyCode)
        {
            const string sql = @"
SELECT TOP 1 1
FROM dbo.sms_verify
WHERE customerID = @customerId
  AND mobile_number = @mobileNumber
  AND verify_code = @verifyCode
  AND sent_time >= DATEADD(hh, -10, SYSDATETIME())
ORDER BY sent_time DESC";

            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@customerId", customerId);
            command.Parameters.AddWithValue("@mobileNumber", mobileNumber);
            command.Parameters.AddWithValue("@verifyCode", verifyCode);
            var result = await command.ExecuteScalarAsync();
            return result != null && result != DBNull.Value;
        }

        private async Task<string> SendSmsVerificationPinAsync(string mobileNumber, string pin, string brandDomain)
        {
            try
            {
                var gatewayUrl = ConfigOrEnv("SmsGateway:Url", "SMS_GATEWAY_URL", "https://www.smarterasp.net/sms/sms2.php").Trim();
                if (string.IsNullOrWhiteSpace(gatewayUrl))
                {
                    gatewayUrl = "https://www.smarterasp.net/sms/sms2.php";
                }

                using var httpClient = new HttpClient { Timeout = TimeSpan.FromSeconds(15) };
                using var content = new FormUrlEncodedContent(new Dictionary<string, string>
                {
                    ["to"] = mobileNumber,
                    ["pincode"] = pin,
                    ["branddomain"] = brandDomain
                });

                using var response = await httpClient.PostAsync(gatewayUrl, content);
                var body = (await response.Content.ReadAsStringAsync()).Trim();
                return string.IsNullOrWhiteSpace(body)
                    ? $"{(int)response.StatusCode} {response.ReasonPhrase}".Trim()
                    : response.IsSuccessStatusCode ? body : $"{(int)response.StatusCode} {response.ReasonPhrase}: {body}";
            }
            catch (Exception ex) when (ex is HttpRequestException or TaskCanceledException)
            {
                return ex.Message;
            }
        }

        private async Task HandleAccountPasswordChangeAsync(HttpContext context)
        {
            var sessionUser = GetSessionUser(context);
            if (sessionUser == null)
            {
                await Results.Json(
                    new AccountActionResponse(false, "Not signed in."),
                    statusCode: StatusCodes.Status401Unauthorized
                ).ExecuteAsync(context);
                return;
            }

            if (IsStaffAutoLogin(context))
            {
                await Results.Json(
                    new AccountActionResponse(false, "Staff auto-login cannot update customer passwords. Please ask the customer to make this change."),
                    statusCode: StatusCodes.Status403Forbidden
                ).ExecuteAsync(context);
                return;
            }

            var request = await context.Request.ReadFromJsonAsync<AccountPasswordChangeRequest>();
            var currentPassword = request?.CurrentPassword ?? "";
            var newPassword = request?.NewPassword ?? "";
            var confirmPassword = request?.ConfirmPassword ?? "";

            if (string.IsNullOrWhiteSpace(currentPassword) || string.IsNullOrWhiteSpace(newPassword))
            {
                await Results.BadRequest(new AccountActionResponse(false, "Enter current password and new password.")).ExecuteAsync(context);
                return;
            }

            if (newPassword != confirmPassword)
            {
                await Results.BadRequest(new AccountActionResponse(false, "New password and confirmation do not match.")).ExecuteAsync(context);
                return;
            }

            if (!IsPasswordComplexEnough(newPassword))
            {
                await Results.BadRequest(new AccountActionResponse(false, "Password must be at least 8 characters and include a letter and a number.")).ExecuteAsync(context);
                return;
            }

            var connectionString = GetEhbConfigConnectionString();
            if (string.IsNullOrWhiteSpace(connectionString))
            {
                await Results.Problem("Missing EhbConfig connection string.").ExecuteAsync(context);
                return;
            }

            await using var connection = new SqlConnection(connectionString);
            await connection.OpenAsync();

            var storedHash = await LoadCustomerPasswordHashAsync(connection, sessionUser.CustomerId);
            if (!PasswordMatches(currentPassword, storedHash))
            {
                await Results.Json(
                    new AccountActionResponse(false, "Current password is not correct."),
                    statusCode: StatusCodes.Status401Unauthorized
                ).ExecuteAsync(context);
                return;
            }

            if (PasswordMatches(newPassword, storedHash))
            {
                await Results.BadRequest(new AccountActionResponse(false, "New password cannot be the same as current password.")).ExecuteAsync(context);
                return;
            }

            const string sql = @"
UPDATE dbo.customer_profile
SET pp1 = @passwordHash,
    securityversion = 5,
    customerPassHash = '5',
    reVerify = 1
WHERE customerID = @customerId";

            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@passwordHash", HashHex(SHA256.HashData(Encoding.UTF8.GetBytes(newPassword))));
            command.Parameters.AddWithValue("@customerId", sessionUser.CustomerId);
            await command.ExecuteNonQueryAsync();

            var syncResult = await SyncAccountPasswordTargetsAsync(connection, sessionUser.CustomerId, newPassword, request?.SyncTargets);

            context.Session.SetString("customerID", sessionUser.CustomerId.ToString(CultureInfo.InvariantCulture));
            context.Session.SetString("customerLogin", sessionUser.Login);
            context.Session.SetString("customerType", sessionUser.CustomerType);

            await Results.Ok(new AccountActionResponse(true, FormatPasswordSyncMessage("Account password updated.", syncResult))).ExecuteAsync(context);
        }

        private async Task HandleAccountEmailChangeRequestAsync(HttpContext context)
        {
            var sessionUser = GetSessionUser(context);
            if (sessionUser == null)
            {
                await Results.Json(
                    new AccountActionResponse(false, "Not signed in."),
                    statusCode: StatusCodes.Status401Unauthorized
                ).ExecuteAsync(context);
                return;
            }

            if (IsStaffAutoLogin(context))
            {
                await Results.Json(
                    new AccountActionResponse(false, "Staff auto-login cannot change the customer contact email. Please ask the customer to make this change."),
                    statusCode: StatusCodes.Status403Forbidden
                ).ExecuteAsync(context);
                return;
            }

            var request = await context.Request.ReadFromJsonAsync<AccountEmailChangeRequest>();
            var email = NormalizeAccountText(request?.Email, 160).ToLowerInvariant();
            if (!IsValidEmail(email))
            {
                await Results.BadRequest(new AccountActionResponse(false, "Enter a valid email address.")).ExecuteAsync(context);
                return;
            }

            var connectionString = GetEhbConfigConnectionString();
            if (string.IsNullOrWhiteSpace(connectionString))
            {
                await Results.Problem("Missing EhbConfig connection string.").ExecuteAsync(context);
                return;
            }

            await using var connection = new SqlConnection(connectionString);
            await connection.OpenAsync();

            var emailVerifySalt = ConfigOrEnv("EmailVerify:Salt", "EMAIL_VERIFY_SALT", "SmarterASP.NET").ToLowerInvariant();
            var verifyHash = HashHex(MD5.HashData(Encoding.UTF8.GetBytes($"{sessionUser.Login.ToLowerInvariant()}{email}{emailVerifySalt}")));
            await using (var deleteCommand = new SqlCommand("DELETE FROM dbo.reset_verify WHERE customerID = @customerId", connection))
            {
                deleteCommand.Parameters.AddWithValue("@customerId", sessionUser.CustomerId);
                await deleteCommand.ExecuteNonQueryAsync();
            }

            await using (var insertCommand = new SqlCommand(@"
INSERT INTO dbo.reset_verify (reset_str, customerID, new_email, create_date)
VALUES (@resetStr, @customerId, @email, GETDATE())", connection))
            {
                insertCommand.Parameters.AddWithValue("@resetStr", verifyHash);
                insertCommand.Parameters.AddWithValue("@customerId", sessionUser.CustomerId);
                insertCommand.Parameters.AddWithValue("@email", email);
                await insertCommand.ExecuteNonQueryAsync();
            }

            var verifyUrl = $"/account/emailchangeverify?ac={Uri.EscapeDataString(verifyHash)}&customerlogin={Uri.EscapeDataString(sessionUser.Login)}";
            var absoluteVerifyUrl = BuildAbsoluteUrl(context, verifyUrl);
            var mailResult = await SendAccountEmailAsync(
                email,
                "Verify your SmarterASP.NET account email",
                $@"
<p>Hello {WebUtility.HtmlEncode(sessionUser.Login)},</p>
<p>Use the link below to verify this email address for your SmarterASP.NET account.</p>
<p><a href=""{WebUtility.HtmlEncode(absoluteVerifyUrl)}"">Verify email address</a></p>
<p>If you did not request this change, you can ignore this email.</p>",
                $@"Hello {sessionUser.Login},

Use this link to verify this email address for your SmarterASP.NET account.

{absoluteVerifyUrl}

If you did not request this change, you can ignore this email."
            );
            if (!mailResult.Success)
            {
                await Results.Json(
                    new AccountActionResponse(false, $"Email change verification request was created, but SMTP delivery failed: {mailResult.Message}"),
                    statusCode: StatusCodes.Status502BadGateway
                ).ExecuteAsync(context);
                return;
            }

            await Results.Ok(new AccountActionResponse(true, $"Email change verification email sent to {email}.")).ExecuteAsync(context);
        }

        private async Task HandleAccountEmailChangeVerifyAsync(HttpContext context)
        {
            var resetHash = NormalizeAccountText(context.Request.Query["ac"].ToString(), 256);
            var login = NormalizeAccountText(context.Request.Query["customerlogin"].ToString(), 120);
            if (string.IsNullOrWhiteSpace(resetHash) || string.IsNullOrWhiteSpace(login))
            {
                await Results.BadRequest(new EmailChangeVerifyResponse(false, "Missing email verification link information.", false, "", null)).ExecuteAsync(context);
                return;
            }

            var connectionString = GetEhbConfigConnectionString();
            if (string.IsNullOrWhiteSpace(connectionString))
            {
                await Results.Problem("Missing EhbConfig connection string.").ExecuteAsync(context);
                return;
            }

            await using var connection = new SqlConnection(connectionString);
            await connection.OpenAsync();

            const string sql = @"
SELECT TOP 1 rv.customerID, CAST(rv.new_email AS nvarchar(max)) AS new_email, rv.create_date, cp.customerLogin
FROM dbo.reset_verify rv
INNER JOIN dbo.customer_profile cp ON cp.customerID = rv.customerID
WHERE rv.reset_str = @resetHash
  AND LOWER(cp.customerLogin) = LOWER(@login)
  AND rv.new_email IS NOT NULL
ORDER BY rv.create_date DESC";

            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@resetHash", resetHash);
            command.Parameters.AddWithValue("@login", login);

            await using var reader = await command.ExecuteReaderAsync();
            if (!await reader.ReadAsync())
            {
                await Results.Json(
                    new EmailChangeVerifyResponse(false, "This email verification link is invalid or has already been used.", false, "", null),
                    statusCode: StatusCodes.Status404NotFound
                ).ExecuteAsync(context);
                return;
            }

            var customerId = Convert.ToInt64(reader.GetValue(0), CultureInfo.InvariantCulture);
            var newEmail = reader.IsDBNull(1) ? "" : reader.GetString(1).Trim();
            var createdAt = reader.IsDBNull(2) ? (DateTime?)null : reader.GetDateTime(2);
            var customerLogin = reader.GetString(3).Trim();

            var emailVerifySalt = ConfigOrEnv("EmailVerify:Salt", "EMAIL_VERIFY_SALT", "SmarterASP.NET").ToLowerInvariant();
            var expectedHash = HashHex(MD5.HashData(Encoding.UTF8.GetBytes($"{customerLogin.ToLowerInvariant()}{newEmail.ToLowerInvariant()}{emailVerifySalt}")));
            if (!FixedTimeEquals(resetHash, expectedHash))
            {
                await Results.Json(
                    new EmailChangeVerifyResponse(false, "This email verification link does not match the pending email address.", false, newEmail, createdAt),
                    statusCode: StatusCodes.Status400BadRequest
                ).ExecuteAsync(context);
                return;
            }

            var encryptedEmail = await TryLegacyEncryptPwdAsync(newEmail);
            if (string.IsNullOrWhiteSpace(encryptedEmail))
            {
                await Results.Json(
                    new EmailChangeVerifyResponse(false, "Email verified, but the account email was not changed because the encryption service did not return a value.", false, newEmail, createdAt),
                    statusCode: StatusCodes.Status409Conflict
                ).ExecuteAsync(context);
                return;
            }

            await using (var updateCommand = new SqlCommand(@"
UPDATE dbo.customer_profile
SET email = @email
WHERE customerID = @customerId
  AND LOWER(customerLogin) = LOWER(@login)", connection))
            {
                updateCommand.Parameters.AddWithValue("@email", encryptedEmail);
                updateCommand.Parameters.AddWithValue("@customerId", customerId);
                updateCommand.Parameters.AddWithValue("@login", customerLogin);
                await updateCommand.ExecuteNonQueryAsync();
            }

            await using (var deleteCommand = new SqlCommand("DELETE FROM dbo.reset_verify WHERE customerID = @customerId", connection))
            {
                deleteCommand.Parameters.AddWithValue("@customerId", customerId);
                await deleteCommand.ExecuteNonQueryAsync();
            }

            var helpdeskResult = await UpdateHelpdeskLoginEmailAsync(customerLogin, newEmail);
            var message = helpdeskResult.Success
                ? "Email Updated"
                : $"Email Updated. Helpdesk login email sync needs attention: {helpdeskResult.Message}";
            await Results.Ok(new EmailChangeVerifyResponse(true, message, true, newEmail, createdAt)).ExecuteAsync(context);
        }

