        private async Task HandlePasswordResetRequestAsync(HttpContext context)
        {
            var request = await context.Request.ReadFromJsonAsync<PasswordResetRequest>();
            var login = NormalizeAccountText(request?.Login, 120);
            if (string.IsNullOrWhiteSpace(login))
            {
                await Results.BadRequest(new PasswordResetResponse(false, "Enter your account username.", null)).ExecuteAsync(context);
                return;
            }

            var connectionString = GetEhbConfigConnectionString();
            if (string.IsNullOrWhiteSpace(connectionString))
            {
                await Results.Problem("Missing EhbConfig connection string.").ExecuteAsync(context);
                return;
            }

            await using var connection = new SqlConnection(connectionString);
            await connection.OpenAsync();

            const string customerSql = @"
SELECT TOP 1 customerID, status, CAST(email AS nvarchar(max)) AS email
FROM dbo.customer_profile
WHERE LOWER(customerLogin) = LOWER(@login)";

            long customerId;
            int status;
            string accountEmail;
            await using (var customerCommand = new SqlCommand(customerSql, connection))
            {
                customerCommand.Parameters.AddWithValue("@login", login);
                await using var reader = await customerCommand.ExecuteReaderAsync();
                if (!await reader.ReadAsync())
                {
                    await Results.Json(
                        new PasswordResetResponse(false, "Account was not found. Enter the account username, not the email address.", null),
                        statusCode: StatusCodes.Status404NotFound
                    ).ExecuteAsync(context);
                    return;
                }

                customerId = Convert.ToInt64(reader.GetValue(0), CultureInfo.InvariantCulture);
                status = reader.IsDBNull(1) ? -1 : reader.GetInt32(1);
                accountEmail = reader.IsDBNull(2) ? "" : reader.GetString(2).Trim();
            }

            if (status == 3)
            {
                await Results.Json(
                    new PasswordResetResponse(false, "This account is canceled and cannot reset password from the account panel.", null),
                    statusCode: StatusCodes.Status403Forbidden
                ).ExecuteAsync(context);
                return;
            }

            await using (var cleanupCommand = new SqlCommand(@"
DELETE FROM dbo.reset_verify
WHERE customerID = @customerId
   OR DATEDIFF(hour, create_date, SYSDATETIME()) > 2", connection))
            {
                cleanupCommand.Parameters.AddWithValue("@customerId", customerId);
                await cleanupCommand.ExecuteNonQueryAsync();
            }

            var token = GenerateResetToken();
            await using (var insertCommand = new SqlCommand(@"
INSERT INTO dbo.reset_verify (reset_str, customerID, create_date)
VALUES (@resetStr, @customerId, GETDATE())", connection))
            {
                insertCommand.Parameters.AddWithValue("@resetStr", token);
                insertCommand.Parameters.AddWithValue("@customerId", customerId);
                await insertCommand.ExecuteNonQueryAsync();
            }

            var resetUrl = $"/account/retrieve_password_reset?guid={Uri.EscapeDataString(token)}";
            var absoluteResetUrl = BuildAbsoluteUrl(context, resetUrl);
            if (!IsValidEmail(accountEmail))
            {
                await Results.Json(
                    new PasswordResetResponse(false, "Password reset link was created, but this account email is not readable yet. The stored email may require the decrypt service.", resetUrl),
                    statusCode: StatusCodes.Status500InternalServerError
                ).ExecuteAsync(context);
                return;
            }

            var mailResult = await SendAccountEmailAsync(
                accountEmail,
                "SmarterASP.NET password reset",
                $@"
<p>Hello {WebUtility.HtmlEncode(login)},</p>
<p>Use the link below to reset your SmarterASP.NET account password. This link expires in 2 hours.</p>
<p><a href=""{WebUtility.HtmlEncode(absoluteResetUrl)}"">Reset your password</a></p>
<p>If you did not request this, you can ignore this email.</p>",
                $@"Hello {login},

Use this link to reset your SmarterASP.NET account password. This link expires in 2 hours.

{absoluteResetUrl}

If you did not request this, you can ignore this email."
            );
            if (!mailResult.Success)
            {
                await Results.Json(
                    new PasswordResetResponse(false, $"Password reset link was created, but SMTP delivery failed: {mailResult.Message}", resetUrl),
                    statusCode: StatusCodes.Status502BadGateway
                ).ExecuteAsync(context);
                return;
            }

            await Results.Ok(new PasswordResetResponse(true, $"Password reset email sent to {MaskStoredSecret(accountEmail)}.", resetUrl)).ExecuteAsync(context);
        }

        private async Task HandlePasswordResetConfirmAsync(HttpContext context)
        {
            var request = await context.Request.ReadFromJsonAsync<PasswordResetConfirmRequest>();
            var token = NormalizeAccountText(request?.Token, 256);
            var newPassword = request?.NewPassword ?? "";
            var confirmPassword = request?.ConfirmPassword ?? "";

            if (string.IsNullOrWhiteSpace(token))
            {
                await Results.BadRequest(new AccountActionResponse(false, "Missing password reset token.")).ExecuteAsync(context);
                return;
            }

            if (newPassword != confirmPassword)
            {
                await Results.BadRequest(new AccountActionResponse(false, "New password and confirmation do not match.")).ExecuteAsync(context);
                return;
            }

            if (!IsPasswordComplexEnough(newPassword))
            {
                await Results.BadRequest(new AccountActionResponse(false, "Password must be at least 8 characters and include a letter and a number.")).ExecuteAsync(context);
                return;
            }

            var connectionString = GetEhbConfigConnectionString();
            if (string.IsNullOrWhiteSpace(connectionString))
            {
                await Results.Problem("Missing EhbConfig connection string.").ExecuteAsync(context);
                return;
            }

            await using var connection = new SqlConnection(connectionString);
            await connection.OpenAsync();

            long customerId;
            int tokenAgeMinutes;
            await using (var lookupCommand = new SqlCommand(@"
SELECT TOP 1 customerID, DATEDIFF(minute, create_date, SYSDATETIME()) AS token_age_minutes
FROM dbo.reset_verify
WHERE reset_str = @resetStr
  AND new_email IS NULL
ORDER BY create_date DESC", connection))
            {
                lookupCommand.Parameters.AddWithValue("@resetStr", token);
                await using var reader = await lookupCommand.ExecuteReaderAsync();
                if (!await reader.ReadAsync())
                {
                    await Results.Json(
                        new AccountActionResponse(false, "This password reset link is invalid or has already been used."),
                        statusCode: StatusCodes.Status404NotFound
                    ).ExecuteAsync(context);
                    return;
                }

                customerId = Convert.ToInt64(reader.GetValue(0), CultureInfo.InvariantCulture);
                tokenAgeMinutes = ReadInt32(reader, 1, 9999);
            }

            if (tokenAgeMinutes > 120)
            {
                await using var expiredDeleteCommand = new SqlCommand("DELETE FROM dbo.reset_verify WHERE reset_str = @resetStr", connection);
                expiredDeleteCommand.Parameters.AddWithValue("@resetStr", token);
                await expiredDeleteCommand.ExecuteNonQueryAsync();

                await Results.BadRequest(new AccountActionResponse(false, "This password reset link has expired. Create a new reset link.")).ExecuteAsync(context);
                return;
            }

            await using (var updateCommand = new SqlCommand(@"
UPDATE dbo.customer_profile
SET pp1 = @passwordHash,
    securityversion = 5,
    customerPassHash = '5',
    reVerify = 1
WHERE customerID = @customerId", connection))
            {
                updateCommand.Parameters.AddWithValue("@passwordHash", HashHex(SHA256.HashData(Encoding.UTF8.GetBytes(newPassword))));
                updateCommand.Parameters.AddWithValue("@customerId", customerId);
                await updateCommand.ExecuteNonQueryAsync();
            }

            await using (var deleteCommand = new SqlCommand("DELETE FROM dbo.reset_verify WHERE customerID = @customerId", connection))
            {
                deleteCommand.Parameters.AddWithValue("@customerId", customerId);
                await deleteCommand.ExecuteNonQueryAsync();
            }

            var syncResult = await SyncAccountPasswordTargetsAsync(connection, customerId, newPassword, null);

            await Results.Ok(new AccountActionResponse(true, FormatPasswordSyncMessage("Password reset completed.", syncResult))).ExecuteAsync(context);
        }

        private async Task<PasswordSyncResult> SyncAccountPasswordTargetsAsync(SqlConnection connection, long customerId, string newPassword, IReadOnlyCollection<string>? requestedTargets)
        {
            var synced = new List<string>();
            var blocked = new List<string>();
            var targetSet = requestedTargets == null
                ? null
                : new HashSet<string>(requestedTargets.Where(target => !string.IsNullOrWhiteSpace(target)), StringComparer.OrdinalIgnoreCase);
            var accounts = await LoadHostingAccountsAsync(connection, customerId);
            var activeAccounts = accounts
                .Where(account => account.Status.Equals("Active", StringComparison.OrdinalIgnoreCase))
                .ToList();

            if (activeAccounts.Count == 0)
            {
                return new PasswordSyncResult(synced, blocked);
            }

            var passwordHash = HashHex(SHA256.HashData(Encoding.UTF8.GetBytes(newPassword)));
            var agent = GetLegacyAgentSettings();

            foreach (var account in activeAccounts)
            {
                var label = string.IsNullOrWhiteSpace(account.CpLogin) ? $"CP #{account.CpId}" : account.CpLogin;
                var syncCp = targetSet == null || targetSet.Contains($"cp_{account.CpId}");
                var syncFtp = targetSet == null || targetSet.Contains($"ftp_{account.CpId}");
                var syncIis = targetSet == null || targetSet.Contains($"iis_{account.CpId}");

                if (syncCp)
                {
                    var encryptedCpPassword = await TryLegacyEncryptPwdAsync(newPassword);
                    var cpUpdated = await ExecuteNonQueryAsync(connection, @"
UPDATE dbo.cp_config
SET pp1 = @passwordHash,
    cpPasswordHash = CASE WHEN @encryptedPassword <> '' THEN @encryptedPassword ELSE cpPasswordHash END
WHERE cpID = @cpId
  AND customerID = @customerId", command =>
                {
                    command.Parameters.AddWithValue("@passwordHash", passwordHash);
                    command.Parameters.AddWithValue("@encryptedPassword", encryptedCpPassword);
                    command.Parameters.AddWithValue("@cpId", account.CpId);
                    command.Parameters.AddWithValue("@customerId", customerId);
                    });

                    if (cpUpdated > 0)
                    {
                        synced.Add($"{label}: CP login hash updated.");
                        if (string.IsNullOrWhiteSpace(encryptedCpPassword))
                        {
                            blocked.Add($"{label}: cpPasswordHash was not rewritten because password encryption compatibility is not configured.");
                        }
                        else
                        {
                            synced.Add($"{label}: cpPasswordHash updated with encrypted password output.");
                        }
                    }
                    else
                    {
                        blocked.Add($"{label}: CP login hash was not updated because the account row was not found.");
                    }
                }

                if (IsLinuxHosting(account.WebHostType))
                {
                    if (syncCp)
                    {
                        var linuxResult = await SyncLinuxHostingPasswordAsync(connection, account, newPassword);
                        AddPasswordSyncCallResult(label, "Linux cPanel password", linuxResult, synced, blocked);
                    }
                    continue;
                }

                if (syncFtp)
                {
                    var ftpSync = await SyncWindowsFtpPasswordAsync(connection, account, newPassword);
                    if (ftpSync.Success)
                    {
                        synced.Add($"{label}: {ftpSync.Message}");
                    }
                    else
                    {
                        blocked.Add($"{label}: {ftpSync.Message}");
                    }
                }

                if (syncIis && string.IsNullOrWhiteSpace(account.ServerId))
                {
                    blocked.Add($"{label}: IIS Manager/Web Deploy sync skipped because ServerID is missing.");
                }
                else if (syncIis)
                {
                    var iisPasswordHash = passwordHash;
                    var iisAdd = await PostLegacyAgentAsync(agent, account.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                    {
                        ["action"] = "SetIISManagerUser",
                        ["SetAction"] = "AddUser",
                        ["user"] = account.CpLogin,
                        ["pwd"] = iisPasswordHash
                    });
                    AddPasswordSyncCallResult(label, "IIS Manager AddUser", iisAdd, synced, blocked);

                    var iisReset = await PostLegacyAgentAsync(agent, account.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                    {
                        ["action"] = "SetIISManagerUser",
                        ["SetAction"] = "ResetUser",
                        ["user"] = account.CpLogin,
                        ["pwd"] = iisPasswordHash
                    });
                    AddPasswordSyncCallResult(label, "IIS Manager ResetUser", iisReset, synced, blocked);
                }

                if (syncIis)
                {
                    var ssrsServerId = await LoadSsrsServerIdAsync(connection, account.CpId);
                    if (!string.IsNullOrWhiteSpace(ssrsServerId))
                    {
                        var ssrsAdd = await PostLegacyAgentAsync(agent, ssrsServerId, "/aspuser.asp", new Dictionary<string, string>
                        {
                            ["action"] = "LocalUserAdd",
                            ["UserID"] = account.CpLogin,
                            ["Password"] = newPassword,
                            ["cpID"] = account.CpId.ToString(CultureInfo.InvariantCulture)
                        });
                        AddPasswordSyncCallResult(label, "SSRS local user add", ssrsAdd, synced, blocked);

                        var ssrsReset = await PostLegacyAgentAsync(agent, ssrsServerId, "/aspuser.asp", new Dictionary<string, string>
                        {
                            ["action"] = "LocalUserPasswordReset",
                            ["UserID"] = account.CpLogin,
                            ["Password"] = newPassword,
                            ["cpID"] = account.CpId.ToString(CultureInfo.InvariantCulture)
                        });
                        AddPasswordSyncCallResult(label, "SSRS local user reset", ssrsReset, synced, blocked);
                    }
                }
            }

            return new PasswordSyncResult(synced, blocked);
        }

        private async Task<LegacyAgentCallResult> SyncWindowsFtpPasswordAsync(SqlConnection connection, HostingAccountSummary account, string newPassword)
        {
            var encryptedPassword = await TryLegacyEncryptPwdAsync(newPassword);
            var encryptedFtpPassword = await TryLegacyEncryptFtpPwdAsync(newPassword);
            if (string.IsNullOrWhiteSpace(encryptedPassword) || string.IsNullOrWhiteSpace(encryptedFtpPassword))
            {
                return new LegacyAgentCallResult(false, "FTP password DB sync blocked because password encryption compatibility is not configured.", "", "", null);
            }

            var existingRootFtp = await ExecuteScalarAsync<int>(connection, @"
SELECT COUNT(*)
FROM dbo.cp_config_FTP
WHERE cpID = @cpId
  AND LOWER(ftp_login) = LOWER(@cpLogin)", command =>
            {
                command.Parameters.AddWithValue("@cpId", account.CpId);
                command.Parameters.AddWithValue("@cpLogin", account.CpLogin);
            });

            if (existingRootFtp <= 0)
            {
                var ftpPath = await LoadFtpRootPathAsync(connection, account.CpId, account.CpLogin);
                var diskQuota = await LoadDiskQuotaMbAsync(connection, account.CpId, account.WebHostType);
                await ExecuteNonQueryAsync(connection, @"
INSERT INTO dbo.cp_config_FTP (pp1, cpid, ftp_login, ftp_password, ftp_path, ftp_quota, ftp_permission, cpurl)
VALUES (@pp1, @cpId, @ftpLogin, @ftpPassword, @ftpPath, @ftpQuota, 'write', @cpUrl)", command =>
                {
                    command.Parameters.AddWithValue("@pp1", encryptedFtpPassword);
                    command.Parameters.AddWithValue("@cpId", account.CpId);
                    command.Parameters.AddWithValue("@ftpLogin", account.CpLogin);
                    command.Parameters.AddWithValue("@ftpPassword", encryptedPassword);
                    command.Parameters.AddWithValue("@ftpPath", ftpPath);
                    command.Parameters.AddWithValue("@ftpQuota", diskQuota);
                    command.Parameters.AddWithValue("@cpUrl", BuildLegacyPublicHost(account.ServerId));
                });
                return new LegacyAgentCallResult(true, $"root FTP user was missing and was recreated in cp_config_FTP with path {ftpPath}.", "", "", null);
            }

            var updated = await ExecuteNonQueryAsync(connection, @"
UPDATE dbo.cp_config_FTP
SET ftp_password = @ftpPassword,
    pp1 = @pp1
WHERE cpID = @cpId
  AND LOWER(ftp_login) = LOWER(@cpLogin)", command =>
            {
                command.Parameters.AddWithValue("@ftpPassword", encryptedPassword);
                command.Parameters.AddWithValue("@pp1", encryptedFtpPassword);
                command.Parameters.AddWithValue("@cpId", account.CpId);
                command.Parameters.AddWithValue("@cpLogin", account.CpLogin);
            });

            return updated > 0
                ? new LegacyAgentCallResult(true, "root FTP encrypted password fields updated in cp_config_FTP.", "", "", null)
                : new LegacyAgentCallResult(false, "root FTP row was not updated.", "", "", null);
        }

        private static async Task<string> LoadFtpRootPathAsync(SqlConnection connection, long cpId, string cpLogin)
        {
            var existingPath = await ExecuteScalarAsync<string>(connection, @"
SELECT TOP 1 ftp_path
FROM dbo.cp_config_FTP
WHERE cpID = @cpId
ORDER BY CASE WHEN LOWER(ftp_login) = LOWER(@cpLogin) THEN 0 ELSE 1 END, ftp_uid", command =>
            {
                command.Parameters.AddWithValue("@cpId", cpId);
                command.Parameters.AddWithValue("@cpLogin", cpLogin);
            }) ?? "";

            if (!string.IsNullOrWhiteSpace(existingPath))
            {
                var normalized = existingPath.Trim().TrimEnd('\\', '/');
                var marker = $"\\{cpLogin}\\";
                var markerIndex = normalized.IndexOf(marker, StringComparison.OrdinalIgnoreCase);
                if (markerIndex >= 0)
                {
                    return normalized[..(markerIndex + marker.Length - 1)];
                }

                return normalized;
            }

            return $@"h:\root\home\{cpLogin}";
        }

        private static async Task<int> LoadDiskQuotaMbAsync(SqlConnection connection, long cpId, string webHostType)
        {
            var quota = await ExecuteScalarAsync<int>(connection, @"
SELECT ISNULL(c.additionalDiskQuota, 0) + ISNULL(pc.webspace, 0)
FROM dbo.cp_config c
LEFT JOIN dbo.product_config pc ON pc.product_name = c.WebHostType
WHERE c.cpID = @cpId", command =>
            {
                command.Parameters.AddWithValue("@cpId", cpId);
            });

            return quota > 0 ? quota : 100;
        }

        private async Task<LegacyAgentCallResult> SyncLinuxHostingPasswordAsync(SqlConnection connection, HostingAccountSummary account, string newPassword)
        {
            var whmAuth = ConfigOrEnv("LinuxCpanel:WhmAuthorization", "LCP_WHM_AUTHORIZATION").Trim();
            if (string.IsNullOrWhiteSpace(whmAuth))
            {
                return new LegacyAgentCallResult(false, "Linux WHM Authorization header is not configured.", "", "", null);
            }

            var cpanelLogin = await LoadCpanelLoginByCpLoginAsync(connection, account.CpLogin);
            if (string.IsNullOrWhiteSpace(cpanelLogin))
            {
                return new LegacyAgentCallResult(false, "Linux cPanel alias login was not found.", "", "", null);
            }

            var whmHost = await LoadServerTempUrlIpAsync(connection, account.ServerId);
            if (string.IsNullOrWhiteSpace(whmHost))
            {
                whmHost = BuildLegacyPublicHost(account.ServerId);
            }

            if (string.IsNullOrWhiteSpace(whmHost))
            {
                return new LegacyAgentCallResult(false, "Linux WHM host could not be resolved.", "", "", null);
            }

            var scheme = ConfigOrEnv("LinuxCpanel:WhmScheme", "LCP_WHM_SCHEME", "https").Trim();
            var portText = ConfigOrEnv("LinuxCpanel:WhmPort", "LCP_WHM_PORT", "2087").Trim();
            var port = int.TryParse(portText, NumberStyles.Integer, CultureInfo.InvariantCulture, out var configuredPort)
                ? configuredPort
                : 2087;
            var url = $"{(string.IsNullOrWhiteSpace(scheme) ? "https" : scheme)}://{whmHost}:{port}/json-api/passwd";

            try
            {
                using var httpClient = new HttpClient { Timeout = TimeSpan.FromSeconds(60) };
                using var request = new HttpRequestMessage(HttpMethod.Post, url);
                request.Headers.TryAddWithoutValidation("Authorization", whmAuth);
                request.Content = new FormUrlEncodedContent(new Dictionary<string, string>
                {
                    ["user"] = cpanelLogin,
                    ["pass"] = newPassword
                });

                var response = await httpClient.SendAsync(request);
                var body = await response.Content.ReadAsStringAsync();
                var accepted = response.IsSuccessStatusCode && body.Contains("\"status\":1", StringComparison.OrdinalIgnoreCase);
                return accepted
                    ? new LegacyAgentCallResult(true, "WHM accepted the password change.", url, Preview(body), new { status = (int)response.StatusCode })
                    : new LegacyAgentCallResult(false, $"WHM rejected the password change: {Preview(body)}", url, Preview(body), new { status = (int)response.StatusCode });
            }
            catch (Exception ex) when (ex is HttpRequestException or TaskCanceledException)
            {
                return new LegacyAgentCallResult(false, $"WHM password call failed: {ex.Message}", url, "", null);
            }
        }

