        private static async Task<ProductRenewalCatalog?> LoadProductRenewalCatalogAsync(SqlConnection connection, long customerId, int clientProductId)
        {
            const string productSql = @"
SELECT TOP 1 cp.client_product_id, cp.product_id, p.name, p.description, p.product_type,
       cp.next_due_date, cp.status, cp.create_date, cp.last_update,
       latestOrder.payment_term, latestOrder.amount,
       ISNULL(hostcp.cpID, 0) AS cpID,
       ISNULL(hostcp.cpLogin, '') AS cpLogin
FROM oms.dbo.client_product cp
INNER JOIN oms.dbo.product p ON p.product_id = cp.product_id
LEFT JOIN dbo.cp_config hostcp ON hostcp.client_product_id = cp.client_product_id
OUTER APPLY (
    SELECT TOP 1 o.payment_term, o.amount
    FROM oms.dbo.[order] o
    WHERE o.client_product_id = cp.client_product_id
      AND o.order_status = 'completed'
    ORDER BY o.create_date DESC, o.order_id DESC
) latestOrder
WHERE cp.client_id = @customerId
  AND cp.client_product_id = @clientProductId";

            AccountProductSummary? product;
            long cpId;
            string cpLogin;
            await using (var command = new SqlCommand(productSql, connection))
            {
                command.Parameters.AddWithValue("@customerId", customerId);
                command.Parameters.AddWithValue("@clientProductId", clientProductId);

                await using var reader = await command.ExecuteReaderAsync();
                if (!await reader.ReadAsync())
                {
                    return null;
                }

                product = ReadAccountProduct(reader);
                cpId = reader.IsDBNull(11) ? 0 : Convert.ToInt64(reader.GetValue(11), CultureInfo.InvariantCulture);
                cpLogin = reader.IsDBNull(12) ? "" : reader.GetString(12).Trim();
            }

            var options = new List<ProductRenewalOption>();
            const string optionsSql = @"
SELECT pr.price_id, ISNULL(pr.currency, 'USD') AS currency, ISNULL(pr.payment_term, '') AS payment_term,
       ISNULL(pr.price_amount, 0) AS price_amount, ISNULL(pr.original_price_amount, pr.price_amount) AS original_price_amount
FROM oms.dbo.price pr
WHERE pr.product_id = @productId
  AND ISNULL(pr.price_amount, 0) >= 0
  AND NOT EXISTS (
      SELECT 1
      FROM oms.dbo.price_ext pe
      WHERE pe.price_id = pr.price_id
        AND ISNULL(pe.isTrial, 0) = 1
  )
ORDER BY pr.price_amount, pr.price_id";

            await using (var command = new SqlCommand(optionsSql, connection))
            {
                command.Parameters.AddWithValue("@productId", product.ProductId);

                await using var reader = await command.ExecuteReaderAsync();
                while (await reader.ReadAsync())
                {
                    var priceId = reader.GetInt32(0);
                    var currency = reader.GetString(1).Trim().ToUpperInvariant();
                    var term = reader.GetString(2).Trim();
                    var amount = reader.GetDecimal(3);
                    var originalAmount = reader.GetDecimal(4);
                    if (string.IsNullOrWhiteSpace(term))
                    {
                        continue;
                    }

                    options.Add(new ProductRenewalOption(
                        priceId,
                        term,
                        currency,
                        amount,
                        originalAmount,
                        MonthlyAmount(amount, term)
                    ));
                }
            }

            var isHostingRenewal = cpId > 0;
            var isOptionRenewal = IsOptionAddonRenewal(product);
            var pageType = isHostingRenewal
                ? ConstPageTypeCpRenew
                : isOptionRenewal
                    ? ConstPageTypeOptionAddonRenew
                    : ConstPageTypeAddonRenew;
            var renewalProductName = isHostingRenewal && !string.IsNullOrWhiteSpace(cpLogin)
                ? $"Renew {cpLogin}"
                : $"Renew {product.Name}";
            var legacyTrace = isHostingRenewal
                ? "Hosting renewal checkout is ready."
                : isOptionRenewal
                    ? "Selected term creates an option add-on renewal order."
                    : "Selected term creates an add-on renewal order.";

            return new ProductRenewalCatalog(product, options, cpId, cpLogin, pageType, renewalProductName, legacyTrace);
        }

        private static bool IsOptionAddonRenewal(AccountProductSummary product)
        {
            var text = $"{product.Name} {product.Description} {product.ProductType}".ToLowerInvariant();
            return text.Contains("domain", StringComparison.Ordinal)
                || text.Contains("whois", StringComparison.Ordinal)
                || text.Contains("privacy", StringComparison.Ordinal)
                || text.Contains("ssl", StringComparison.Ordinal)
                || text.Contains("rapid", StringComparison.Ordinal)
                || text.Contains("option", StringComparison.Ordinal);
        }

        private static decimal MonthlyAmount(decimal amount, string paymentTerm)
        {
            var months = paymentTerm.Trim().ToLowerInvariant() switch
            {
                "monthly" => 1,
                "quarterly" => 3,
                "semi-annually" => 6,
                "annually" => 12,
                "biennially" => 24,
                "3y" => 36,
                _ => 0
            };

            return months <= 1 ? amount : Math.Round(amount / months, 2);
        }

        private static async Task<DomainRenewalOption?> LoadDomainRenewalOptionAsync(SqlConnection connection, long customerId, AccountDomainSummary domain)
        {
            const string sql = @"
SELECT TOP 1 cp.client_product_id, cp.product_id, p.name, pr.currency, pr.payment_term, pr.price_amount
FROM oms.dbo.client_product cp
INNER JOIN oms.dbo.product p ON p.product_id = cp.product_id
INNER JOIN oms.dbo.price pr ON pr.product_id = p.product_id
WHERE cp.client_id = @customerId
  AND cp.client_product_id = @clientProductId
  AND pr.price_amount > 0
ORDER BY pr.price_amount";

            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@customerId", customerId);
            command.Parameters.AddWithValue("@clientProductId", domain.ClientProductId);

            await using var reader = await command.ExecuteReaderAsync();
            if (!await reader.ReadAsync())
            {
                return null;
            }

            var clientProductId = ReadInt32(reader, 0);
            var productId = ReadInt32(reader, 1);
            var productName = reader.IsDBNull(2) ? "Domain Renewal" : reader.GetString(2).Trim();
            var currency = reader.IsDBNull(3) ? "usd" : reader.GetString(3).Trim().ToLowerInvariant();
            var paymentTerm = reader.IsDBNull(4) ? "annually" : reader.GetString(4).Trim().ToLowerInvariant();
            var priceAmount = reader.IsDBNull(5) ? 0m : reader.GetDecimal(5);
            await reader.CloseAsync();

            if (priceAmount <= 0m)
            {
                return null;
            }

            var termYears = RenewalTermYears(paymentTerm);
            var maxRenewPeriod = termYears > 1 ? termYears : 10;
            var tld = DomainTld(domain.DomainName);
            if (tld is "be" or "it" or "nl")
            {
                maxRenewPeriod = 1;
            }
            else if (tld == "au")
            {
                maxRenewPeriod = 4;
            }
            else if (tld is "hu" or "ai")
            {
                termYears = 2;
                maxRenewPeriod = 2;
            }

            var years = Math.Min(termYears, maxRenewPeriod);
            var quantity = Math.Max(1, years / Math.Max(1, termYears));
            var privacyClientProductId = domain.WhoisPrivacyPurchased
                ? await LoadDomainPrivacyClientProductIdAsync(connection, domain.DomainName)
                : 0;
            var includePrivacy = privacyClientProductId > 0;
            const decimal whoisPrivacyYearlyPrice = 8m;
            var total = priceAmount * quantity + (includePrivacy ? whoisPrivacyYearlyPrice * years : 0m);
            var purchaseParameter = string.Join("|", new[]
            {
                clientProductId.ToString(CultureInfo.InvariantCulture),
                paymentTerm,
                string.IsNullOrWhiteSpace(currency) ? "usd" : currency,
                quantity.ToString(CultureInfo.InvariantCulture),
                years.ToString(CultureInfo.InvariantCulture),
                includePrivacy ? "pri" : "",
                includePrivacy ? privacyClientProductId.ToString(CultureInfo.InvariantCulture) : ""
            });
            var title = includePrivacy
                ? $"Renew Domain Name - {domain.DomainName} + Whois Privacy ({years} Years)"
                : $"Renew Domain Name - {domain.DomainName} ({years} Years)";
            var note = includePrivacy
                ? "Created like option_addon_renew.asp with active Whois Privacy included in the renewal amount."
                : "Created like option_addon_renew.asp using the first valid domain renewal option.";

            return new DomainRenewalOption(clientProductId, productId, title, productName, paymentTerm, currency, quantity, years, priceAmount, total, includePrivacy, privacyClientProductId, purchaseParameter, note);
        }

        private static async Task<int> LoadDomainPrivacyClientProductIdAsync(SqlConnection connection, string domainName)
        {
            const string sql = @"
SELECT TOP 1 p.client_product_id
FROM domaincontroller.dbo.domain_privacy p
INNER JOIN oms.dbo.client_product cp ON cp.client_product_id = p.client_product_id
WHERE LOWER(p.domain) = LOWER(@domainName)
  AND cp.status = 1";

            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@domainName", domainName);
            var value = await command.ExecuteScalarAsync();
            return value == null || value == DBNull.Value ? 0 : Convert.ToInt32(value, CultureInfo.InvariantCulture);
        }

        private static int RenewalTermYears(string paymentTerm)
        {
            var normalized = (paymentTerm ?? "").Trim().ToLowerInvariant();
            if (normalized.StartsWith("bienn", StringComparison.Ordinal)) return 2;
            if (normalized.StartsWith("trienn", StringComparison.Ordinal)) return 3;
            if (normalized.StartsWith("quad", StringComparison.Ordinal)) return 4;
            return 1;
        }

        private static AccountProductSummary ReadAccountProduct(SqlDataReader reader)
        {
            var clientProductId = reader.GetInt32(0);
            var dueDate = reader.IsDBNull(5) ? (DateOnly?)null : DateOnly.FromDateTime(reader.GetDateTime(5));
            dueDate = NormalizeClientProductDueDate(clientProductId, dueDate);
            var daysLeft = dueDate == null ? (int?)null : dueDate.Value.DayNumber - DateOnly.FromDateTime(DateTime.UtcNow).DayNumber;

            return new AccountProductSummary(
                clientProductId,
                reader.GetInt32(1),
                reader.GetString(2).Trim(),
                reader.GetString(3).Trim(),
                reader.GetString(4),
                dueDate,
                daysLeft,
                StatusLabel(reader.GetInt32(6)),
                DateOnly.FromDateTime(reader.GetDateTime(7)),
                DateOnly.FromDateTime(reader.GetDateTime(8)),
                reader.IsDBNull(9) ? "" : reader.GetString(9),
                reader.IsDBNull(10) ? (decimal?)null : reader.GetDecimal(10)
            );
        }

        private static async Task<List<AddonCatalogProduct>> LoadAddonCatalogAsync(SqlConnection connection, string customerType)
        {
            const string sql = @"
SELECT p.product_id, p.name, p.description, p.product_type,
       pr.price_id, pr.currency, pr.payment_term, pr.setup_fee, pr.price_amount, pr.original_price_amount
FROM oms.dbo.product p
LEFT JOIN oms.dbo.price pr ON pr.product_id = p.product_id
WHERE p.active = 1
  AND (p.product_type = @customerType OR p.product_type = 'individual')
  AND (
       p.name LIKE 'SSL%' OR
       p.name LIKE 'SPACEMSSQL%' OR
       p.name LIKE 'SPACEMYSQL%' OR
       p.name LIKE 'SPACEEMAIL%' OR
       p.name LIKE 'SPACEWEB%' OR
       p.name LIKE 'STATICIP%' OR
       p.name LIKE 'RAM%' OR
       p.name LIKE 'CloudBackup%' OR
       p.name LIKE 'DataBackup%' OR
       p.name LIKE 'ServerBackup%' OR
       p.name LIKE 'CustomBackup%' OR
       p.name LIKE 'Site Guard%' OR
       p.name LIKE 'SQLJOB%' OR
       p.name LIKE 'SSRS%' OR
       p.name LIKE 'SCHTASK%' OR
       p.name LIKE 'File-Limit100k%' OR
       p.name LIKE 'SITE%' OR
       p.name LIKE 'MYSQL%' OR
       p.name LIKE 'MSSQL%'
  )
ORDER BY
  CASE
    WHEN p.name LIKE 'SSL%' THEN 0
    WHEN p.name LIKE 'STATICIP%' THEN 1
    WHEN p.name LIKE 'RAM%' THEN 2
    WHEN p.name LIKE '%Backup%' THEN 3
    ELSE 4
  END,
  p.name,
  pr.price_amount";

            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@customerType", string.IsNullOrWhiteSpace(customerType) ? "individual" : customerType);

            var products = new Dictionary<int, AddonCatalogProduct>();
            await using var reader = await command.ExecuteReaderAsync();
            while (await reader.ReadAsync())
            {
                var productId = reader.GetInt32(0);
                if (!products.TryGetValue(productId, out var product))
                {
                    var name = reader.GetString(1).Trim();
                    product = new AddonCatalogProduct(
                        productId,
                        name,
                        reader.GetString(2).Trim(),
                        reader.GetString(3),
                        AddonCategory(name),
                        new List<AddonPriceOption>()
                    );
                    products.Add(productId, product);
                }

                if (!reader.IsDBNull(4))
                {
                    product.Prices.Add(new AddonPriceOption(
                        reader.GetInt32(4),
                        reader.GetString(5),
                        reader.GetString(6),
                        reader.GetDecimal(7),
                        reader.GetDecimal(8),
                        reader.GetDecimal(9)
                    ));
                }
            }

            return new List<AddonCatalogProduct>(products.Values);
        }

        private static async Task<List<AccountProductSummary>> LoadActiveAddonsAsync(SqlConnection connection, long customerId)
        {
            const string sql = @"
SELECT TOP 100 cp.client_product_id, cp.product_id, p.name, p.description, p.product_type,
       cp.next_due_date, cp.status, cp.create_date, cp.last_update,
       latestOrder.payment_term, latestOrder.amount
FROM oms.dbo.client_product cp
INNER JOIN oms.dbo.product p ON p.product_id = cp.product_id
OUTER APPLY (
    SELECT TOP 1 o.payment_term, o.amount
    FROM oms.dbo.[order] o
    WHERE o.client_product_id = cp.client_product_id
      AND o.order_status <> 'refunded'
    ORDER BY o.create_date DESC, o.order_id DESC
) latestOrder
WHERE cp.client_id = @customerId
  AND cp.status = 1
  AND (
       p.name LIKE 'SSL%' OR
       p.name LIKE 'SPACEMSSQL%' OR
       p.name LIKE 'SPACEMYSQL%' OR
       p.name LIKE 'SPACEEMAIL%' OR
       p.name LIKE 'SPACEWEB%' OR
       p.name LIKE 'STATICIP%' OR
       p.name LIKE 'RAM%' OR
       p.name LIKE 'CloudBackup%' OR
       p.name LIKE 'DataBackup%' OR
       p.name LIKE 'ServerBackup%' OR
       p.name LIKE 'CustomBackup%' OR
       p.name LIKE 'Site Guard%' OR
       p.name LIKE 'SQLJOB%' OR
       p.name LIKE 'SSRS%' OR
       p.name LIKE 'SCHTASK%' OR
       p.name LIKE 'File-Limit100k%'
  )
ORDER BY CASE WHEN cp.next_due_date IS NULL THEN 1 ELSE 0 END, cp.next_due_date, p.name";

            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@customerId", customerId);

            var rows = new List<AccountProductSummary>();
            await using var reader = await command.ExecuteReaderAsync();
            while (await reader.ReadAsync())
            {
                rows.Add(ReadAccountProduct(reader));
            }

            return rows;
        }

        private static string AddonCategory(string productName)
        {
            var name = productName.ToUpperInvariant();
            if (name.StartsWith("SSL", StringComparison.Ordinal)) return "SSL";
            if (name.Contains("BACKUP", StringComparison.Ordinal)) return "Backup";
            if (name.StartsWith("MSSQL", StringComparison.Ordinal) || name.StartsWith("MYSQL", StringComparison.Ordinal) || name.StartsWith("SPACEMSSQL", StringComparison.Ordinal) || name.StartsWith("SPACEMYSQL", StringComparison.Ordinal) || name.StartsWith("SQLJOB", StringComparison.Ordinal) || name.StartsWith("SSRS", StringComparison.Ordinal)) return "Database";
            if (name.StartsWith("SPACEEMAIL", StringComparison.Ordinal)) return "Email";
            if (name.StartsWith("STATICIP", StringComparison.Ordinal)) return "IP";
            if (name.StartsWith("RAM", StringComparison.Ordinal) || name.StartsWith("SPACEWEB", StringComparison.Ordinal) || name.StartsWith("FILE-LIMIT", StringComparison.Ordinal) || name.StartsWith("SITE", StringComparison.Ordinal) || name.StartsWith("SCHTASK", StringComparison.Ordinal)) return "Hosting";
            return "Other";
        }

        private static async Task<List<AffiliateReferralSummary>> LoadAffiliateReferralsAsync(SqlConnection connection, long customerId)
        {
            const string sql = @"
SELECT cp.customerID, cp.customerLogin, cp.account_start_date,
       uds.status,
       CASE WHEN EXISTS (
            SELECT 1
            FROM oms.dbo.client_product paid
            WHERE paid.client_id = cp.customerID
              AND paid.status = 1
       ) THEN CAST(1 AS bit) ELSE CAST(0 AS bit) END AS is_paid
FROM dbo.upline_downline ud
INNER JOIN dbo.customer_profile cp ON cp.customerID = ud.downline_id
LEFT JOIN dbo.upline_downline_status uds ON uds.downline_id = ud.downline_id
WHERE ud.upline_id = @customerId
ORDER BY cp.account_start_date DESC, cp.customerLogin";

            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@customerId", customerId);

            var rows = new List<AffiliateReferralSummary>();
            await using var reader = await command.ExecuteReaderAsync();
            while (await reader.ReadAsync())
            {
                rows.Add(new AffiliateReferralSummary(
                    reader.GetInt64(0),
                    reader.GetString(1),
                    reader.IsDBNull(2) ? null : DateOnly.FromDateTime(reader.GetDateTime(2)),
                    reader.IsDBNull(3) ? "" : reader.GetString(3).Trim(),
                    !reader.IsDBNull(4) && reader.GetBoolean(4)
                ));
            }

            return rows;
        }

        private static async Task<List<AffiliateCommissionSummary>> LoadAffiliateCommissionsAsync(SqlConnection connection, long customerId)
        {
            const string sql = @"
SELECT ccc.client_commission_cashin_id, ccc.client_product_id,
       cp.customerLogin, p.name, ccc.description,
       ccc.commission_cashin, ccc.create_date,
       DATEADD(day, 90, ccc.create_date) AS release_date
FROM oms.dbo.client_commission_cashin ccc
INNER JOIN oms.dbo.client_product clientProduct ON clientProduct.client_product_id = ccc.client_product_id
INNER JOIN dbo.customer_profile cp ON cp.customerID = clientProduct.client_id
INNER JOIN oms.dbo.product p ON p.product_id = clientProduct.product_id
WHERE ccc.client_id = @customerId
ORDER BY ccc.create_date DESC, ccc.client_commission_cashin_id DESC";

            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@customerId", customerId);

            var today = DateOnly.FromDateTime(DateTime.UtcNow);
            var rows = new List<AffiliateCommissionSummary>();
            await using var reader = await command.ExecuteReaderAsync();
            while (await reader.ReadAsync())
            {
                var releaseDate = DateOnly.FromDateTime(reader.GetDateTime(7));
                rows.Add(new AffiliateCommissionSummary(
                    reader.GetInt32(0),
                    reader.GetInt32(1),
                    reader.GetString(2),
                    reader.GetString(3),
                    reader.GetString(4),
                    reader.GetDecimal(5),
                    DateOnly.FromDateTime(reader.GetDateTime(6)),
                    releaseDate,
                    releaseDate <= today
                ));
            }

            return rows;
        }

