        private static string MaskStoredSecret(string value)
        {
            if (string.IsNullOrWhiteSpace(value))
            {
                return "";
            }

            var trimmed = value.Trim();
            if (trimmed.Contains('@', StringComparison.Ordinal) && trimmed.Length <= 120)
            {
                var parts = trimmed.Split('@', 2);
                var local = parts[0];
                var domain = parts[1];
                var visibleLocal = local.Length <= 2 ? local[..1] : local[..2];
                return $"{visibleLocal}***@{domain}";
            }

            return "Stored securely";
        }

        private async Task<string> ReadableStoredEmailAsync(string value)
        {
            var trimmed = (value ?? "").Trim();
            if (string.IsNullOrWhiteSpace(trimmed))
            {
                return "";
            }

            if (IsValidEmail(trimmed))
            {
                return trimmed;
            }

            var modernKey = ConfigOrEnv("Crypto:ModernKey", "CONTROL_PANEL_CRYPTO_KEY").Trim();
            if (!string.IsNullOrWhiteSpace(modernKey))
            {
                var decrypted = CryptoHelper.Decrypt(modernKey, trimmed);
                if (IsValidEmail(decrypted))
                {
                    return decrypted;
                }
            }

            var compatibilitySalt = ConfigOrEnv("Crypto:Pbkdf2CompatibilitySalt", "PBKDF2_COMPATIBILITY_SALT").Trim();
            if (!string.IsNullOrWhiteSpace(modernKey) && !string.IsNullOrWhiteSpace(compatibilitySalt))
            {
                var decrypted = CryptoHelper.DecryptPbkdf2AesCbcHex(modernKey, trimmed, compatibilitySalt);
                if (IsValidEmail(decrypted))
                {
                    return decrypted;
                }
            }

            var legacyDecryptUrl = ConfigOrEnv("LegacyCrypto:DecryptPwdApiUrl", "LEGACY_DECRYPTPWD_API_URL").Trim();
            if (!string.IsNullOrWhiteSpace(legacyDecryptUrl))
            {
                var decrypted = await TryLegacyDecryptPwdApiAsync(legacyDecryptUrl, trimmed);
                if (IsValidEmail(decrypted))
                {
                    return decrypted;
                }
            }

            return "Stored securely";
        }

        private async Task<string> ReadableTwoFactorSecretAsync(string value)
        {
            var trimmed = (value ?? "").Trim();
            if (string.IsNullOrWhiteSpace(trimmed))
            {
                return "";
            }

            if (LooksLikeTotpSecret(trimmed))
            {
                return trimmed;
            }

            var modernKey = ConfigOrEnv("Crypto:ModernKey", "CONTROL_PANEL_CRYPTO_KEY").Trim();
            if (!string.IsNullOrWhiteSpace(modernKey))
            {
                var decrypted = CryptoHelper.Decrypt(modernKey, trimmed);
                if (LooksLikeTotpSecret(decrypted))
                {
                    return decrypted.Trim();
                }
            }

            var compatibilitySalt = ConfigOrEnv("Crypto:Pbkdf2CompatibilitySalt", "PBKDF2_COMPATIBILITY_SALT").Trim();
            if (!string.IsNullOrWhiteSpace(modernKey) && !string.IsNullOrWhiteSpace(compatibilitySalt))
            {
                var decrypted = CryptoHelper.DecryptPbkdf2AesCbcHex(modernKey, trimmed, compatibilitySalt);
                if (LooksLikeTotpSecret(decrypted))
                {
                    return decrypted.Trim();
                }
            }

            var legacyDecryptUrl = ConfigOrEnv("LegacyCrypto:DecryptPwdApiUrl", "LEGACY_DECRYPTPWD_API_URL").Trim();
            if (!string.IsNullOrWhiteSpace(legacyDecryptUrl))
            {
                var decrypted = await TryLegacyDecryptPwdApiAsync(legacyDecryptUrl, trimmed);
                if (LooksLikeTotpSecret(decrypted))
                {
                    return decrypted.Trim();
                }
            }

            return "";
        }

        private static bool LooksLikeTotpSecret(string value)
        {
            var trimmed = (value ?? "").Trim();
            return trimmed.Length is >= 8 and <= 128
                && trimmed.All(character => char.IsLetterOrDigit(character) || character == '=');
        }

        private static async Task<string> TryLegacyDecryptPwdApiAsync(string apiUrl, string encryptedValue)
        {
            try
            {
                using var httpClient = new HttpClient { Timeout = TimeSpan.FromSeconds(10) };
                using var request = new HttpRequestMessage(HttpMethod.Post, apiUrl)
                {
                    Content = new FormUrlEncodedContent(new Dictionary<string, string>
                    {
                        ["action"] = "decryptpwd",
                        ["mode"] = "decryptpwd",
                        ["kind"] = "decryptpwd",
                        ["value"] = encryptedValue,
                        ["pwd"] = encryptedValue,
                        ["pwd_hash"] = encryptedValue
                    })
                };

                var response = await httpClient.SendAsync(request);
                if (!response.IsSuccessStatusCode)
                {
                    var separator = apiUrl.Contains('?', StringComparison.Ordinal) ? "&" : "?";
                    var url = $"{apiUrl}{separator}pwd_hash={Uri.EscapeDataString(encryptedValue)}";
                    response = await httpClient.GetAsync(url);
                    if (!response.IsSuccessStatusCode)
                    {
                        return "";
                    }
                }

                var text = (await response.Content.ReadAsStringAsync()).Trim();
                return text.Contains('<', StringComparison.Ordinal) ? "" : text;
            }
            catch
            {
                return "";
            }
        }

        private async Task<string> TryLegacyDecryptFtpPwdAsync(string encryptedValue)
        {
            var apiUrl = ConfigOrEnv("LegacyCrypto:DecryptFtpPwdApiUrl", "LEGACY_DECRYPTFTPPWD_API_URL").Trim();
            if (string.IsNullOrWhiteSpace(apiUrl))
            {
                apiUrl = ConfigOrEnv("LegacyCrypto:DecryptPwdApiUrl", "LEGACY_DECRYPTPWD_API_URL").Trim();
            }

            if (string.IsNullOrWhiteSpace(apiUrl) || string.IsNullOrWhiteSpace(encryptedValue))
            {
                return "";
            }

            return await TryLegacyDecryptApiAsync(apiUrl, encryptedValue, "decryptFTPpwd");
        }

        private static async Task<string> TryLegacyDecryptApiAsync(string apiUrl, string encryptedValue, string kind)
        {
            try
            {
                using var httpClient = new HttpClient { Timeout = TimeSpan.FromSeconds(10) };
                using var request = new HttpRequestMessage(HttpMethod.Post, apiUrl)
                {
                    Content = new FormUrlEncodedContent(new Dictionary<string, string>
                    {
                        ["action"] = kind,
                        ["mode"] = kind,
                        ["kind"] = kind,
                        ["value"] = encryptedValue,
                        ["pwd"] = encryptedValue,
                        ["pwd_hash"] = encryptedValue
                    })
                };

                var response = await httpClient.SendAsync(request);
                if (!response.IsSuccessStatusCode)
                {
                    return "";
                }

                var text = (await response.Content.ReadAsStringAsync()).Trim();
                return text.Contains('<', StringComparison.Ordinal) ? "" : text;
            }
            catch (Exception ex) when (ex is HttpRequestException or TaskCanceledException)
            {
                return "";
            }
        }

        private static AffiliateSummary BuildAffiliateSummary(List<AffiliateReferralSummary> referrals, List<AffiliateCommissionSummary> commissions, List<AffiliatePayoutSummary> payouts)
        {
            var pending = 0m;
            var current = 0m;

            foreach (var commission in commissions)
            {
                if (commission.IsReleased)
                {
                    current += commission.Amount;
                }
                else
                {
                    pending += commission.Amount;
                }
            }

            var paidOut = 0m;
            foreach (var payout in payouts)
            {
                paidOut += payout.Amount;
            }

            return new AffiliateSummary(
                referrals.Count,
                referrals.FindAll((referral) => referral.IsPaid).Count,
                referrals.FindAll((referral) => string.Equals(referral.Status, "valid", StringComparison.OrdinalIgnoreCase)).Count,
                pending,
                current,
                paidOut,
                current - paidOut
            );
        }

        private static AffiliateWithdrawPreview BuildAffiliateWithdrawPreview(decimal amount, string method, AffiliateSummary summary, List<AffiliateReferralSummary> referrals)
        {
            var paidReferralsThisYear = 0;
            var cutoff = DateOnly.FromDateTime(DateTime.UtcNow.AddYears(-1));
            foreach (var referral in referrals)
            {
                if (referral.IsPaid && referral.AccountStartDate >= cutoff)
                {
                    paidReferralsThisYear++;
                }
            }

            var isPaypal = method.Equals("paypal", StringComparison.OrdinalIgnoreCase) || method.Equals("cash", StringComparison.OrdinalIgnoreCase);
            var minimum = isPaypal ? 100m : 1m;
            var eligible = amount >= minimum && amount <= summary.AvailableCommission && paidReferralsThisYear >= 3;
            var message = eligible
                ? isPaypal
                    ? "PayPal payout request is eligible and can be submitted."
                    : "Commission is eligible to convert to account credit once the credit ledger service is available."
                : "Withdraw is not eligible yet. Legacy rules require enough available commission, the method minimum, and at least 3 paid referrals in the last year.";

            return new AffiliateWithdrawPreview(
                amount,
                method,
                summary.AvailableCommission,
                paidReferralsThisYear,
                minimum,
                eligible,
                message
            );
        }

        private static bool IsValidEmail(string value)
        {
            try
