        private static async Task<List<AccountDomainSummary>> LoadAccountDomainsAsync(SqlConnection connection, long customerId)
        {
            const string sql = @"
SELECT dp.id, dp.domain_name, dp.client_product_id, dp.status, dp.StartDate, dp.BuyYear,
       dp.RegisterStatus, dp.RegisterInfoID, dp.AddDate, cp.next_due_date, cp.status AS product_status,
       CASE WHEN privacyTld.tld IS NULL THEN 0 ELSE 1 END AS whois_privacy_supported,
       CASE WHEN privacy.client_product_id IS NULL THEN 0 ELSE 1 END AS whois_privacy_purchased,
       privacy.turnOnDate,
       ISNULL(grace.graceperiod, 0) AS grace_period_days
FROM domaincontroller.dbo.domain_profile dp
LEFT JOIN oms.dbo.client_product cp ON cp.client_product_id = dp.client_product_id
OUTER APPLY (
    SELECT TOP 1 tld
    FROM domaincontroller.dbo.domain_privacy_tld
    WHERE SUBSTRING(dp.domain_name, CHARINDEX('.', dp.domain_name), LEN(dp.domain_name)) = tld
) privacyTld
OUTER APPLY (
    SELECT TOP 1 p.client_product_id, p.turnOnDate
    FROM domaincontroller.dbo.domain_privacy p
    INNER JOIN oms.dbo.client_product privacyCp ON privacyCp.client_product_id = p.client_product_id
    WHERE LOWER(p.domain) = LOWER(dp.domain_name)
      AND privacyCp.status = 1
) privacy
OUTER APPLY (
    SELECT TOP 1 graceperiod
    FROM domaincontroller.dbo.domain_graceperiod_tld
    WHERE SUBSTRING(dp.domain_name, CHARINDEX('.', dp.domain_name), LEN(dp.domain_name)) = tld
) grace
WHERE dp.customer_profile_id = @customerId
ORDER BY dp.domain_name";

            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@customerId", customerId);

            var today = DateOnly.FromDateTime(DateTime.UtcNow);
            var rows = new List<AccountDomainSummary>();

            await using var reader = await command.ExecuteReaderAsync();
            while (await reader.ReadAsync())
            {
                var startDate = reader.IsDBNull(4) ? (DateOnly?)null : DateOnly.FromDateTime(reader.GetDateTime(4));
                var buyYear = reader.IsDBNull(5) ? 1 : reader.GetInt32(5);
                var expirationDate = CalculateDomainExpiration(startDate, buyYear);
                var daysLeft = expirationDate == null ? (int?)null : expirationDate.Value.DayNumber - today.DayNumber;

                // Match legacy domain_list.asp: hide domains more than 40 days past expiration unless start date is the placeholder.
                if (daysLeft < -40 && startDate != new DateOnly(1900, 1, 1))
                {
                    continue;
                }

                var status = reader.IsDBNull(3) ? "unknown" : reader.GetString(3).Trim();
                if (daysLeft < 0 && startDate != null && startDate != new DateOnly(1900, 1, 1))
                {
                    status = "expired";
                }

                var registerStatus = reader.IsDBNull(6) ? "" : reader.GetString(6).Trim();
                var clientProductId = reader.GetInt32(2);
                var canRenew = clientProductId > 0 && (status.Equals("completed", StringComparison.OrdinalIgnoreCase) || status.Equals("expired", StringComparison.OrdinalIgnoreCase));
                var canManage = status.Equals("completed", StringComparison.OrdinalIgnoreCase);
                var transferActionLabel = "";
                var transferActionUrl = "";
                if (status.Equals("in-progress", StringComparison.OrdinalIgnoreCase) || registerStatus.Equals("in-progress", StringComparison.OrdinalIgnoreCase))
                {
                    transferActionLabel = "Transfer Log";
                    transferActionUrl = "/account/transfer_domain_step6";
                }
                else if (status.Equals("cancelled", StringComparison.OrdinalIgnoreCase) || registerStatus.Equals("cancelled", StringComparison.OrdinalIgnoreCase))
                {
                    transferActionLabel = "Resubmit";
                    transferActionUrl = $"/account/transfer_domain_step3_detail?profileid={reader.GetInt32(7)}";
                }

                rows.Add(new AccountDomainSummary(
                    reader.GetInt32(0),
                    reader.GetString(1).Trim(),
                    clientProductId,
                    status,
                    startDate,
                    expirationDate,
                    daysLeft,
                    registerStatus,
                    reader.IsDBNull(7) ? 0 : reader.GetInt32(7),
                    reader.IsDBNull(8) ? null : DateOnly.FromDateTime(reader.GetDateTime(8)),
                    reader.IsDBNull(9) ? null : DateOnly.FromDateTime(reader.GetDateTime(9)),
                    reader.IsDBNull(10) ? "Unknown" : StatusLabel(reader.GetInt32(10)),
                    ReadBoolean(reader, 11),
                    ReadBoolean(reader, 12),
                    reader.IsDBNull(13) ? null : DateOnly.FromDateTime(reader.GetDateTime(13)),
                    ReadInt32(reader, 14),
                    canRenew,
                    canManage,
                    canRenew ? $"/account/domain_renew?client_product_id={clientProductId}" : "",
                    canManage ? $"/account/editdns?profileid={reader.GetInt32(0)}" : "",
                    canManage ? $"/account/domain_profile?profileid={reader.GetInt32(7)}" : "",
                    transferActionLabel,
                    transferActionUrl
                ));
            }

            return rows;
        }

        private static async Task<AccountDomainSummary?> LoadOwnedAccountDomainAsync(SqlConnection connection, long customerId, int domainId)
        {
            var domains = await LoadAccountDomainsAsync(connection, customerId);
            return domains.Find(item => item.Id == domainId);
        }

        private List<string> HostingDefaultDnsServers()
        {
            return ConfigOrEnv("HostingDefaults:DnsServers", "HOSTING_DEFAULT_DNS_SERVERS", "NS1.SITE4NOW.NET,NS2.SITE4NOW.NET,NS3.SITE4NOW.NET")
                .Split(new[] { ',', ';', '\n', '\r' }, StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList();
        }

        private sealed record SimpleDnsSettings(string ApiUrl, string Username, string Password)
        {
            public bool IsConfigured =>
                !string.IsNullOrWhiteSpace(ApiUrl)
                && !string.IsNullOrWhiteSpace(Username)
                && !string.IsNullOrWhiteSpace(Password);
        }

        private SimpleDnsSettings GetSimpleDnsSettings()
        {
            return new SimpleDnsSettings(
                ConfigOrEnv("SimpleDns:ApiUrl", "SIMPLEDNS_API_URL").Trim().TrimEnd('/'),
                ConfigOrEnv("SimpleDns:Username", "SIMPLEDNS_API_USERNAME").Trim(),
                ConfigOrEnv("SimpleDns:Password", "SIMPLEDNS_API_PASSWORD").Trim()
            );
        }

        private async Task<DomainDnsParseResult?> ListSimpleDnsRecordsAsync(string zoneName, bool includeSoa = false)
        {
            var settings = GetSimpleDnsSettings();
            if (!settings.IsConfigured)
            {
                return null;
            }

            zoneName = NormalizeZoneName(zoneName);
            if (string.IsNullOrWhiteSpace(zoneName))
            {
                return new DomainDnsParseResult(false, "Invalid zone name.", new List<DomainDnsRecordPreview>());
            }

            try
            {
                using var httpClient = CreateSimpleDnsClient(settings);
                using var response = await httpClient.GetAsync($"zones/{Uri.EscapeDataString(zoneName)}/records");
                var responseText = await response.Content.ReadAsStringAsync();
                if (!response.IsSuccessStatusCode)
                {
                    return new DomainDnsParseResult(false, $"SimpleDNS list failed: {(int)response.StatusCode} {response.ReasonPhrase}.", new List<DomainDnsRecordPreview>());
                }

                using var document = JsonDocument.Parse(responseText);
                var root = document.RootElement;
                if (root.ValueKind != JsonValueKind.Array)
                {
                    return new DomainDnsParseResult(false, "SimpleDNS returned an unexpected payload.", new List<DomainDnsRecordPreview>());
                }

                var records = new List<DomainDnsRecordPreview>();
                var index = 0;
                foreach (var record in root.EnumerateArray())
                {
                    var parsed = ParseSimpleDnsRecord(record, includeSoa, index);
                    if (parsed == null)
                    {
                        continue;
                    }

                    records.Add(parsed);
                    index++;
                }

                return new DomainDnsParseResult(true, "DNS records loaded.", records);
            }
            catch (Exception ex)
            {
                return new DomainDnsParseResult(false, $"Unable to load DNS records: {ex.Message}", new List<DomainDnsRecordPreview>());
            }
        }

        private async Task<DomainDnsParseResult?> DeleteSimpleDnsRecordByIndexAsync(string zoneName, int recordIndex)
        {
            var listResult = await ListSimpleDnsRecordsAsync(zoneName, includeSoa: false);
            if (listResult == null || !listResult.Success)
            {
                return listResult ?? new DomainDnsParseResult(false, "SimpleDNS is not configured. Set SIMPLEDNS_API_* and retry.", new List<DomainDnsRecordPreview>());
            }

            if (recordIndex < 0 || recordIndex >= listResult.Records.Count)
            {
                return new DomainDnsParseResult(false, "Choose a valid DNS record.", listResult.Records);
            }

            var target = listResult.Records[recordIndex];
            var patchPayload = new List<Dictionary<string, object?>>();

            var removeItem = new Dictionary<string, object?>(StringComparer.OrdinalIgnoreCase)
            {
                ["Remove"] = true,
                ["Name"] = target.Name,
                ["Type"] = target.Type
            };

            if (!string.IsNullOrWhiteSpace(target.Value))
            {
                removeItem["Data"] = target.Value;
            }

            patchPayload.Add(removeItem);

            var patchResult = await PatchSimpleDnsRecordsAsync(zoneName, patchPayload);
            if (!patchResult.Success)
            {
                return patchResult;
            }

            var refreshed = await ListSimpleDnsRecordsAsync(zoneName, includeSoa: false);
            return refreshed?.Success == true
                ? new DomainDnsParseResult(true, "DNS record deleted.", refreshed!.Records)
                : patchResult;
        }

        private async Task<DomainDnsParseResult?> DeleteTemporaryUrlDnsRecordAsync(string domainName)
        {
            var split = SplitTemporaryUrlDomain(domainName);
            if (split == null)
            {
                return null;
            }

            var current = await ListSimpleDnsRecordsAsync(split.Value.Zone, includeSoa: false);
            if (current == null)
            {
                return new DomainDnsParseResult(false, "SimpleDNS is not configured. Set SIMPLEDNS_API_* and retry.", new List<DomainDnsRecordPreview>());
            }

            if (!current.Success)
            {
                return current;
            }

            var matches = current.Records
                .Where(record =>
                    record.Type.Equals("A", StringComparison.OrdinalIgnoreCase)
                    && SimpleDnsRecordNameMatches(record.Name, split.Value.Host, split.Value.Zone, domainName))
                .ToList();

            if (matches.Count == 0)
            {
                return new DomainDnsParseResult(true, $"No temp URL DNS A record found for {domainName}.", current.Records);
            }

            var patchPayload = matches.Select(record =>
            {
                var removeItem = new Dictionary<string, object?>(StringComparer.OrdinalIgnoreCase)
                {
                    ["Remove"] = true,
                    ["Name"] = record.Name,
                    ["Type"] = record.Type
                };

                if (!string.IsNullOrWhiteSpace(record.Value))
                {
                    removeItem["Data"] = record.Value;
                }

                return removeItem;
            }).ToList();

            var patchResult = await PatchSimpleDnsRecordsAsync(split.Value.Zone, patchPayload);
            if (!patchResult.Success)
            {
                return patchResult;
            }

            var refreshed = await ListSimpleDnsRecordsAsync(split.Value.Zone, includeSoa: false);
            return refreshed?.Success == true
                ? new DomainDnsParseResult(true, $"Temp URL DNS A record deleted for {domainName}.", refreshed!.Records)
                : new DomainDnsParseResult(true, $"Temp URL DNS A record delete sent for {domainName}.", current.Records);
        }

        private async Task<DomainDnsParseResult?> UpsertSimpleDnsRecordAsync(string action, string zoneName, DomainDnsActionRequest? request)
        {
            action = (action ?? "").Trim().ToLowerInvariant();
            if (action is not ("add" or "edit"))
            {
                return new DomainDnsParseResult(false, "Select Add or Edit.", new List<DomainDnsRecordPreview>());
            }

            var current = await ListSimpleDnsRecordsAsync(zoneName, includeSoa: false);
            if (current == null)
            {
                return new DomainDnsParseResult(false, "SimpleDNS is not configured. Set SIMPLEDNS_API_* and retry.", new List<DomainDnsRecordPreview>());
            }

            if (!current.Success)
            {
                return current;
            }

            var settingsResult = ValidateSimpleDnsRequest(request, action);
            if (settingsResult != null)
            {
                return settingsResult;
            }

            zoneName = NormalizeZoneName(zoneName);
            if (string.IsNullOrWhiteSpace(zoneName))
            {
                return new DomainDnsParseResult(false, "Invalid zone name.", new List<DomainDnsRecordPreview>());
            }

            var patchPayload = new List<Dictionary<string, object?>>();
            var name = NormalizeSimpleDnsRecordName(request!.Name, zoneName);
            var type = (request.RecordType ?? "A").Trim().ToUpperInvariant();
            var value = (request.Value ?? "").Trim();
            var ttl = Math.Max(60, Math.Min(86400, request.Ttl <= 0 ? 300 : request.Ttl));

            if (action == "edit")
            {
                var recordIndex = request.RecordIndex ?? -1;
                if (recordIndex < 0 || recordIndex >= current.Records.Count)
                {
                    return new DomainDnsParseResult(false, "Select a valid DNS record to edit.", current.Records);
                }

                var oldRecord = current.Records[recordIndex];
                var removeOld = new Dictionary<string, object?>(StringComparer.OrdinalIgnoreCase)
                {
                    ["Remove"] = true,
                    ["Name"] = oldRecord.Name,
                    ["Type"] = oldRecord.Type
                };

                if (!string.IsNullOrWhiteSpace(oldRecord.Value))
                {
                    removeOld["Data"] = oldRecord.Value;
                }

                patchPayload.Add(removeOld);
            }

            var addItem = new Dictionary<string, object?>(StringComparer.OrdinalIgnoreCase)
            {
                ["Name"] = name,
                ["Type"] = type,
                ["TTL"] = ttl
            };

            var dataValue = BuildSimpleDnsRecordData(type, request);
            if (string.IsNullOrWhiteSpace(dataValue))
            {
                return new DomainDnsParseResult(false, "DNS record value is required.", current.Records);
            }
            addItem["Data"] = dataValue;

            if (request.Priority.HasValue)
            {
                addItem["Priority"] = Math.Max(0, Math.Min(65535, request.Priority.Value));
            }
            if (request.Weight.HasValue)
            {
                addItem["Weight"] = Math.Max(0, Math.Min(65535, request.Weight.Value));
            }
            if (request.Port.HasValue)
            {
                addItem["Port"] = Math.Max(1, Math.Min(65535, request.Port.Value));
            }

            patchPayload.Add(addItem);

            var patchResult = await PatchSimpleDnsRecordsAsync(zoneName, patchPayload);
            if (!patchResult.Success)
            {
                return patchResult;
            }

            var refreshed = await ListSimpleDnsRecordsAsync(zoneName, includeSoa: false);
            return refreshed?.Success == true
                ? new DomainDnsParseResult(true, action == "add" ? "DNS record added." : "DNS record updated.", refreshed!.Records)
                : patchResult;
        }

        private static DomainDnsParseResult? ValidateSimpleDnsRequest(DomainDnsActionRequest? request, string action)
        {
            if (request == null)
            {
                return new DomainDnsParseResult(false, "Request body is required.", new List<DomainDnsRecordPreview>());
            }

            if (string.IsNullOrWhiteSpace(request.RecordType))
            {
                return new DomainDnsParseResult(false, "Record type is required.", new List<DomainDnsRecordPreview>());
            }

            if (action == "edit" && request.RecordIndex == null)
            {
                return new DomainDnsParseResult(false, "Record index is required for edit.", new List<DomainDnsRecordPreview>());
            }

            return null;
        }

        private static string NormalizeSimpleDnsRecordName(string name, string zoneName)
        {
            var trimmed = NormalizeSimpleInput(name);
            if (string.IsNullOrWhiteSpace(trimmed))
            {
                return "@";
            }

            if (trimmed.Contains("@", StringComparison.Ordinal))
            {
                return zoneName;
            }

            if (trimmed == "*")
            {
                return $"*.{zoneName}";
            }

            if (trimmed.Equals("www", StringComparison.OrdinalIgnoreCase))
            {
                return $"www.{zoneName}";
            }

            if (trimmed.EndsWith($".{zoneName}", StringComparison.OrdinalIgnoreCase))
            {
                return trimmed;
            }

            if (trimmed.Contains('.', StringComparison.Ordinal) && !trimmed.EndsWith(".", StringComparison.Ordinal))
            {
                return trimmed;
            }

            return $"{trimmed}.{zoneName}";
        }

        private static string NormalizeSimpleInput(string value)
            => value.Trim().TrimStart('.', '\\', '/');

        private static string NormalizeZoneName(string? zoneName)
            => (zoneName ?? "").Trim().Trim('.').ToLowerInvariant();

        private static (string Host, string Zone)? SplitTemporaryUrlDomain(string? domainName)
        {
            var normalized = NormalizeZoneName(domainName);
            if (string.IsNullOrWhiteSpace(normalized) || !normalized.Contains("tempurl.com", StringComparison.OrdinalIgnoreCase))
            {
                return null;
            }

            var labels = normalized.Split('.', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
            if (labels.Length < 3)
            {
                return null;
            }

            var zone = string.Join('.', labels.Skip(labels.Length - 2));
            var host = string.Join('.', labels.Take(labels.Length - 2));
            return string.IsNullOrWhiteSpace(host) || string.IsNullOrWhiteSpace(zone) ? null : (host, zone);
        }

        private static bool SimpleDnsRecordNameMatches(string recordName, string host, string zoneName, string fullDomain)
        {
            var normalizedRecord = NormalizeZoneName(recordName);
            var normalizedHost = NormalizeZoneName(host);
            var normalizedZone = NormalizeZoneName(zoneName);
            var normalizedDomain = NormalizeZoneName(fullDomain);
            return normalizedRecord.Equals(normalizedHost, StringComparison.OrdinalIgnoreCase)
                || normalizedRecord.Equals(normalizedDomain, StringComparison.OrdinalIgnoreCase)
                || normalizedRecord.Equals($"{normalizedHost}.{normalizedZone}", StringComparison.OrdinalIgnoreCase);
        }

        private static string? BuildSimpleDnsRecordData(string type, DomainDnsActionRequest request)
        {
            var value = NormalizeSimpleInput(request.Value ?? "");
            var name = NormalizeSimpleInput(request.Name ?? "");
            var typeUpper = type.ToUpperInvariant();

            if (string.IsNullOrWhiteSpace(value))
            {
                return null;
            }

            return typeUpper switch
            {
                "MX" => $"{value} {(request.Priority ?? 10)}",
                "SRV" => $"{name} {request.Priority ?? 10} {(request.Weight ?? 0)} {(request.Port ?? 443)} {value}",
                _ => value
            };
        }

        private static DomainDnsRecordPreview? ParseSimpleDnsRecord(JsonElement record, bool includeSoa, int index)
        {
            var type = JsonStringProperty(record, "Type");
            if (string.IsNullOrWhiteSpace(type))
            {
                return null;
            }

            if (!includeSoa && type.Equals("SOA", StringComparison.OrdinalIgnoreCase))
            {
                return null;
            }

            var name = JsonStringProperty(record, "Name");
            var data = JsonStringProperty(record, "Data");
            if (string.IsNullOrWhiteSpace(name))
            {
                return null;
            }

            var ttl = JsonIntProperty(record, "TTL", 300);
            int? priority = JsonNullableIntProperty(record, "Priority");

            if (string.IsNullOrWhiteSpace(data))
            {
                data = JsonStringProperty(record, "Value");
            }

            return new DomainDnsRecordPreview(
                type.Trim().ToUpperInvariant(),
                name.Trim(),
                data ?? "",
                priority,
                ttl,
                index
            );
        }

        private async Task<DomainDnsParseResult> PatchSimpleDnsRecordsAsync(string zoneName, List<Dictionary<string, object?>> payload)
        {
            var settings = GetSimpleDnsSettings();
            if (!settings.IsConfigured)
            {
                return new DomainDnsParseResult(false, "SimpleDNS is not configured. Set SIMPLEDNS_API_URL, SIMPLEDNS_API_USERNAME, and SIMPLEDNS_API_PASSWORD.", new List<DomainDnsRecordPreview>());
            }

            zoneName = NormalizeZoneName(zoneName);
            if (string.IsNullOrWhiteSpace(zoneName))
            {
                return new DomainDnsParseResult(false, "Invalid zone name.", new List<DomainDnsRecordPreview>());
            }

            try
            {
                var requestBody = JsonSerializer.Serialize(payload);
                using var httpClient = CreateSimpleDnsClient(settings);
                using var content = new StringContent(requestBody, Encoding.UTF8, "application/json");
                using var response = await httpClient.PatchAsync($"zones/{Uri.EscapeDataString(zoneName)}/records", content);
                if (!response.IsSuccessStatusCode)
                {
                    var responseText = await response.Content.ReadAsStringAsync();
                    return new DomainDnsParseResult(false, $"SimpleDNS update failed: {(int)response.StatusCode} {response.ReasonPhrase}. {responseText}".Trim(), new List<DomainDnsRecordPreview>());
                }

                return new DomainDnsParseResult(true, "DNS record update sent.", new List<DomainDnsRecordPreview>());
            }
            catch (Exception ex)
            {
                return new DomainDnsParseResult(false, $"Unable to update DNS records: {ex.Message}", new List<DomainDnsRecordPreview>());
            }
        }

        private static HttpClient CreateSimpleDnsClient(SimpleDnsSettings settings)
        {
            var authBytes = Encoding.UTF8.GetBytes($"{settings.Username}:{settings.Password}");
            var handler = new HttpClientHandler
            {
                PreAuthenticate = true
            };
            var httpClient = new HttpClient(handler)
            {
                BaseAddress = new Uri(settings.ApiUrl.TrimEnd('/') + "/"),
                Timeout = TimeSpan.FromSeconds(30)
            };
            httpClient.DefaultRequestHeaders.Authorization =
                new AuthenticationHeaderValue(
                    "Basic",
                    Convert.ToBase64String(authBytes)
                );
            return httpClient;
        }

        private LegacyDnsAgentSettings GetLegacyDnsAgentSettings()
        {
            return new LegacyDnsAgentSettings(
                ConfigOrEnv("LegacyDnsAgent:Url", "LEGACY_DNS_AGENT_URL").Trim(),
                ConfigOrEnv("LegacyDnsAgent:Token", "LEGACY_DNS_AGENT_TOKEN").Trim());
        }

        private async Task<LegacyDnsAgentResult> PostLegacyDnsAgentAsync(string action, string zoneName, Dictionary<string, string> form)
        {
            var settings = GetLegacyDnsAgentSettings();
            if (!settings.IsConfigured)
            {
                return new LegacyDnsAgentResult(false, settings.MissingMessage, new List<DomainDnsRecordPreview>());
            }

            var fields = new Dictionary<string, string>(form, StringComparer.OrdinalIgnoreCase)
            {
                ["action"] = action,
                ["zonename"] = zoneName.Trim().TrimEnd('.').ToLowerInvariant()
            };
            if (!string.IsNullOrWhiteSpace(settings.Token))
            {
                fields["token"] = settings.Token;
            }

            try
            {
                using var httpClient = new HttpClient { Timeout = TimeSpan.FromSeconds(30) };
                using var response = await httpClient.PostAsync(settings.Url, new FormUrlEncodedContent(fields));
                var body = await response.Content.ReadAsStringAsync();
                var parsed = ParseLegacyDnsAgentResponse(body);
                if (parsed == null)
                {
                    return new LegacyDnsAgentResult(false, $"DNS agent returned an unreadable response ({(int)response.StatusCode}).", new List<DomainDnsRecordPreview>());
                }

                if (!response.IsSuccessStatusCode && parsed.Success)
                {
                    return parsed with { Success = false, Message = $"DNS agent returned HTTP {(int)response.StatusCode}: {parsed.Message}" };
                }

                return parsed;
            }
            catch (Exception ex)
            {
                return new LegacyDnsAgentResult(false, $"Unable to reach live DNS agent: {ex.Message}", new List<DomainDnsRecordPreview>());
            }
        }

        private static LegacyDnsAgentResult? ParseLegacyDnsAgentResponse(string body)
        {
            try
            {
                using var document = JsonDocument.Parse(body);
                var root = document.RootElement;
                var success = root.TryGetProperty("success", out var successElement) && successElement.ValueKind == JsonValueKind.True;
                var message = root.TryGetProperty("message", out var messageElement) ? messageElement.GetString() ?? "" : "";
                var records = new List<DomainDnsRecordPreview>();

                if (root.TryGetProperty("records", out var recordsElement) && recordsElement.ValueKind == JsonValueKind.Array)
                {
                    foreach (var item in recordsElement.EnumerateArray())
                    {
                        var type = JsonStringProperty(item, "type").ToUpperInvariant();
                        var name = JsonStringProperty(item, "name");
                        var value = JsonStringProperty(item, "value");
                        var priority = JsonNullableIntProperty(item, "priority");
                        var ttl = JsonIntProperty(item, "ttl", 300);
                        var index = JsonNullableIntProperty(item, "index");
                        if (string.IsNullOrWhiteSpace(type) || string.IsNullOrWhiteSpace(name))
                        {
                            continue;
                        }

                        records.Add(new DomainDnsRecordPreview(type, name, value, priority, ttl, index));
                    }
                }

                return new LegacyDnsAgentResult(success, string.IsNullOrWhiteSpace(message) ? "DNS agent completed." : message, records);
            }
            catch
            {
                return null;
            }
        }

        private static List<DomainDnsRecordPreview> BuildDnsStarterRecords(string domainName)
        {
            return new List<DomainDnsRecordPreview>
            {
                new("A", "@", "208.98.35.146", null, 300),
                new("CNAME", "www", domainName.TrimEnd('.').ToLowerInvariant(), null, 300),
                new("MX", "@", $"mail.{domainName.TrimEnd('.').ToLowerInvariant()}", 10, 300),
                new("TXT", "@", "v=spf1 a mx include:_spf.site4now.net -all", null, 300)
            };
        }

        private static string BuildDnsRecordLine(DomainDnsActionRequest? request, string domainName)
        {
            var type = (request?.RecordType ?? "A").Trim().ToUpperInvariant();
            var name = string.IsNullOrWhiteSpace(request?.Name) ? "@" : request.Name.Trim();
            var value = (request?.Value ?? "").Trim();
            var ttl = Math.Max(300, Math.Min(86400, request?.Ttl ?? 300));
            var priority = Math.Max(0, Math.Min(100, request?.Priority ?? 10));
            var weight = Math.Max(0, Math.Min(100, request?.Weight ?? 1));
            var port = Math.Max(1, Math.Min(65535, request?.Port ?? 443));

            return type switch
            {
                "MX" => $"MX {name} {value} {priority} {ttl}",
                "SRV" => $"SRV {name} {value} {priority} {weight} {port} {ttl}",
                "TXT" => $"TXT {name} {value}",
                _ => $"{type} {name} {value} {ttl}"
            };
        }

        private static async Task<DomainProfileDetail?> LoadDomainProfileAsync(SqlConnection connection, long customerId, int domainId)
        {
            const string sql = @"
SELECT TOP 1
       dp.id, dp.domain_name, dp.RegisterInfoID, dp.RegisterStatus, dp.StartDate, dp.BuyYear,
       CASE WHEN privacyTld.tld IS NULL THEN 0 ELSE 1 END AS whois_privacy_supported,
       CASE WHEN privacy.client_product_id IS NULL THEN 0 ELSE 1 END AS whois_privacy_purchased,
       privacy.turnOnDate,
       ISNULL(grace.graceperiod, 0) AS grace_period_days,
       dr.firstname, dr.lastname, dr.organization, dr.email, dr.phone, dr.fax, dr.street, dr.street1, dr.city, dr.state, dr.province, dr.country, dr.zip,
       dr.firstnamea, dr.lastnamea, dr.organizationa, dr.emaila, dr.phonea, dr.faxa, dr.streeta, dr.street1a, dr.citya, dr.statea, dr.provincea, dr.countrya, dr.zipa,
       dr.firstnameb, dr.lastnameb, dr.organizationb, dr.emailb, dr.phoneb, dr.faxb, dr.streetb, dr.street1b, dr.cityb, dr.stateb, dr.provinceb, dr.countryb, dr.zipb,
       dr.firstnamet, dr.lastnamet, dr.organizationt, dr.emailt, dr.phonet, dr.faxt, dr.streett, dr.street1t, dr.cityt, dr.statet, dr.provincet, dr.countryt, dr.zipt
FROM domaincontroller.dbo.domain_profile dp
INNER JOIN domaincontroller.dbo.DomainRegisterInfo dr ON dr.id = dp.RegisterInfoID
OUTER APPLY (
    SELECT TOP 1 tld
    FROM domaincontroller.dbo.domain_privacy_tld
    WHERE SUBSTRING(dp.domain_name, CHARINDEX('.', dp.domain_name), LEN(dp.domain_name)) = tld
) privacyTld
OUTER APPLY (
    SELECT TOP 1 p.client_product_id, p.turnOnDate
    FROM domaincontroller.dbo.domain_privacy p
    INNER JOIN oms.dbo.client_product privacyCp ON privacyCp.client_product_id = p.client_product_id
    WHERE LOWER(p.domain) = LOWER(dp.domain_name)
      AND privacyCp.status = 1
) privacy
OUTER APPLY (
    SELECT TOP 1 graceperiod
    FROM domaincontroller.dbo.domain_graceperiod_tld
    WHERE SUBSTRING(dp.domain_name, CHARINDEX('.', dp.domain_name), LEN(dp.domain_name)) = tld
) grace
WHERE dp.id = @domainId
  AND dp.customer_profile_id = @customerId
  AND dr.sponsorid = @customerId";

            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@domainId", domainId);
            command.Parameters.AddWithValue("@customerId", customerId);

            await using var reader = await command.ExecuteReaderAsync();
            if (!await reader.ReadAsync())
            {
                return null;
            }

            string Field(int index) => reader.IsDBNull(index) ? "" : Convert.ToString(reader.GetValue(index))?.Trim() ?? "";
            DomainContactDetail Contact(int offset) => new(
                Field(offset),
                Field(offset + 1),
                Field(offset + 2),
                Field(offset + 3),
                Field(offset + 4),
                Field(offset + 5),
                Field(offset + 6),
                Field(offset + 7),
                Field(offset + 8),
                Field(offset + 9),
                Field(offset + 10),
                Field(offset + 11),
                Field(offset + 12)
            );

            var startDate = reader.IsDBNull(4) ? (DateOnly?)null : DateOnly.FromDateTime(reader.GetDateTime(4));
            var buyYear = reader.IsDBNull(5) ? 1 : reader.GetInt32(5);
            var expirationDate = CalculateDomainExpiration(startDate, buyYear);
            var daysLeft = expirationDate == null ? (int?)null : expirationDate.Value.DayNumber - DateOnly.FromDateTime(DateTime.UtcNow).DayNumber;

            return new DomainProfileDetail(
                reader.GetInt32(0),
                Field(1),
                reader.IsDBNull(2) ? 0 : reader.GetInt32(2),
                Field(3),
                expirationDate,
                daysLeft,
                ReadBoolean(reader, 6),
                ReadBoolean(reader, 7),
                reader.IsDBNull(8) ? null : DateOnly.FromDateTime(reader.GetDateTime(8)),
                ReadInt32(reader, 9),
                Contact(10),
                Contact(23),
                Contact(36),
                Contact(49)
            );
        }

        private async Task<GithubDeployStatus> LoadGithubDeployStatusAsync(SqlConnection connection, OwnedHostingSite site)
        {
            var token = await LoadGithubTokenRowAsync(connection, site.CpId);
            if (!string.IsNullOrWhiteSpace(token.AccessToken) &&
                token.ExpiresAt != null &&
                token.ExpiresAt.Value <= DateTime.Now.AddMinutes(5) &&
                !string.IsNullOrWhiteSpace(token.RefreshToken))
            {
                var refreshToken = await TryLegacyDecryptImportKey2Async(token.RefreshToken);
                if (string.IsNullOrWhiteSpace(refreshToken))
                {
                    refreshToken = token.RefreshToken;
                }

                var refreshed = await RefreshGithubTokensAsync(refreshToken);
                if (refreshed.Success)
                {
                    await SaveGithubTokensAsync(connection, site.CpId, refreshed.AccessToken, refreshed.RefreshToken, refreshed.ExpiresAt);
                    token = await LoadGithubTokenRowAsync(connection, site.CpId);
                }
            }

            var hook = await LoadGithubDeployHookAsync(connection, site.SiteUid);
            var deployments = await LoadGithubDeploymentsAsync(connection, site);
            var environmentSettings = await LoadGithubEnvironmentSettingsAsync(connection, site);
            var repositories = new List<GithubRepositoryRow>();
            if (!string.IsNullOrWhiteSpace(token.AccessToken))
            {
                var accessToken = await TryLegacyDecryptImportKey2Async(token.AccessToken);
                if (string.IsNullOrWhiteSpace(accessToken))
                {
                    accessToken = token.AccessToken;
                }

                repositories = await ListGithubRepositoriesAsync(accessToken);
            }

            var hookUrl = "";
            if (hook.WorkqueueId > 0)
            {
                var encryptedJobId = await TryLegacyImportKey2EncryptAsync(hook.WorkqueueId.ToString(CultureInfo.InvariantCulture));
                if (!string.IsNullOrWhiteSpace(encryptedJobId))
                {
                    hookUrl = $"{GetGithubDeployHookBaseUrl()}/github/deployhook?jobid={Uri.EscapeDataString(encryptedJobId)}";
                }
            }

            return new GithubDeployStatus(
                site.CpId,
                site.SiteUid,
                !string.IsNullOrWhiteSpace(token.AccessToken),
                !string.IsNullOrWhiteSpace(token.InstallationId),
                token.ExpiresAt,
                token.InstallationId,
                hook.WorkqueueId > 0,
                hook.WorkqueueId,
                hookUrl,
                hook.LastUpdate,
                deployments,
                repositories,
                environmentSettings);
        }

        private static async Task<List<GithubRepositoryRow>> ListGithubRepositoriesAsync(string accessToken)
        {
            var repositories = new List<GithubRepositoryRow>();
            if (string.IsNullOrWhiteSpace(accessToken))
            {
                return repositories;
            }

            try
            {
                using var http = new HttpClient();
                using var request = new HttpRequestMessage(HttpMethod.Get, "https://api.github.com/user/repos?per_page=100&type=all");
                request.Headers.Authorization = new AuthenticationHeaderValue("Bearer", accessToken);
                request.Headers.Accept.Add(new MediaTypeWithQualityHeaderValue("application/vnd.github+json"));
                request.Headers.UserAgent.ParseAdd("SmarterASP-ControlPanel/1.0");
                using var response = await http.SendAsync(request);
                if (!response.IsSuccessStatusCode)
                {
                    return repositories;
                }

                var json = await response.Content.ReadAsStringAsync();
                using var document = JsonDocument.Parse(json);
                if (document.RootElement.ValueKind != JsonValueKind.Array)
                {
                    return repositories;
                }

                foreach (var repo in document.RootElement.EnumerateArray())
                {
                    var fullName = JsonStringProperty(repo, "full_name");
                    var cloneUrl = JsonStringProperty(repo, "clone_url");
                    if (string.IsNullOrWhiteSpace(fullName) || string.IsNullOrWhiteSpace(cloneUrl))
                    {
                        continue;
                    }

                    repositories.Add(new GithubRepositoryRow(
                        JsonStringProperty(repo, "name"),
                        fullName,
                        cloneUrl,
                        JsonBoolProperty(repo, "private", false)));
                }
            }
            catch
            {
                return repositories;
            }

            return repositories
                .OrderBy(repository => repository.FullName, StringComparer.OrdinalIgnoreCase)
                .ToList();
        }

        private async Task<GithubTokenExchangeResult> RefreshGithubTokensAsync(string refreshToken)
        {
            var settings = GetGithubSettings(new DefaultHttpContext());
            if (!settings.IsConfigured || string.IsNullOrWhiteSpace(refreshToken))
            {
                return new GithubTokenExchangeResult(false, "GitHub OAuth refresh is not configured.", "", "", null);
            }

            try
            {
                using var httpClient = new HttpClient { Timeout = TimeSpan.FromSeconds(20) };
                var tokenFields = new Dictionary<string, string>
                {
                    ["client_id"] = settings.ClientId,
                    ["client_secret"] = settings.ClientSecret,
                    ["grant_type"] = "refresh_token",
                    ["refresh_token"] = refreshToken
                };

                using var request = new HttpRequestMessage(HttpMethod.Post, "https://github.com/login/oauth/access_token")
                {
                    Content = new FormUrlEncodedContent(tokenFields)
                };
                request.Headers.Accept.Add(new MediaTypeWithQualityHeaderValue("application/json"));
                request.Headers.UserAgent.ParseAdd("SmarterASP-ControlPanel/1.0");

                var response = await httpClient.SendAsync(request);
                var json = await response.Content.ReadAsStringAsync();
                if (!response.IsSuccessStatusCode)
                {
                    return new GithubTokenExchangeResult(false, $"GitHub token refresh failed: {Preview(json)}", "", "", null);
                }

                using var document = JsonDocument.Parse(json);
                var root = document.RootElement;
                var accessToken = root.TryGetProperty("access_token", out var accessTokenElement) ? accessTokenElement.GetString() ?? "" : "";
                var newRefreshToken = root.TryGetProperty("refresh_token", out var refreshTokenElement) ? refreshTokenElement.GetString() ?? "" : "";
                var expiresIn = root.TryGetProperty("expires_in", out var expiresInElement) && expiresInElement.TryGetInt32(out var seconds)
                    ? seconds
                    : 28800;
                if (string.IsNullOrWhiteSpace(accessToken))
                {
                    return new GithubTokenExchangeResult(false, "GitHub did not return a refreshed access token.", "", "", null);
                }

                return new GithubTokenExchangeResult(true, "GitHub token refresh completed.", accessToken, newRefreshToken, DateTime.Now.AddSeconds(expiresIn));
            }
            catch (Exception ex)
            {
                return new GithubTokenExchangeResult(false, $"GitHub token refresh failed: {ex.Message}", "", "", null);
            }
        }

        private static async Task<List<GithubDeploymentRow>> LoadGithubDeploymentsAsync(SqlConnection connection, OwnedHostingSite site)
        {
            var rows = new List<GithubDeploymentRow>();
            const string sql = @"
SELECT TOP 3 id, zipfile, enterdate, status
FROM dbo.workqueue
WHERE cplogin = @cpLogin
  AND siteowner = @siteName
  AND type = 'deploy'
  AND enterdate > DATEADD(DAY, -90, GETDATE())
ORDER BY enterdate DESC";
            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@cpLogin", site.CpLogin);
            command.Parameters.AddWithValue("@siteName", site.SiteName);
            await using var reader = await command.ExecuteReaderAsync();
            while (await reader.ReadAsync())
            {
                rows.Add(new GithubDeploymentRow(
                    reader.IsDBNull(0) ? 0 : Convert.ToInt64(reader.GetValue(0), CultureInfo.InvariantCulture),
                    reader.IsDBNull(1) ? "" : Convert.ToString(reader.GetValue(1), CultureInfo.InvariantCulture) ?? "",
                    reader.IsDBNull(2) ? null : reader.GetDateTime(2),
                    reader.IsDBNull(3) ? 0 : Convert.ToInt32(reader.GetValue(3), CultureInfo.InvariantCulture)));
            }

            return rows;
        }

