        private static async Task<GithubDeployHookJob> RequeueGithubDeployHookAsync(SqlConnection connection, long workqueueId)
        {
            const string pendingSql = @"
SELECT COUNT(*)
FROM dbo.workqueue
WHERE status <> 2 AND status <> 3 AND type = 'deploy' AND id = @workqueueId";
            await using (var pendingCommand = new SqlCommand(pendingSql, connection))
            {
                pendingCommand.Parameters.AddWithValue("@workqueueId", workqueueId);
                var pending = Convert.ToInt32(await pendingCommand.ExecuteScalarAsync(), CultureInfo.InvariantCulture);
                if (pending > 0)
                {
                    return new GithubDeployHookJob("Error, there is a existing task in the queue. Please wait a bit and try again.", "ERROR", DateTime.Now.ToString(CultureInfo.InvariantCulture));
                }
            }

            const string sql = "UPDATE dbo.workqueue SET status = 0, enterdate = GETDATE() WHERE id = @workqueueId";
            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@workqueueId", workqueueId);
            await command.ExecuteNonQueryAsync();
            return new GithubDeployHookJob(workqueueId.ToString(CultureInfo.InvariantCulture), "PENDING", DateTime.Now.ToString(CultureInfo.InvariantCulture));
        }

        private async Task<long> TryDecryptGithubDeployHookJobIdAsync(string encryptedJobId)
        {
            if (string.IsNullOrWhiteSpace(encryptedJobId))
            {
                return 0;
            }

            if (long.TryParse(encryptedJobId, NumberStyles.Integer, CultureInfo.InvariantCulture, out var plainJobId))
            {
                return plainJobId;
            }

            var decrypted = await TryLegacyDecryptImportKey2Async(encryptedJobId);
            return long.TryParse(decrypted, NumberStyles.Integer, CultureInfo.InvariantCulture, out var jobId) ? jobId : 0;
        }

        private string GetGithubDeployHookBaseUrl()
        {
            var configured = ConfigOrEnv("Github:DeployHookBaseUrl", "GITHUB_DEPLOYHOOK_BASE_URL").Trim().TrimEnd('/');
            if (!string.IsNullOrWhiteSpace(configured))
            {
                return configured;
            }

            var publicUrl = ConfigOrEnv("PublicApp:BaseUrl", "PUBLIC_APP_BASE_URL", "http://localhost:5056").Trim().TrimEnd('/');
            return string.IsNullOrWhiteSpace(publicUrl) ? "http://localhost:5056" : publicUrl;
        }

        private static async Task WriteGithubPopupHtmlAsync(HttpContext context, string title, string message, bool closeWindow)
        {
            context.Response.ContentType = "text/html; charset=utf-8";
            var safeTitle = WebUtility.HtmlEncode(title);
            var safeMessage = WebUtility.HtmlEncode(message);
            var returnUrl = NormalizeLocalReturnUrl(context.Session.GetString("github_return_url") ?? "") ?? "/panel_cp?section=websites";
            var safeReturnUrl = JsonSerializer.Serialize(returnUrl);
            var closeScript = closeWindow
                ? $"setTimeout(function(){{ if (window.opener) {{ window.close(); }} else {{ window.location.href = {safeReturnUrl}; }} }}, 900);"
                : $"setTimeout(function(){{ window.location.href = {safeReturnUrl}; }}, 900);";
            await context.Response.WriteAsync($@"<!doctype html>
<html>
<head>
  <meta charset=""utf-8"" />
  <title>{safeTitle}</title>
  <style>
    body {{ margin: 0; min-height: 100vh; display: grid; place-items: center; background: #050505; color: #ededed; font: 14px/1.5 -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }}
    main {{ width: min(460px, calc(100vw - 40px)); border: 1px solid #242424; border-radius: 12px; padding: 28px; background: #111; box-shadow: 0 24px 70px rgba(0,0,0,.35); }}
    h1 {{ margin: 0 0 8px; font-size: 22px; }}
    p {{ margin: 0; color: #a1a1aa; }}
  </style>
</head>
<body>
  <main>
    <h1>{safeTitle}</h1>
    <p>{safeMessage}</p>
  </main>
  <script>
    if (window.opener) {{
      try {{ window.opener.postMessage({{ type: 'github-auth-complete' }}, window.location.origin); }} catch (error) {{}}
    }}
    {closeScript}
  </script>
</body>
</html>");
        }

        private static string? NormalizeLocalReturnUrl(string value)
        {
            var trimmed = (value ?? "").Trim();
            if (string.IsNullOrWhiteSpace(trimmed))
            {
                return null;
            }

            if (!trimmed.StartsWith("/", StringComparison.Ordinal) || trimmed.StartsWith("//", StringComparison.Ordinal) || trimmed.Contains("\\", StringComparison.Ordinal))
            {
                return null;
            }

            return trimmed;
        }

        private static DateOnly? CalculateDomainExpiration(DateOnly? startDate, int buyYear)
        {
            if (startDate == null)
            {
                return null;
            }

            return startDate.Value.AddYears(Math.Max(buyYear, 1));
        }

        private static async Task<OwnedHostingSite?> LoadOwnedHostingSiteAsync(SqlConnection connection, long customerId, long requestedCpId, int siteUid)
        {
            const string sql = @"
SELECT TOP 1 cp.cpID, cp.cpLogin, cp.ServerID, cp.WebHostType,
       s.site_Uid, s.site_name, s.Display_name, s.site_path, s.iis_id, s.pool_id,
       s.iis_status, s.running_status, s.version, s.phpversion, s.is_secure, s.isSubdomain, s.create_date,
       ISNULL(s.detailerror, 0) AS detailerror
FROM dbo.cp_config cp
INNER JOIN dbo.cp_config_Sites s ON s.cpID = cp.cpID
WHERE cp.customerID = @customerId
  AND ISNULL(cp.hideit, 0) = 0
  AND cp.status <> 3
  AND s.site_Uid = @siteUid
  AND (@requestedCpId = 0 OR cp.cpID = @requestedCpId)";

            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@customerId", customerId);
            command.Parameters.AddWithValue("@requestedCpId", requestedCpId);
            command.Parameters.AddWithValue("@siteUid", siteUid);

            await using var reader = await command.ExecuteReaderAsync();
            if (!await reader.ReadAsync())
            {
                return null;
            }

            return new OwnedHostingSite(
                reader.GetInt64(0),
                reader.GetString(1).Trim(),
                reader.IsDBNull(2) ? "" : reader.GetString(2).Trim(),
                reader.IsDBNull(3) ? "" : reader.GetString(3).Trim(),
                reader.GetInt32(4),
                reader.GetString(5).Trim(),
                reader.IsDBNull(6) ? "" : reader.GetString(6).Trim(),
                reader.IsDBNull(7) ? "" : reader.GetString(7).Trim(),
                reader.IsDBNull(8) ? "" : Convert.ToString(reader.GetValue(8), CultureInfo.InvariantCulture) ?? "",
                reader.IsDBNull(9) ? "" : Convert.ToString(reader.GetValue(9), CultureInfo.InvariantCulture) ?? "",
                !reader.IsDBNull(10) && reader.GetBoolean(10),
                reader.IsDBNull(11) ? "" : reader.GetString(11).Trim(),
                reader.IsDBNull(12) ? "" : reader.GetString(12).Trim(),
                reader.IsDBNull(13) ? "" : reader.GetString(13).Trim(),
                !reader.IsDBNull(14) && reader.GetBoolean(14),
                !reader.IsDBNull(15) && reader.GetBoolean(15),
                reader.IsDBNull(16) ? null : reader.GetDateTime(16),
                !reader.IsDBNull(17) && Convert.ToBoolean(reader.GetValue(17), CultureInfo.InvariantCulture)
            );
        }

        private static async Task<List<OwnedHostingSite>> LoadOwnedHostingSitesForCpAsync(SqlConnection connection, long cpId)
        {
            const string sql = @"
SELECT cp.cpID, cp.cpLogin, cp.ServerID, cp.WebHostType,
       s.site_Uid, s.site_name, s.Display_name, s.site_path, s.iis_id, s.pool_id,
       s.iis_status, s.running_status, s.version, s.phpversion, s.is_secure, s.isSubdomain, s.create_date,
       ISNULL(s.detailerror, 0) AS detailerror
FROM dbo.cp_config cp
INNER JOIN dbo.cp_config_Sites s ON s.cpID = cp.cpID
WHERE cp.cpID = @cpId
  AND ISNULL(cp.hideit, 0) = 0
  AND cp.status <> 3
ORDER BY s.site_Uid";

            var sites = new List<OwnedHostingSite>();
            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@cpId", cpId);

            await using var reader = await command.ExecuteReaderAsync();
            while (await reader.ReadAsync())
            {
                sites.Add(new OwnedHostingSite(
                    reader.GetInt64(0),
                    reader.GetString(1).Trim(),
                    reader.IsDBNull(2) ? "" : reader.GetString(2).Trim(),
                    reader.IsDBNull(3) ? "" : reader.GetString(3).Trim(),
                    reader.GetInt32(4),
                    reader.GetString(5).Trim(),
                    reader.IsDBNull(6) ? "" : reader.GetString(6).Trim(),
                    reader.IsDBNull(7) ? "" : reader.GetString(7).Trim(),
                    reader.IsDBNull(8) ? "" : Convert.ToString(reader.GetValue(8), CultureInfo.InvariantCulture) ?? "",
                    reader.IsDBNull(9) ? "" : Convert.ToString(reader.GetValue(9), CultureInfo.InvariantCulture) ?? "",
                    !reader.IsDBNull(10) && reader.GetBoolean(10),
                    reader.IsDBNull(11) ? "" : reader.GetString(11).Trim(),
                    reader.IsDBNull(12) ? "" : reader.GetString(12).Trim(),
                    reader.IsDBNull(13) ? "" : reader.GetString(13).Trim(),
                    !reader.IsDBNull(14) && reader.GetBoolean(14),
                    !reader.IsDBNull(15) && reader.GetBoolean(15),
                    reader.IsDBNull(16) ? null : reader.GetDateTime(16),
                    !reader.IsDBNull(17) && Convert.ToBoolean(reader.GetValue(17), CultureInfo.InvariantCulture)
                ));
            }

            return sites;
        }

        private async Task<HostingSiteFunctionDetails> BuildHostingSiteFunctionDetailsAsync(SqlConnection connection, OwnedHostingSite site, string functionKey)
        {
            var normalizedKey = NormalizeWebsiteFunctionKey(functionKey);
            var spec = GetWebsiteFunctionSpec(normalizedKey);
            var warnings = new List<string>();
            var siteSummary = new Dictionary<string, object?>
            {
                ["cpId"] = site.CpId,
                ["cpLogin"] = site.CpLogin,
                ["serverId"] = site.ServerId,
                ["webHostType"] = site.WebHostType,
                ["siteUid"] = site.SiteUid,
                ["siteName"] = DisplaySiteName(site),
                ["rootName"] = site.SiteName,
                ["iisId"] = site.IisId,
                ["poolId"] = site.PoolId,
                ["sitePath"] = site.SitePath,
                ["status"] = site.IisStatus ? "Active" : "Stopped",
                ["runningStatus"] = site.RunningStatus,
                ["version"] = site.Version,
                ["phpVersion"] = site.PhpVersion,
                ["isSecure"] = site.IsSecure,
                ["isSubdomain"] = site.IsSubdomain,
                ["detailError"] = site.DetailError,
                ["createDate"] = site.CreateDate
            };

            var domains = await TryLoadFunctionRowsAsync(
                connection,
                warnings,
                "mapped domains",
                @"
SELECT domain_Uid, domain_name, ISNULL(cdn, 0) AS cdn, ISNULL(isDefault, 0) AS isDefault, create_date
FROM dbo.cp_config_Domains
WHERE site_Uid = @siteUid
ORDER BY ISNULL(isDefault, 0) DESC, domain_name",
                command => command.Parameters.AddWithValue("@siteUid", site.SiteUid));

            var workqueue = await TryLoadFunctionRowsAsync(
                connection,
                warnings,
                "recent worker jobs",
                @"
SELECT TOP 12 id, type, ISNULL(status, 0) AS status, zipfile, dstfolder, serverid, data1, Enterdate, siteowner, notifyemail, errormessage
FROM dbo.workqueue
WHERE cplogin = @cpLogin
  AND (siteowner = @siteName OR zipfile LIKE @siteNeedle OR dstfolder LIKE @siteNeedle OR data1 LIKE @siteNeedle)
ORDER BY id DESC",
                command =>
                {
                    command.Parameters.AddWithValue("@cpLogin", site.CpLogin);
                    command.Parameters.AddWithValue("@siteName", site.SiteName);
                    command.Parameters.AddWithValue("@siteNeedle", $"%{site.SiteName}%");
                });

            var functionData = new Dictionary<string, object?>
            {
                ["site"] = siteSummary,
                ["domains"] = domains,
                ["recentJobs"] = workqueue
            };

            if (normalizedKey is "application-pool" or "mapped-path" or "aspnet-version" or "core-mode" or "php-version" or "php-settings" or "detail-error" or "force-https" or "remote-iis-manager" or "site-guard")
            {
                functionData["runtime"] = await TryLoadFunctionRowsAsync(
                    connection,
                    warnings,
                    "runtime rows",
                    @"
SELECT TOP 50 'Pool' AS row_type, CAST(pool_id AS varchar(30)) AS id, CAST(privateMemory AS varchar(30)) + ' MB' AS title, pool_version AS status, '' AS servername, create_date AS created
FROM dbo.cp_config_Pools
WHERE cpID = @cpId
UNION ALL
SELECT TOP 50 'Redirect' AS row_type, CAST(r.id AS varchar(30)) AS id, r.domain AS title, r.destination AS status, r.rulename AS servername, NULL AS created
FROM dbo.cp_config_redirect r
INNER JOIN dbo.cp_config_Sites s ON s.site_Uid = r.site_uid
WHERE s.cpID = @cpId
ORDER BY row_type, title",
                    command => command.Parameters.AddWithValue("@cpId", site.CpId));
            }

            if (normalizedKey == "detail-error")
            {
                functionData["detailError"] = new Dictionary<string, object?>
                {
                    ["enabled"] = site.DetailError,
                    ["status"] = site.DetailError ? "ON" : "OFF",
                    ["appPath"] = "/",
                    ["notice"] = "Displays detailed diagnostic messages instead of a generic error page. When enabled, .NET Core and Node.js application logs are saved to the /logs folder at your site root.",
                    ["legacySource"] = "/Users/erwinyu/Downloads/hosting/cp8/cp/boxinfo_detailerror.asp"
                };
            }

            if (normalizedKey == "nodejs-app")
            {
                functionData["nodejs"] = new Dictionary<string, object?>
                {
                    ["status"] = site.Version.Contains("node", StringComparison.OrdinalIgnoreCase) ? "ON" : "OFF",
                    ["startupFile"] = "",
                    ["preferredMode"] = "httpPlatformHandler"
                };
            }

            if (normalizedKey is "ftp-access" or "vs-webdeploy" or "remote-iis-manager" or "visitor-stats")
            {
                functionData["ftpUsers"] = await TryLoadFunctionRowsAsync(
                    connection,
                    warnings,
                    "FTP users",
                    @"
SELECT TOP 50 ftp_login, ftp_path, ftp_quota, ftp_permission, cpurl
FROM dbo.cp_config_FTP
WHERE cpID = @cpId
ORDER BY ftp_login",
                    command => command.Parameters.AddWithValue("@cpId", site.CpId));
            }

            if (normalizedKey == "visitor-stats")
            {
                var statsRows = await TryLoadFunctionRowsAsync(
                    connection,
                    warnings,
                    "visitor stats",
                    @"
SELECT TOP 1 ISNULL(Stats_enabled, 0) AS stats_enabled, ISNULL(Stats_mainDomain, '') AS stats_domain
FROM dbo.cp_config_Sites
WHERE site_Uid = @siteUid AND cpID = @cpId",
                    command =>
                    {
                        command.Parameters.AddWithValue("@siteUid", site.SiteUid);
                        command.Parameters.AddWithValue("@cpId", site.CpId);
                    });
                var formattedIisId = FormatIisId(site.IisId);
                var hash = HashHex(MD5.HashData(Encoding.UTF8.GetBytes($"abcde12345{site.CpId}{formattedIisId}")));
                functionData["visitorStats"] = new Dictionary<string, object?>
                {
                    ["rows"] = statsRows,
                    ["available"] = !site.IsSubdomain,
                    ["statsUrl"] = $"https://{site.ServerId}.site4now.net/stats/awstats.pl?config={site.CpId}{formattedIisId}&h={hash}",
                    ["login"] = site.CpLogin,
                    ["notice"] = "Stats take about 24 hours before the first update."
                };
            }

            if (normalizedKey == "iis-log-manager")
            {
                var w3svcId = $"{site.CpId}{FormatIisId(site.IisId)}";
                var primaryDomain = domains
                    .Select(row => row.TryGetValue("domain_name", out var value) ? Convert.ToString(value, CultureInfo.InvariantCulture)?.Trim() ?? "" : "")
                    .FirstOrDefault(value => !string.IsNullOrWhiteSpace(value) && !IsTemporaryHostingDomain(value))
                    ?? domains.Select(row => row.TryGetValue("domain_name", out var value) ? Convert.ToString(value, CultureInfo.InvariantCulture)?.Trim() ?? "" : "").FirstOrDefault(value => !string.IsNullOrWhiteSpace(value))
                    ?? "";
                functionData["iisLogs"] = new Dictionary<string, object?>
                {
                    ["w3svcId"] = w3svcId,
                    ["source"] = $@"c:\logfiles\W3SVC{w3svcId}\*.log",
                    ["destination"] = $@"/www/db/{w3svcId}",
                    ["primaryDomain"] = primaryDomain,
                    ["note"] = "Classic download copies raw logs into the hosting account /db folder."
                };
            }

            if (normalizedKey == "ip-deny")
            {
                var customerId = await LoadCustomerIdForCpAsync(connection, site.CpId);
                var denyListCall = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/iis_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "get_ipSecurity_deny_list",
                    ["IIS_ID"] = FullIisId(site)
                }, customerId);
                var dynamicCall = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/iis_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "Get_Dynamic_IP_Restrict",
                    ["IIS_ID"] = FullIisId(site)
                }, customerId);
                functionData["ipDeny"] = new Dictionary<string, object?>
                {
                    ["denyList"] = ParseIpDenyList(denyListCall.Body),
                    ["dynamic"] = ParseDynamicIpRestriction(dynamicCall.Body),
                    ["denyListStatus"] = denyListCall.Success ? "Loaded" : denyListCall.Message,
                    ["dynamicStatus"] = dynamicCall.Success ? "Loaded" : dynamicCall.Message
                };
                if (!denyListCall.Success) warnings.Add(denyListCall.Message);
                if (!dynamicCall.Success) warnings.Add(dynamicCall.Message);
            }

            if (normalizedKey is "vs-webdeploy" or "remote-iis-manager")
            {
                var siteFullName = $"{site.CpLogin}-{site.SiteName}";
                var webDeployUser = normalizedKey == "remote-iis-manager"
                    ? $"ifc\\{site.CpLogin}"
                    : site.CpLogin;
                var serviceHost = BuildLegacyHost(GetLegacyAgentSettings(), site.ServerId);
                var checkCall = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "CheckIISManagerUser",
                    ["sitename"] = siteFullName,
                    ["user"] = webDeployUser
                });

                var isEnabled = checkCall.Success && checkCall.Preview.Trim().Equals("1", StringComparison.OrdinalIgnoreCase);
                functionData["webDeploy"] = new Dictionary<string, object?>
                {
                    ["enabled"] = isEnabled,
                    ["status"] = isEnabled ? "On" : "Off",
                    ["serviceUrl"] = $"https://{serviceHost}:8172/MsDeploy.axd?site={siteFullName}",
                    ["serverName"] = serviceHost,
                    ["siteName"] = siteFullName,
                    ["username"] = webDeployUser,
                    ["password"] = "Stored securely",
                    ["publishSettings"] = "Server-side generation pending legacy password decrypt compatibility",
                    ["classicCheckResponse"] = checkCall.Preview
                };

                if (!checkCall.Success)
                {
                    warnings.Add(checkCall.Message);
                }

            }

            if (normalizedKey is "site-guard" or "force-https" or "ip-deny" or "cdn" or "domain-manager")
            {
                functionData["security"] = await TryLoadFunctionRowsAsync(
                    connection,
                    warnings,
                    "security settings",
                    @"
SELECT TOP 25 s.site_Uid, s.site_name, s.webknight, d.domain_name, d.cdn, d.isDefault
FROM dbo.cp_config_Sites s
LEFT JOIN dbo.cp_config_Domains d ON d.site_Uid = s.site_Uid
WHERE s.site_Uid = @siteUid",
                    command => command.Parameters.AddWithValue("@siteUid", site.SiteUid));
            }

            if (normalizedKey is "default-doc" or "custom-errors" or "mime-type" or "script-map")
            {
                var appPath = "/";
                var readForm = normalizedKey switch
                {
                    "default-doc" => new Dictionary<string, string>
                    {
                        ["action"] = "IIS_Member_DefaultPage_Get",
                        ["IIS_ID"] = FullIisId(site)
                    },
                    "custom-errors" => new Dictionary<string, string>
                    {
                        ["action"] = "IIS_Member_ErrorPage_Get",
                        ["IIS_ID"] = FullIisId(site)
                    },
                    "mime-type" => new Dictionary<string, string>
                    {
                        ["action"] = "get_mimeMap",
                        ["IIS_ID"] = FullIisId(site),
                        ["apppath"] = appPath
                    },
                    "script-map" => new Dictionary<string, string>
                    {
                        ["action"] = "IIS_Member_IISEntry_CustomScriptMap_Get",
                        ["IIS_ID"] = FullIisId(site)
                    },
                    _ => new Dictionary<string, string>()
                };

                var readCall = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", readForm);
                functionData["iisCurrent"] = new Dictionary<string, object?>
                {
                    ["success"] = readCall.Success,
                    ["action"] = readForm.TryGetValue("action", out var readAction) ? readAction : "",
                    ["appPath"] = appPath,
                    ["preview"] = readCall.Preview,
                    ["body"] = readCall.Body,
                    ["url"] = readCall.Url
                };

                if (normalizedKey == "default-doc")
                {
                    functionData["defaultDocs"] = FormatDefaultDocsForTextarea(readCall.Body);
                }

                if (normalizedKey == "mime-type")
                {
                    functionData["mimeMaps"] = ParseMimeMaps(readCall.Body);
                }

                if (normalizedKey == "script-map")
                {
                    functionData["scriptMaps"] = ParseScriptMaps(readCall.Body);
                }

                if (normalizedKey == "custom-errors")
                {
                    functionData["errorPages"] = ParseIisErrorPages(readCall.Body);
                }

                if (!readCall.Success)
                {
                    warnings.Add(readCall.Message);
                }
            }

            if (normalizedKey is "create-net-app" or "virtual-dir")
            {
                var customerId = await LoadCustomerIdForCpAsync(connection, site.CpId);
                var appListCall = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "IIS_Member_Apps_List_Get",
                    ["IIS_ID"] = FullIisId(site)
                }, customerId);
                functionData["iisApps"] = ParseIisAppList(appListCall.Body);
                if (!appListCall.Success)
                {
                    warnings.Add(appListCall.Message);
                }

                if (normalizedKey == "virtual-dir")
                {
                    var vdListCall = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                    {
                        ["action"] = "IIS_Member_VD_List_Get",
                        ["IIS_ID"] = FullIisId(site)
                    }, customerId);
                    functionData["virtualDirs"] = ParseIisVirtualDirs(vdListCall.Body, site.CpLogin);
                    if (!vdListCall.Success)
                    {
                        warnings.Add(vdListCall.Message);
                    }
                }
            }

            if (normalizedKey is "schedule-tasks")
            {
                var scheduleConnectionString = GetScheduleTaskConnectionString();
                if (string.IsNullOrWhiteSpace(scheduleConnectionString))
                {
                    warnings.Add("Scheduled tasks need SCHEDULE_TASK_CONNECTION_STRING before this drawer can read task rows.");
                    functionData["scheduledTasks"] = new List<Dictionary<string, object?>>();
                }
                else
                {
                    try
                    {
                        await using var scheduleConnection = new SqlConnection(scheduleConnectionString);
                        await scheduleConnection.OpenAsync();
                        functionData["scheduledTasks"] = await TryLoadFunctionRowsAsync(
                            scheduleConnection,
                            warnings,
                            "scheduled tasks",
                            @"
SELECT id, cpid, enterdate, url, everynummin, lastrun, laststatus, timeout, certaintime, certainday, certainmin, ISNULL(wintask, 0) AS wintask
FROM dbo.tasks
WHERE cpid = @cpId
ORDER BY ISNULL(wintask, 0), id DESC",
                            command => command.Parameters.AddWithValue("@cpId", site.CpId));
                    }
                    catch (SqlException ex)
                    {
                        warnings.Add($"Unable to open scheduled-task database: {ex.Message}");
                        functionData["scheduledTasks"] = new List<Dictionary<string, object?>>();
                    }
                }

                var taskQuota = await LoadScheduleTaskQuotaAsync(connection, site.CpId);
                var windowsTaskQuota = await LoadAddonQuotaAsync(connection, site.CpId, "AdditionalMassSMTP");
                functionData["scheduledTaskQuota"] = new Dictionary<string, object?>
                {
                    ["scheduleTaskQuota"] = taskQuota,
                    ["windowsTaskQuota"] = windowsTaskQuota
                };
            }

            if (normalizedKey is "outgoing-port")
            {
                functionData["outgoingPorts"] = await TryLoadFunctionRowsAsync(
                    connection,
                    warnings,
                    "outgoing port rules",
                    @"
SELECT TOP 100 ipid, remoteip, port, adddate, rulename
FROM dbo.cp_config_db_out_ip
WHERE cpID = @cpId
ORDER BY adddate DESC, ipid DESC",
                    command => command.Parameters.AddWithValue("@cpId", site.CpId));
            }

            functionData["agent"] = new Dictionary<string, object?>
            {
                ["host"] = BuildLegacyHost(GetLegacyAgentSettings(), site.ServerId),
                ["port"] = GetLegacyAgentSettings().Port,
                ["usesRemoteAgent"] = spec.UsesRemoteAgent
            };

            return new HostingSiteFunctionDetails(
                normalizedKey,
                spec.Label,
                spec.Group,
                spec.LegacyEntry,
                spec.UnderlyingApi,
                spec.Description,
                spec.SupportsWrite,
                spec.UsesRemoteAgent,
                spec.Fields,
                functionData,
                warnings
            );
        }

        private async Task<HostingSiteFunctionMutationResponse> RunHostingSiteFunctionMutationAsync(SqlConnection connection, OwnedHostingSite site, string functionKey, HostingSiteFunctionMutationRequest request)
        {
            var normalizedKey = NormalizeWebsiteFunctionKey(functionKey);
            var action = (request.Action ?? "").Trim();
            var fields = request.Fields ?? new Dictionary<string, string>();
            var spec = GetWebsiteFunctionSpec(normalizedKey);

            if (!spec.SupportsWrite)
            {
                return new HostingSiteFunctionMutationResponse(false, $"{spec.Label} is read-only in this panel.", null);
            }

            if (normalizedKey == "site-name")
            {
                var nextName = fields.TryGetValue("siteName", out var siteName) ? siteName.Trim() : "";
                if (!IsSafeSiteDisplayName(nextName))
                {
                    return new HostingSiteFunctionMutationResponse(false, "Enter a safe site name without slashes or special path characters.", null);
                }

                var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/iis_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "IIS_Member_IISEntry_SITENAME_EDIT",
                    ["IIS_ID"] = FullIisId(site),
                    ["site_name"] = nextName
                });

                if (!call.Success)
                {
                    return new HostingSiteFunctionMutationResponse(false, call.Message, call);
                }

                await using var command = new SqlCommand("UPDATE dbo.cp_config_Sites SET Display_name = @siteName WHERE site_Uid = @siteUid AND cpID = @cpId", connection);
                command.Parameters.AddWithValue("@siteName", nextName);
                command.Parameters.AddWithValue("@siteUid", site.SiteUid);
                command.Parameters.AddWithValue("@cpId", site.CpId);
                await command.ExecuteNonQueryAsync();
                return new HostingSiteFunctionMutationResponse(true, "Site name updated in IIS and account data.", call);
            }

            if (normalizedKey == "site-on-off")
            {
                var nextState = action.Equals("stop", StringComparison.OrdinalIgnoreCase) || action.Equals("off", StringComparison.OrdinalIgnoreCase)
                    ? "stop"
                    : "start";
                var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/iis_api.asp", new Dictionary<string, string>
                {
                    ["action"] = nextState == "stop" ? "IIS_Member_IISEntry_STOP" : "IIS_Member_IISEntry_START",
                    ["IIS_ID"] = FullIisId(site)
                });

                if (!call.Success)
                {
                    return new HostingSiteFunctionMutationResponse(false, call.Message, call);
                }

                await using var command = new SqlCommand("UPDATE dbo.cp_config_Sites SET iis_status = @status WHERE site_Uid = @siteUid AND cpID = @cpId", connection);
                command.Parameters.AddWithValue("@status", nextState != "stop");
                command.Parameters.AddWithValue("@siteUid", site.SiteUid);
                command.Parameters.AddWithValue("@cpId", site.CpId);
                await command.ExecuteNonQueryAsync();
                return new HostingSiteFunctionMutationResponse(true, $"Site {nextState} request completed.", call);
            }

            if (normalizedKey is "vs-webdeploy" or "remote-iis-manager")
            {
                return await RunWebDeployMutationAsync(connection, site, action);
            }

            if (normalizedKey == "application-pool")
            {
                return await RunApplicationPoolMutationAsync(connection, site, action, fields);
            }

            if (normalizedKey == "mapped-path")
            {
                return await RunMappedPathMutationAsync(connection, site, fields);
            }

            if (normalizedKey == "nodejs-app")
            {
                return await RunNodeJsAppMutationAsync(connection, site, action, fields);
            }

            if (normalizedKey == "github-deploy")
            {
                var type = "";
                if (normalizedKey == "github-deploy" && action.Equals("deploy", StringComparison.OrdinalIgnoreCase))
                {
                    type = "deploy";
                }

                if (string.IsNullOrWhiteSpace(type))
                {
                    return new HostingSiteFunctionMutationResponse(
                        false,
                        $"{spec.Label} only queues explicit worker actions. Choose a supported action instead of running a generic queue job.",
                        new
                        {
                            supportedActions = normalizedKey switch
                            {
                                "github-deploy" => new[] { "deploy" },
                                _ => Array.Empty<string>()
                            }
                        });
                }

                var queueRequest = new HostingWorkqueueRequest(
                    site.CpId,
                    type,
                    fields.TryGetValue("source", out var source) ? source : site.SitePath,
                    fields.TryGetValue("target", out var target) ? target : site.SitePath,
                    site.ServerId,
                    string.IsNullOrWhiteSpace(action) ? spec.Label : action,
                    site.SiteName,
                    "website-more-functions"
                );
                var result = await CreateHostingWorkqueueAsync(connection, new SelectedHostingCp(site.CpId, site.CpLogin, site.ServerId, site.WebHostType), queueRequest);
                if (result.Success &&
                    normalizedKey == "github-deploy" &&
                    result.Id > 0 &&
                    fields.TryGetValue("createDeployhook", out var createDeployhook) &&
                    string.Equals(createDeployhook, "true", StringComparison.OrdinalIgnoreCase))
                {
                    await SaveGithubDeployHookAsync(connection, site.SiteUid, result.Id);
                    var status = await LoadGithubDeployStatusAsync(connection, site);
                    return new HostingSiteFunctionMutationResponse(true, "Github deploy job queued and deploy hook saved.", new
                    {
                        queue = result,
                        github = status
                    });
                }

                return new HostingSiteFunctionMutationResponse(result.Success, result.Message, result);
            }

            if (normalizedKey == "scan-virus")
            {
                var queueRequest = new HostingWorkqueueRequest(
                    site.CpId,
                    "scanvirus",
                    site.SitePath,
                    site.SitePath,
                    site.ServerId,
                    fields.TryGetValue("command", out var command) ? command : "",
                    site.SiteName,
                    "website-more-functions"
                );
                var result = await CreateHostingWorkqueueAsync(connection, new SelectedHostingCp(site.CpId, site.CpLogin, site.ServerId, site.WebHostType), queueRequest);
                return new HostingSiteFunctionMutationResponse(result.Success, result.Message, result);
            }

            if (normalizedKey == "ftp-access")
            {
                return new HostingSiteFunctionMutationResponse(
                    true,
                    "FTP Access uses the live FTP Manager flow. Create FTP users or update FTP passwords from the FTP section.",
                    new
                    {
                        site.SiteName,
                        site.SitePath,
                        legacySource = "/Users/erwinyu/Downloads/hosting/cp8/functions/functions.inc:createFTPSingle"
                    });
            }

            if (normalizedKey == "outgoing-port")
            {
                return await RunOutgoingPortMutationAsync(connection, site, action, fields);
            }

            if (normalizedKey == "force-https")
            {
                return await RunForceHttpsMutationAsync(connection, site, action, fields);
            }

            if (normalizedKey == "ip-deny")
            {
                return await RunIpDenyMutationAsync(site, action, fields);
            }

            if (normalizedKey == "create-net-app")
            {
                return await RunCreateNetAppMutationAsync(connection, site, action, fields);
            }

            if (normalizedKey == "virtual-dir")
            {
                return await RunVirtualDirMutationAsync(connection, site, action, fields);
            }

            if (normalizedKey == "custom-errors")
            {
                return await RunCustomErrorsMutationAsync(site, action, fields);
            }

            if (normalizedKey == "aspnet-version")
            {
                return await RunAspNetVersionMutationAsync(connection, site, fields);
            }

            if (normalizedKey == "php-version")
            {
                return await RunPhpVersionMutationAsync(connection, site, fields);
            }

            if (normalizedKey == "php-settings")
            {
                return await RunPhpSettingsMutationAsync(connection, site, fields);
            }

            if (normalizedKey == "visitor-stats")
            {
                return await RunVisitorStatsMutationAsync(connection, site, action, fields);
            }

            if (normalizedKey == "smtp-sample-code")
            {
                return await RunSmtpSampleCodeMutationAsync(connection, site, fields);
            }

            if (normalizedKey == "iis-log-manager")
            {
                return await RunIisLogManagerMutationAsync(connection, site, action);
            }

            if (normalizedKey == "domain-manager")
            {
                return await RunDomainManagerMutationAsync(connection, site, action, fields);
            }

            if (normalizedKey == "delete-website")
            {
                return await RunDeleteWebsiteMutationAsync(connection, site, fields);
            }

            if (normalizedKey == "schedule-tasks")
            {
                return await RunScheduleTaskMutationAsync(connection, site, action, fields);
            }

            if (normalizedKey is "core-mode" or "detail-error" or "site-guard")
            {
                return await RunAspNetAppMutationAsync(connection, site, normalizedKey, action, fields);
            }

            var remote = BuildWebsiteFunctionRemoteAction(normalizedKey, site, action, fields);
            if (remote != null)
            {
                var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, remote.Path, remote.Form);
                return new HostingSiteFunctionMutationResponse(call.Success, call.Message, call);
            }

            return new HostingSiteFunctionMutationResponse(false, $"{spec.Label} needs an approved service action before it can write safely.", null);
        }

        private async Task<List<LegacyAgentCallResult>> SetCoreHostingModelForSiteAsync(OwnedHostingSite site, string mode, long customerId)
        {
            var calls = new List<LegacyAgentCallResult>();
            var appPaths = new List<string> { "" };
            var appsCall = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
            {
                ["action"] = "IIS_Member_Apps_List_Get",
                ["IIS_ID"] = FullIisId(site)
            }, customerId);

            if (appsCall.Success && !string.IsNullOrWhiteSpace(appsCall.Body))
            {
                foreach (var chunk in appsCall.Body.Split('|', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries))
                {
                    var appPath = chunk.Split(';', 2, StringSplitOptions.TrimEntries)[0];
                    if (!string.IsNullOrWhiteSpace(appPath) && !appPaths.Contains(appPath, StringComparer.OrdinalIgnoreCase))
                    {
                        appPaths.Add(appPath);
                    }
                }
            }

            foreach (var path in appPaths)
            {
                calls.Add(await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "set_HostingModel",
                    ["IIS_ID"] = FullIisId(site),
                    ["Mode"] = mode,
                    ["apppath"] = path
                }, customerId));
            }

            return calls;
        }

        private async Task<HostingSiteFunctionMutationResponse> RunNodeJsAppMutationAsync(SqlConnection connection, OwnedHostingSite site, string action, Dictionary<string, string> fields)
        {
            var mode = FieldValue(fields, "mode", FieldValue(fields, "Mode", FieldValue(fields, "handler", "httpPlatformHandler")));
            if (NormalizeWebsiteAction(action) is "disable" or "delete" or "remove")
            {
                mode = "none";
            }

            mode = mode.Equals("none", StringComparison.OrdinalIgnoreCase)
                ? "none"
                : "httpPlatformHandler";
            var appPath = NormalizeIisAppPath(FieldValue(fields, "appPath", "/"));
            var agentAppPath = appPath == "/" ? "" : appPath.TrimStart('/');
            var customerId = await LoadCustomerIdForCpAsync(connection, site.CpId);
            var calls = new List<LegacyAgentCallResult>();

            if (mode == "none")
            {
                calls.Add(await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "del_handler_httpPlatformHandler",
                    ["IIS_ID"] = FullIisId(site),
                    ["apppath"] = agentAppPath
                }, customerId));
                calls.Add(await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "del_handler_iisnode",
                    ["IIS_ID"] = FullIisId(site),
                    ["apppath"] = agentAppPath
                }, customerId));

                var failedDisable = calls.FirstOrDefault(call => !call.Success);
                if (failedDisable != null)
                {
                    return new HostingSiteFunctionMutationResponse(false, failedDisable.Message, calls);
                }

                await SetSubAppInfoAsync(connection, site.SiteUid, appPath, "nodejs", "0");
                return new HostingSiteFunctionMutationResponse(true, "Node.js disabled.", calls);
            }

            var startupFile = NormalizeNodeStartupFile(FieldValue(fields, "startupfile", FieldValue(fields, "entryPoint", "")));
            if (string.IsNullOrWhiteSpace(startupFile))
            {
                return new HostingSiteFunctionMutationResponse(false, "Application startup file is required.", null);
            }

            if (appPath != "/")
            {
                var createAppCall = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "IIS_Member_App_Create",
                    ["IIS_ID"] = FullIisId(site),
                    ["apppath"] = agentAppPath
                }, customerId);
                calls.Add(createAppCall);
                if (!createAppCall.Success)
                {
                    return new HostingSiteFunctionMutationResponse(false, createAppCall.Message, calls);
                }
            }

            calls.Add(await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
            {
                ["action"] = "del_handler_httpPlatformHandler",
                ["IIS_ID"] = FullIisId(site),
                ["apppath"] = agentAppPath
            }, customerId));
            calls.Add(await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
            {
                ["action"] = "del_handler_iisnode",
                ["IIS_ID"] = FullIisId(site),
                ["apppath"] = agentAppPath
            }, customerId));
            calls.Add(await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
            {
                ["action"] = "create_handler_httpPlatformHandler",
                ["IIS_ID"] = FullIisId(site),
                ["apppath"] = agentAppPath,
                ["processPath"] = "node",
                ["startupfile"] = startupFile,
                ["portname"] = "PORT"
            }, customerId));

            var failed = calls.FirstOrDefault(call => !call.Success);
            if (failed != null)
            {
                return new HostingSiteFunctionMutationResponse(false, failed.Message, calls);
            }

            await ExecuteNonQueryAsync(connection, @"
INSERT INTO dbo.workqueue (cplogin, zipfile, dstfolder, enterdate, serverid, type)
VALUES (@cpLogin, @sitePath, '3', GETDATE(), @serverId, 'nodejs')",
                command =>
                {
                    command.Parameters.AddWithValue("@cpLogin", site.CpLogin);
                    command.Parameters.AddWithValue("@sitePath", site.SitePath);
                    command.Parameters.AddWithValue("@serverId", site.ServerId);
                });

            var webConfigPath = appPath == "/"
                ? site.SitePath
                : $@"{site.SitePath}\{agentAppPath}".Replace("/", "\\", StringComparison.Ordinal);
            var rewriteCall = await PostLegacySharedApiAsync(GetLegacySharedApiSettings(), "/api/redirect_api.asp", new Dictionary<string, string>
            {
                ["action"] = "delete",
                ["webconfigPath"] = webConfigPath,
                ["rulename"] = "iisnode",
                ["serverid"] = site.ServerId
            });
            calls.Add(rewriteCall);

            await SetSubAppInfoAsync(connection, site.SiteUid, appPath, "nodejs", "1");
            return new HostingSiteFunctionMutationResponse(true, "Node.js enabled.", calls);
        }

        private static string NormalizeNodeStartupFile(string value)
        {
            var startupFile = (value ?? "").Trim().Replace(":", "", StringComparison.Ordinal).Replace("..", "", StringComparison.Ordinal).Replace("/", "\\", StringComparison.Ordinal);
            if (startupFile.StartsWith("\\", StringComparison.Ordinal))
            {
                startupFile = "." + startupFile;
            }

            if (startupFile.Length > 120 || startupFile.Contains('\0'))
            {
                return "";
            }

            return startupFile;
        }

        private async Task<HostingSiteFunctionMutationResponse> RunForceHttpsMutationAsync(SqlConnection connection, OwnedHostingSite site, string action, Dictionary<string, string> fields)
        {
            var normalizedAction = NormalizeWebsiteAction(action);
            if (normalizedAction is not ("create" or "enable" or "delete" or "remove" or "disable"))
            {
                return new HostingSiteFunctionMutationResponse(false, "Force HTTPS supports only create/enable or delete/remove actions.", null);
            }

            var serverId = site.ServerId;
            var webConfigPath = (site.SitePath ?? "").Trim().ToLowerInvariant();
            if (string.IsNullOrWhiteSpace(serverId) || string.IsNullOrWhiteSpace(webConfigPath))
            {
                return new HostingSiteFunctionMutationResponse(false, "Server ID or site path is missing for this website.", null);
            }

            var ruleName = SafeRewriteRuleName(FieldValue(fields, "ruleName", "httpTohttps"));
            if (string.IsNullOrWhiteSpace(ruleName))
            {
                return new HostingSiteFunctionMutationResponse(false, "Enter a safe redirect rule name.", null);
            }

            var sharedApi = GetLegacySharedApiSettings();
            var form = new Dictionary<string, string>
            {
                ["action"] = normalizedAction is "delete" or "remove" or "disable" ? "delete" : "create",
                ["webconfigPath"] = webConfigPath,
                ["rulename"] = ruleName,
                ["serverid"] = serverId
            };

            if (form["action"] == "create")
            {
                var fromDomain = FieldValue(fields, "fromDomain", FieldValue(fields, "domain", ""));
                var toDomain = FieldValue(fields, "toDomain", FieldValue(fields, "destination", ""));
                if (!IsSafeDomainForRewrite(fromDomain) || !IsSafeDomainForRewrite(toDomain))
                {
                    return new HostingSiteFunctionMutationResponse(false, "Enter safe source and destination domains for the redirect rule.", null);
                }

                var escapedFrom = fromDomain.Replace(".", "\\.", StringComparison.Ordinal);
                var httpValue = FieldBool(fields, "isSSL", false) ? "https://" : "http://";
                var ruleString = ruleName.Equals("httpTohttps", StringComparison.OrdinalIgnoreCase)
                    ? "<rule name=\"httpTohttps\" stopProcessing=\"true\"><match url=\"^(.*)$\" /><conditions><add input=\"{HTTPS}\" pattern=\"off\" ignoreCase=\"true\" /></conditions><action type=\"Redirect\" url=\"https://{HTTP_HOST}/{R:1}\" redirectType=\"Permanent\"  /></rule>"
                    : $"<rule name=\"{ruleName}\" stopProcessing=\"true\"><match url=\"^(.*)$\" /><conditions><add input=\"{{HTTP_HOST}}\" pattern=\"^{escapedFrom}$\" /></conditions><action type=\"Redirect\" url=\"{httpValue}{toDomain}/{{R:1}}\" redirectType=\"Permanent\"  /></rule>";

                form["ruleString"] = ruleString;

                var duplicate = await ExecuteScalarAsync<int>(connection, @"
SELECT COUNT(1)
FROM dbo.cp_config_redirect
WHERE site_uid = @siteUid AND rulename = @ruleName",
                    command =>
                    {
                        command.Parameters.AddWithValue("@siteUid", site.SiteUid);
                        command.Parameters.AddWithValue("@ruleName", ruleName);
                    });
                if (duplicate > 0)
                {
                    return new HostingSiteFunctionMutationResponse(false, $"Redirect rule {ruleName} already exists for this site.", null);
                }

                var call = await PostLegacySharedApiAsync(sharedApi, "/api/redirect_api.asp", form);
                var acceptedCreate = call.Success
                    || call.Preview.Contains("Done.", StringComparison.OrdinalIgnoreCase)
                    || string.IsNullOrWhiteSpace(call.Preview);
                if (!acceptedCreate)
                {
                    return new HostingSiteFunctionMutationResponse(false, call.Message, call);
                }

                await ExecuteNonQueryAsync(connection, @"
INSERT INTO dbo.cp_config_redirect (site_uid, domain, destination, rulename)
VALUES (@siteUid, @domain, @destination, @ruleName)",
                    command =>
                    {
                        command.Parameters.AddWithValue("@siteUid", site.SiteUid);
                        command.Parameters.AddWithValue("@domain", fromDomain);
                        command.Parameters.AddWithValue("@destination", toDomain);
                        command.Parameters.AddWithValue("@ruleName", ruleName);
                    });

                return new HostingSiteFunctionMutationResponse(true, "Force HTTPS redirect rule created.", call);
            }

            var deleteCall = await PostLegacySharedApiAsync(sharedApi, "/api/redirect_api.asp", form);
            var acceptedDelete = deleteCall.Success
                || deleteCall.Preview.Contains("Done.", StringComparison.OrdinalIgnoreCase)
                || deleteCall.Preview.Contains("a null-valued expression", StringComparison.OrdinalIgnoreCase)
                || string.IsNullOrWhiteSpace(deleteCall.Preview);
            if (!acceptedDelete)
            {
                return new HostingSiteFunctionMutationResponse(false, deleteCall.Message, deleteCall);
            }

            await ExecuteNonQueryAsync(connection, @"
DELETE FROM dbo.cp_config_redirect
WHERE site_uid = @siteUid AND rulename = @ruleName",
                command =>
                {
                    command.Parameters.AddWithValue("@siteUid", site.SiteUid);
                    command.Parameters.AddWithValue("@ruleName", ruleName);
                });

            return new HostingSiteFunctionMutationResponse(true, "Force HTTPS redirect rule removed.", deleteCall);
        }

        private async Task<HostingSiteFunctionMutationResponse> RunIpDenyMutationAsync(OwnedHostingSite site, string action, Dictionary<string, string> fields)
        {
            var normalizedAction = NormalizeWebsiteAction(action);
            var ipAddress = FieldValue(fields, "ipAddress", FieldValue(fields, "ip", ""));
            var subnetMask = FieldValue(fields, "subnetMask", FieldValue(fields, "mask", "255.255.255.255"));
            if (normalizedAction is not "dynamicip" && (!IPAddress.TryParse(ipAddress, out _) || !IPAddress.TryParse(subnetMask, out _)))
            {
                return new HostingSiteFunctionMutationResponse(false, "Enter a valid IP address and subnet mask.", null);
            }

            if (normalizedAction is "create" or "add" or "deny")
            {
                var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "set_ipSecurity_deny",
                    ["IIS_ID"] = FullIisId(site),
                    ["ipAddress"] = ipAddress,
                    ["subnetMask"] = subnetMask
                });
                return new HostingSiteFunctionMutationResponse(call.Success, call.Success ? "IP address added to the deny list." : call.Message, call);
            }

            if (normalizedAction is "remove" or "delete" or "allow")
            {
                var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "set_ipSecurity_remove",
                    ["IIS_ID"] = FullIisId(site),
                    ["ipAddress"] = ipAddress,
                    ["subnetMask"] = subnetMask
                });
                return new HostingSiteFunctionMutationResponse(call.Success, call.Success ? "IP address removed from the deny list." : call.Message, call);
            }

            if (normalizedAction == "dynamicip")
            {
                var denyConcurrent = FieldBool(fields, "denyConcurrent", false);
                var denyOverPeriod = FieldBool(fields, "denyOverPeriod", false);
                var maxDenyConcurrent = ParsePositiveInt(FieldValue(fields, "maxDenyConcurrentNumber", FieldValue(fields, "Max_Deny_Concurrent_Number", "5")), 5);
                var maxDenyNumber = ParsePositiveInt(FieldValue(fields, "maxDenyNumber", FieldValue(fields, "Max_Deny_Number", "20")), 20);
                var timePeriod = ParsePositiveInt(FieldValue(fields, "timePeriod", FieldValue(fields, "Time_Period", "200")), 200);
                var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "Set_Dynamic_IP_Restrict",
                    ["IIS_ID"] = FullIisId(site),
                    ["Deny_Concurrent"] = denyConcurrent ? "true" : "false",
                    ["Max_Deny_Concurrent_Number"] = maxDenyConcurrent.ToString(CultureInfo.InvariantCulture),
                    ["Deny_Over_Period"] = denyOverPeriod ? "true" : "false",
                    ["Max_Deny_Number"] = maxDenyNumber.ToString(CultureInfo.InvariantCulture),
                    ["Time_Period"] = timePeriod.ToString(CultureInfo.InvariantCulture)
                });
                return new HostingSiteFunctionMutationResponse(call.Success, call.Success ? "Dynamic IP restriction settings saved." : call.Message, call);
            }

            return new HostingSiteFunctionMutationResponse(false, "IP Deny supports add/create, remove/delete, or dynamicip actions.", null);
        }

        private async Task<HostingSiteFunctionMutationResponse> RunCreateNetAppMutationAsync(SqlConnection connection, OwnedHostingSite site, string action, Dictionary<string, string> fields)
        {
            var normalizedAction = NormalizeWebsiteAction(action);
            var appPath = NormalizeLegacyAppPath(FieldValue(fields, "appPath", ""));
            if (string.IsNullOrWhiteSpace(appPath))
            {
                return new HostingSiteFunctionMutationResponse(false, "Enter a safe application path under this website.", null);
            }

            if (normalizedAction is "delete" or "remove")
            {
                var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "IIS_Member_App_Delete",
                    ["IIS_ID"] = FullIisId(site),
                    ["apppath"] = appPath
                });
                if (!call.Success)
                {
                    return new HostingSiteFunctionMutationResponse(false, call.Message, call);
                }

                await DeleteSubAppInfoAsync(connection, site.SiteUid, appPath);
                return new HostingSiteFunctionMutationResponse(true, ".NET application removed and sub-application metadata cleaned.", call);
            }

            if (normalizedAction is not ("create" or "add"))
            {
                return new HostingSiteFunctionMutationResponse(false, ".NET App supports only create/add or delete/remove actions.", null);
            }

            var createCall = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
            {
                ["action"] = "IIS_Member_App_Create",
                ["IIS_ID"] = FullIisId(site),
                ["apppath"] = appPath
            });
            if (!createCall.Success)
            {
                return new HostingSiteFunctionMutationResponse(false, createCall.Message, createCall);
            }

            var version = FieldValue(fields, "pDotNetVersion", FieldValue(fields, "version", "4.x"));
            await SetSubAppInfoAsync(connection, site.SiteUid, appPath, "version", version);
            return new HostingSiteFunctionMutationResponse(true, ".NET application created and sub-application metadata updated.", createCall);
        }

        private async Task<HostingSiteFunctionMutationResponse> RunVirtualDirMutationAsync(SqlConnection connection, OwnedHostingSite site, string action, Dictionary<string, string> fields)
        {
            var normalizedAction = NormalizeWebsiteAction(action);
            var vdirName = NormalizeVirtualDirName(FieldValue(fields, "vdirname", FieldValue(fields, "virtualPath", "")));
            if (string.IsNullOrWhiteSpace(vdirName))
            {
                return new HostingSiteFunctionMutationResponse(false, "Enter a safe virtual directory name without slashes.", null);
            }

            if (normalizedAction is "delete" or "remove")
            {
                var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "IIS_Member_VD_Delete",
                    ["IIS_ID"] = FullIisId(site),
                    ["vdirName"] = vdirName
                });
                if (!call.Success)
                {
                    return new HostingSiteFunctionMutationResponse(false, call.Message, call);
                }

                await DeleteSubAppInfoAsync(connection, site.SiteUid, vdirName);
                return new HostingSiteFunctionMutationResponse(true, "Virtual directory removed and metadata cleaned.", call);
            }

            if (normalizedAction is not ("create" or "add"))
            {
                return new HostingSiteFunctionMutationResponse(false, "Virtual Dir supports only create/add or delete/remove actions.", null);
            }

            var customerRoot = $@"h:\root\home\{site.CpLogin}\www";
            var requestedPath = FieldValue(fields, "physicalPath", FieldValue(fields, "vdpath", customerRoot));
            var path = NormalizeOwnedHostingAbsolutePath(requestedPath, site.CpLogin);
            if (!path.Success)
            {
                return new HostingSiteFunctionMutationResponse(false, path.Message, null);
            }

            var isApp = FieldBool(fields, "isapp", false);
            var callCreate = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
            {
                ["action"] = "IIS_Member_VD_Create",
                ["isapp"] = isApp ? "1" : "0",
                ["IIS_ID"] = FullIisId(site),
                ["vdirName"] = vdirName,
                ["vdpath"] = path.Path
            });
            if (!callCreate.Success)
            {
                return new HostingSiteFunctionMutationResponse(false, callCreate.Message, callCreate);
            }

            if (isApp)
            {
                await SetSubAppInfoAsync(connection, site.SiteUid, vdirName, "version", "4.x");
            }

            return new HostingSiteFunctionMutationResponse(true, "Virtual directory created.", callCreate);
        }

        private async Task<HostingSiteFunctionMutationResponse> RunCustomErrorsMutationAsync(OwnedHostingSite site, string action, Dictionary<string, string> fields)
        {
            var statusCode = FieldValue(fields, "errorType", FieldValue(fields, "statusCode", "404"));
            if (!int.TryParse(statusCode, NumberStyles.Integer, CultureInfo.InvariantCulture, out var code) || code is < 400 or > 599)
            {
                return new HostingSiteFunctionMutationResponse(false, "Enter a valid HTTP error status code between 400 and 599.", null);
            }

            var useDefault = NormalizeWebsiteAction(action) is "default" or "reset" || FieldBool(fields, "defaultError", false);
            var filePath = NormalizeIisAppPath(FieldValue(fields, "filepath", FieldValue(fields, "path", "/404.html")));
            if (!useDefault && !IsSafeIisRelativeFilePath(filePath))
            {
                return new HostingSiteFunctionMutationResponse(false, "Enter a safe website-relative error page path.", null);
            }
            var agentFilePath = filePath.TrimStart('/');

            var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
            {
                ["action"] = "IIS_Member_ErrorPage_Edit",
                ["IIS_ID"] = FullIisId(site),
                ["errorType"] = code.ToString(CultureInfo.InvariantCulture),
                ["filepath"] = useDefault ? "" : agentFilePath,
                ["defaultError"] = useDefault ? "1" : "0"
            });

            return new HostingSiteFunctionMutationResponse(call.Success, call.Success ? "Custom error page setting updated." : call.Message, call);
        }

        private async Task<HostingSiteFunctionMutationResponse> RunAspNetVersionMutationAsync(SqlConnection connection, OwnedHostingSite site, Dictionary<string, string> fields)
        {
            var appPath = NormalizeIisAppPath(FieldValue(fields, "appPath", "/"));
            var version = NormalizeAspNetVersion(FieldValue(fields, "version", FieldValue(fields, "newversion", "v4.0")));
            var pipeline = NormalizePipelineMode(FieldValue(fields, "pipeline", FieldValue(fields, "Classicmode", "Integrated")));
            if (string.IsNullOrWhiteSpace(version))
            {
                return new HostingSiteFunctionMutationResponse(false, "Choose a supported ASP.NET version.", null);
            }

            var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
            {
                ["action"] = "IIS_Member_DotNetVersion_Edit_No_Mapping",
                ["IIS_ID"] = FullIisId(site),
                ["AppPath"] = appPath,
                ["newversion"] = version,
                ["Classicmode"] = pipeline
            });
            if (!call.Success)
            {
                return new HostingSiteFunctionMutationResponse(false, call.Message, call);
            }

            var display = version.Contains("2", StringComparison.OrdinalIgnoreCase) ? "2/3.5" : version.Contains("1", StringComparison.OrdinalIgnoreCase) ? "1.x" : "4.x";
            display += pipeline.Equals("Classic", StringComparison.OrdinalIgnoreCase) ? "(c)" : "(i)";
            if (appPath == "/")
            {
                await ExecuteNonQueryAsync(connection, "UPDATE dbo.cp_config_sites SET version = @version WHERE site_uid = @siteUid AND cpID = @cpId", command =>
                {
                    command.Parameters.AddWithValue("@version", display);
                    command.Parameters.AddWithValue("@siteUid", site.SiteUid);
                    command.Parameters.AddWithValue("@cpId", site.CpId);
                });
            }
            else
            {
                await SetSubAppInfoAsync(connection, site.SiteUid, appPath, "version", display);
            }

            return new HostingSiteFunctionMutationResponse(true, "ASP.NET version updated.", call);
        }

        private async Task<HostingSiteFunctionMutationResponse> RunPhpVersionMutationAsync(SqlConnection connection, OwnedHostingSite site, Dictionary<string, string> fields)
        {
            var phpVersionIndex = NormalizePhpVersionIndex(FieldValue(fields, "phpversion", FieldValue(fields, "phpVersion", "")));
            if (phpVersionIndex <= 0 && phpVersionIndex != 250)
            {
                return new HostingSiteFunctionMutationResponse(false, "Choose a supported PHP version.", null);
            }

            var removeCall = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
            {
                ["action"] = "IIS_Member_IISEntry_CustomScriptMap_Remove",
                ["IIS_ID"] = FullIisId(site),
                ["TagName"] = "Custom-PHP5-FastCGI-php"
            });
            if (!removeCall.Success)
            {
                return new HostingSiteFunctionMutationResponse(false, removeCall.Message, removeCall);
            }

            if (phpVersionIndex == 250)
            {
                await ExecuteNonQueryAsync(connection, "UPDATE dbo.cp_config_sites SET phpversion = @phpVersion WHERE site_uid = @siteUid AND cpID = @cpId", command =>
                {
                    command.Parameters.AddWithValue("@phpVersion", "Disabled");
                    command.Parameters.AddWithValue("@siteUid", site.SiteUid);
                    command.Parameters.AddWithValue("@cpId", site.CpId);
                });

                return new HostingSiteFunctionMutationResponse(true, "PHP support disabled.", removeCall);
            }

            var addCall = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
            {
                ["action"] = "IIS_Member_IISEntry_CustomScriptMap_Add",
                ["IIS_ID"] = FullIisId(site),
                ["scriptTypeIndex"] = phpVersionIndex.ToString(CultureInfo.InvariantCulture),
                ["extension"] = "php"
            });
            if (!addCall.Success)
            {
                return new HostingSiteFunctionMutationResponse(false, addCall.Message, addCall);
            }

            await ExecuteNonQueryAsync(connection, "UPDATE dbo.cp_config_sites SET version = 'v1.x(i)', phpversion = @phpVersion WHERE site_uid = @siteUid AND cpID = @cpId", command =>
            {
                command.Parameters.AddWithValue("@phpVersion", PhpDisplayVersion(phpVersionIndex));
                command.Parameters.AddWithValue("@siteUid", site.SiteUid);
                command.Parameters.AddWithValue("@cpId", site.CpId);
            });

            return new HostingSiteFunctionMutationResponse(true, "PHP version updated.", new { remove = removeCall, add = addCall });
        }

        private async Task<HostingSiteFunctionMutationResponse> RunPhpSettingsMutationAsync(SqlConnection connection, OwnedHostingSite site, Dictionary<string, string> fields)
        {
            var settings = FieldValue(fields, "phpsettings", FieldValue(fields, "settings", ""));
            if (string.IsNullOrWhiteSpace(settings) || settings.Length > 12000)
            {
                return new HostingSiteFunctionMutationResponse(false, "PHP settings content is empty or too large.", null);
            }

            var cp = new SelectedHostingCp(site.CpId, site.CpLogin, site.ServerId, site.WebHostType);
            var path = NormalizeOwnedFileManagerPath(site.SitePath, BuildHostingHomePath(cp));
            if (!path.Success)
            {
                return new HostingSiteFunctionMutationResponse(false, path.Message, null);
            }

            var fileRequest = new HostingFileManagerActionRequest(site.CpId, "save-file", path.Path, ".user.ini", "", ".user.ini", true, settings, "utf-8");
            var result = await RunFileManagerActionAsync(connection, cp, fileRequest);
            return new HostingSiteFunctionMutationResponse(result.Success, result.Success ? "PHP settings saved to .user.ini." : result.Message, result);
        }

        private async Task<HostingSiteFunctionMutationResponse> RunVisitorStatsMutationAsync(SqlConnection connection, OwnedHostingSite site, string action, Dictionary<string, string> fields)
        {
            if (site.IsSubdomain)
            {
                return new HostingSiteFunctionMutationResponse(false, "Visitor stats are not available for sub-sites.", null);
            }

            var normalizedAction = NormalizeWebsiteAction(action);
            var enable = normalizedAction is "enable" or "on";
            var disable = normalizedAction is "disable" or "off";
            if (!enable && !disable)
            {
                return new HostingSiteFunctionMutationResponse(false, "Visitor Stats supports only enable/on or disable/off actions.", null);
            }

            var mainDomain = FieldValue(fields, "mainDomain", FieldValue(fields, "domain", ""));
            if (string.IsNullOrWhiteSpace(mainDomain))
            {
                mainDomain = await ExecuteScalarAsync<string>(connection, @"
SELECT TOP 1 domain_name
FROM dbo.cp_config_Domains
WHERE site_Uid = @siteUid
ORDER BY ISNULL(isDefault, 0) DESC, domain_name",
                    command => command.Parameters.AddWithValue("@siteUid", site.SiteUid)) ?? "";
            }
            if (!IsSafeDomainForRewrite(mainDomain))
            {
                return new HostingSiteFunctionMutationResponse(false, "Choose a safe primary domain for visitor stats.", null);
            }

            var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/WebStats_api.asp", new Dictionary<string, string>
            {
                ["action"] = enable ? "Enable" : "Disable",
                ["serverID"] = site.ServerId,
                ["cpID"] = site.CpId.ToString(CultureInfo.InvariantCulture),
                ["iis_ID"] = site.IisId,
                ["Domain"] = mainDomain,
                ["cpLogin"] = site.CpLogin,
                ["pwd"] = "",
                ["path"] = ""
            });
            if (!call.Success)
            {
                return new HostingSiteFunctionMutationResponse(false, call.Message, call);
            }

            await ExecuteNonQueryAsync(connection, @"
UPDATE dbo.cp_config_sites
SET Stats_enabled = @enabled, Stats_mainDomain = @mainDomain
WHERE site_uid = @siteUid AND cpID = @cpId",
                command =>
                {
                    command.Parameters.AddWithValue("@enabled", enable);
                    command.Parameters.AddWithValue("@mainDomain", mainDomain);
                    command.Parameters.AddWithValue("@siteUid", site.SiteUid);
                    command.Parameters.AddWithValue("@cpId", site.CpId);
                });

            LegacyAgentCallResult? mkdirCall = null;
            if (enable)
            {
                var statsPath = $@"H:\root\home\{site.CpLogin}\stats\{site.SiteName}";
                mkdirCall = await PostLegacyRemoteCommandAsync(
                    GetLegacyAgentSettings(),
                    GetLegacyRemoteCommandSettings(),
                    site.ServerId,
                    await LoadCustomerIdForCpAsync(connection, site.CpId),
                    $"cmd /c mkdir {statsPath}");
            }

            return new HostingSiteFunctionMutationResponse(true, enable ? "Visitor stats enabled." : "Visitor stats disabled.", new { stats = call, statsFolder = mkdirCall });
        }

        private async Task<HostingSiteFunctionMutationResponse> RunSmtpSampleCodeMutationAsync(SqlConnection connection, OwnedHostingSite site, Dictionary<string, string> fields)
        {
            var scriptType = FieldValue(fields, "scripttype", FieldValue(fields, "scriptType", "1"));
            if (scriptType is not ("1" or "2" or "3" or "4"))
            {
                return new HostingSiteFunctionMutationResponse(false, "Choose ASP.NET C#, ASP.NET VB, ASP, or PHP sample code.", null);
            }

            var domain = NormalizeDomainName(FieldValue(fields, "domain", ""));
            if (!IsSafeDomainForRewrite(domain))
            {
                domain = await ExecuteScalarAsync<string>(connection, @"
SELECT TOP 1 domain_name
FROM dbo.cp_config_Domains
WHERE site_Uid = @siteUid
ORDER BY CASE WHEN domain_name LIKE '%tempurl.%' THEN 1 ELSE 0 END, ISNULL(isDefault, 0) DESC, domain_name",
                    command => command.Parameters.AddWithValue("@siteUid", site.SiteUid)) ?? "";
                domain = NormalizeDomainName(domain);
            }

            if (!IsSafeDomainForRewrite(domain))
            {
                return new HostingSiteFunctionMutationResponse(false, "This website needs a mapped domain before SMTP sample code can be installed.", null);
            }

            var cp = new SelectedHostingCp(site.CpId, site.CpLogin, site.ServerId, site.WebHostType);
            var ftp = await LoadRootFtpForSslExportAsync(connection, cp);
            if (ftp == null)
            {
                return new HostingSiteFunctionMutationResponse(false, "Root FTP user was not found, so SMTP sample code cannot be uploaded.", null);
            }

            var ftpPassword = await TryLegacyDecryptFtpPwdAsync(ftp.Pp1);
            if (string.IsNullOrWhiteSpace(ftpPassword))
            {
                return new HostingSiteFunctionMutationResponse(false, "SMTP sample upload needs the root FTP password, but it could not be decrypted.", null);
            }

            var homePrefix = $@"h:\root\home\{site.CpLogin}\www\";
            var ftpDir = site.SitePath.StartsWith(homePrefix, StringComparison.OrdinalIgnoreCase)
                ? site.SitePath[homePrefix.Length..].Replace("\\", "/", StringComparison.Ordinal).Trim('/')
                : "";
            var localPath = $@"C:\hosting\cp8\otherplugins\smtptester\{scriptType}";
            var call = await PostLegacySharedApiAsync(GetLegacySharedApiSettings(), "/api/upload_api.asp", new Dictionary<string, string>
            {
                ["ftphost"] = string.IsNullOrWhiteSpace(ftp.Server) ? BuildLegacyHost(GetLegacyAgentSettings(), site.ServerId) : ftp.Server,
                ["ftpuser"] = site.CpLogin,
                ["ftppwd"] = ftpPassword,
                ["ftpdir"] = ftpDir,
                ["localPath"] = localPath,
                ["remoteFilename"] = "smtptester",
                ["action"] = "ftp_upload_tree"
            });

            return new HostingSiteFunctionMutationResponse(
                call.Success,
                call.Success ? $"SMTP sample code installed. Test it at http://{domain}/smtptester" : call.Message,
                new
                {
                    legacySource = "/Users/erwinyu/Downloads/hosting/cp8/cp/setupOtherPlugins/smtpscriptsamples_action.asp",
                    url = $"http://{domain}/smtptester",
                    folder = $@"{site.SitePath}\smtptester",
                    call.Url,
                    call.Preview
                });
        }

        private async Task<HostingSiteFunctionMutationResponse> RunIisLogManagerMutationAsync(SqlConnection connection, OwnedHostingSite site, string action)
        {
            var normalizedAction = NormalizeWebsiteAction(action);
            if (normalizedAction is not ("download" or "copy" or "export"))
            {
                return new HostingSiteFunctionMutationResponse(false, "IIS Log Manager supports only the download/export action.", null);
            }

            var customerId = await LoadCustomerIdForCpAsync(connection, site.CpId);
            var w3svcId = $"{site.CpId}{FormatIisId(site.IisId)}";
            var command = $@"xcopy c:\logfiles\W3SVC{w3svcId}\*.log h:\root\home\{site.CpLogin}\www\db\{w3svcId}\ /y";
            var call = await PostLegacyRemoteCommandAsync(GetLegacyAgentSettings(), GetLegacyRemoteCommandSettings(), site.ServerId, customerId, command);
            return new HostingSiteFunctionMutationResponse(
                call.Success,
                call.Success ? $"All IIS Raw Log files were moved to /db/{w3svcId}." : call.Message,
                new { w3svcId, command, call });
        }

        private async Task<HostingSiteFunctionMutationResponse> RunAspNetAppMutationAsync(SqlConnection connection, OwnedHostingSite site, string key, string action, Dictionary<string, string> fields)
        {
            var appPath = NormalizeIisAppPath(FieldValue(fields, "appPath", "/"));
            if (appPath == "/")
            {
                appPath = "";
            }

            if (key == "core-mode")
            {
                var mode = FieldValue(fields, "hostingModel", FieldValue(fields, "mode", "OutOfProcess"));
                mode = mode.Equals("InProcess", StringComparison.OrdinalIgnoreCase) ? "InProcess" : "OutOfProcess";
                var applyAll = FieldBool(fields, "applyAll", true);
                var customerId = await LoadCustomerIdForCpAsync(connection, site.CpId);
                var targetSites = applyAll
                    ? await LoadOwnedHostingSitesForCpAsync(connection, site.CpId)
                    : new List<OwnedHostingSite> { site };
                var calls = new List<object>();

                foreach (var targetSite in targetSites)
                {
                    var siteCalls = await SetCoreHostingModelForSiteAsync(targetSite, mode, customerId);
                    calls.Add(new { siteUid = targetSite.SiteUid, siteName = DisplaySiteName(targetSite), calls = siteCalls });
                    var failed = siteCalls.FirstOrDefault(call => !call.Success);
                    if (failed != null)
                    {
                        return new HostingSiteFunctionMutationResponse(false, failed.Message, new { site = targetSite.SiteUid, calls });
                    }
                }

                var restart = await RestartSitePoolViaRemoteCommandAsync(connection, site);
                return new HostingSiteFunctionMutationResponse(true, applyAll ? $"Core hosting model set to {mode} for all sites." : $"Core hosting model set to {mode}.", new { calls, restart });
            }

            if (key == "detail-error")
            {
                var normalizedAction = NormalizeWebsiteAction(action);
                var fallbackEnabled = normalizedAction switch
                {
                    "disable" or "off" => false,
                    "enable" or "on" => true,
                    _ => true
                };
                var enabled = FieldBool(fields, "enabled", fallbackEnabled);
                var mode = enabled ? "Off" : "On";
                var settingBit = enabled ? 1 : 0;
                var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "set_customErrors_Mode",
                    ["IIS_ID"] = FullIisId(site),
                    ["Mode"] = mode,
                    ["apppath"] = appPath
                });
                if (!call.Success)
                {
                    return new HostingSiteFunctionMutationResponse(false, call.Message, call);
                }

                if (string.IsNullOrWhiteSpace(appPath))
                {
                    await ExecuteNonQueryAsync(connection, "UPDATE dbo.cp_config_Sites SET detailerror = @enabled WHERE cpID = @cpId AND site_Uid = @siteUid", command =>
                    {
                        command.Parameters.AddWithValue("@enabled", settingBit);
                        command.Parameters.AddWithValue("@cpId", site.CpId);
                        command.Parameters.AddWithValue("@siteUid", site.SiteUid);
                    });
                }

                var restart = await RestartSitePoolViaRemoteCommandAsync(connection, site);
                return new HostingSiteFunctionMutationResponse(true, enabled ? "Detailed errors enabled." : "Detailed errors disabled.", new { legacy = call, restart });
            }

            if (key == "site-guard")
            {
                var enabled = FieldBool(fields, "enabled", !action.Equals("disable", StringComparison.OrdinalIgnoreCase));
                var fwAction = enabled ? "enableFW" : "disableFW";
                var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "IIS_Filter_webknight",
                    ["IIS_ID"] = FullIisId(site),
                    ["FW_Action"] = fwAction
                });
                if (!call.Success || !call.Preview.Trim().Equals("OK", StringComparison.OrdinalIgnoreCase))
                {
                    return new HostingSiteFunctionMutationResponse(false, call.Success ? $"Site Guard agent returned unexpected response: {call.Preview}" : call.Message, call);
                }

                if (string.IsNullOrWhiteSpace(appPath))
                {
                    await ExecuteNonQueryAsync(connection, "UPDATE dbo.cp_config_Sites SET webknight = @enabled WHERE cpID = @cpId AND site_Uid = @siteUid", command =>
                    {
                        command.Parameters.AddWithValue("@enabled", enabled ? 1 : 0);
                        command.Parameters.AddWithValue("@cpId", site.CpId);
                        command.Parameters.AddWithValue("@siteUid", site.SiteUid);
                    });
                }

                return new HostingSiteFunctionMutationResponse(true, enabled ? "Site Guard enabled." : "Site Guard disabled.", call);
            }

            return new HostingSiteFunctionMutationResponse(false, "Unsupported ASP.NET app action.", null);
        }

        private async Task<LegacyAgentCallResult> RestartSitePoolViaRemoteCommandAsync(SqlConnection connection, OwnedHostingSite site)
        {
            var poolName = await LoadPoolNameAsync(connection, site.CpId, ParseInt(site.PoolId));
            if (string.IsNullOrWhiteSpace(poolName))
            {
                return new LegacyAgentCallResult(false, "No application pool is assigned to this site.", "", "", null);
            }

            var customerId = await LoadCustomerIdByCpIdAsync(connection, site.CpId);
            if (customerId <= 0)
            {
                return new LegacyAgentCallResult(false, "Unable to resolve customer ID for remote command token.", "", "", null);
            }

            var command = $"powershell Get-Process -IncludeUserName | Where UserName -like '*{poolName}' | Stop-Process -force";
            return await PostLegacyRemoteCommandAsync(GetLegacyAgentSettings(), GetLegacyRemoteCommandSettings(), site.ServerId, customerId, command);
        }

        private async Task<HostingSiteFunctionMutationResponse> RunMappedPathMutationAsync(SqlConnection connection, OwnedHostingSite site, Dictionary<string, string> fields)
        {
            var requestedPath = FieldValue(fields, "target", FieldValue(fields, "sitePath", FieldValue(fields, "path", "")));
            var normalizedPath = NormalizeOwnedHostingAbsolutePath(requestedPath, site.CpLogin);
            if (!normalizedPath.Success)
            {
                return new HostingSiteFunctionMutationResponse(false, normalizedPath.Message, null);
            }

            if (normalizedPath.Path.Contains(@"\ ", StringComparison.Ordinal) || normalizedPath.Path.Contains(@" \", StringComparison.Ordinal))
            {
                return new HostingSiteFunctionMutationResponse(false, "Mapped path cannot contain leading or trailing spaces around folder separators.", null);
            }

            var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
            {
                ["action"] = "IIS_Member_Binding_Path_Change",
                ["IIS_ID"] = FullIisId(site),
                ["site_path"] = normalizedPath.Path
            });

            if (!call.Success || !call.Preview.Trim().Equals("OK", StringComparison.OrdinalIgnoreCase))
            {
                return new HostingSiteFunctionMutationResponse(false, call.Success ? $"Legacy IIS path change returned unexpected response: {call.Preview}" : call.Message, call);
            }

            await using (var updateCommand = new SqlCommand(@"
UPDATE dbo.cp_config_Sites
SET site_path = @sitePath
WHERE site_Uid = @siteUid AND cpID = @cpId", connection))
            {
                updateCommand.Parameters.AddWithValue("@sitePath", normalizedPath.Path);
                updateCommand.Parameters.AddWithValue("@siteUid", site.SiteUid);
                updateCommand.Parameters.AddWithValue("@cpId", site.CpId);
                await updateCommand.ExecuteNonQueryAsync();
            }

            var poolName = await LoadPoolNameAsync(connection, site.CpId, ParseInt(site.PoolId));
            HostingWorkqueueResponse? poolQueue = null;
            if (!string.IsNullOrWhiteSpace(poolName))
            {
                await DeletePendingPoolChangeAsync(connection, site.CpLogin, site.SiteName);
                poolQueue = await CreateHostingWorkqueueAsync(connection, new SelectedHostingCp(site.CpId, site.CpLogin, site.ServerId, site.WebHostType), new HostingWorkqueueRequest(
                    site.CpId,
                    "changepool",
                    normalizedPath.Path,
                    poolName,
                    site.ServerId,
                    site.PoolId,
                    site.SiteName,
                    poolName));
            }

            return new HostingSiteFunctionMutationResponse(true, "Mapped path updated in IIS and account data.", new
            {
                site.SiteUid,
                sitePath = normalizedPath.Path,
                legacy = call,
                poolQueue
            });
        }

        private async Task<HostingSiteFunctionMutationResponse> RunApplicationPoolMutationAsync(SqlConnection connection, OwnedHostingSite site, string action, Dictionary<string, string> fields)
        {
            var normalizedAction = NormalizeWebsiteAction(action);
            var poolId = ParseInt(FieldValue(fields, "poolId", site.PoolId));
            var cp = new SelectedHostingCp(site.CpId, site.CpLogin, site.ServerId, site.WebHostType);
            if (poolId <= 0)
            {
                var defaultPool = await EnsureDefaultApplicationPoolAsync(connection, cp);
                if (defaultPool == null)
                {
                    return new HostingSiteFunctionMutationResponse(false, "Application Pool needs a valid poolId.", null);
                }

                poolId = defaultPool.Id;
                await ExecuteNonQueryAsync(connection, "UPDATE dbo.cp_config_Sites SET pool_id = @poolId WHERE cpID = @cpId AND site_Uid = @siteUid AND ISNULL(pool_id, 0) = 0", command =>
                {
                    command.Parameters.AddWithValue("@poolId", poolId);
                    command.Parameters.AddWithValue("@cpId", site.CpId);
                    command.Parameters.AddWithValue("@siteUid", site.SiteUid);
                });
            }

            var pool = await LoadOwnedPoolAsync(connection, site.CpId, poolId);
            if (pool == null)
            {
                return new HostingSiteFunctionMutationResponse(false, "Application Pool not found for this hosting plan.", null);
            }

            if (normalizedAction is "create" or "createpool")
            {
                var queue = await CreateHostingWorkqueueAsync(connection, cp, new HostingWorkqueueRequest(
                    site.CpId,
                    "createpool",
                    "createpool",
                    pool.Name,
                    site.ServerId,
                    "",
                    site.SiteName,
                    "application-pool"));
                return new HostingSiteFunctionMutationResponse(queue.Success, queue.Message, queue);
            }

            if (normalizedAction is "change" or "changepool")
            {
                await DeletePendingPoolChangeAsync(connection, site.CpLogin, site.SiteName);
                var queue = await CreateHostingWorkqueueAsync(connection, cp, new HostingWorkqueueRequest(
                    site.CpId,
                    "changepool",
                    site.SitePath,
                    pool.Name,
                    site.ServerId,
                    pool.Id.ToString(CultureInfo.InvariantCulture),
                    site.SiteName,
                    await LoadPoolNameAsync(connection, site.CpId, ParseInt(site.PoolId))));
                return new HostingSiteFunctionMutationResponse(queue.Success, queue.Message, queue);
            }

            if (normalizedAction is "start" or "stop" or "restart" or "recycle")
            {
                var agentAction = normalizedAction switch
                {
                    "start" => "IIS_Pools_AppPool_Start",
                    "stop" => "IIS_Pools_AppPool_Stop",
                    _ => "IIS_Pools_AppPool_Recycle"
                };
                var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = agentAction,
                    ["AppPoolName"] = pool.Name
                });
                if (!call.Success || !call.Preview.Contains("OK", StringComparison.OrdinalIgnoreCase))
                {
                    return new HostingSiteFunctionMutationResponse(false, call.Success ? $"Application Pool agent returned unexpected response: {call.Preview}" : call.Message, call);
                }

                HostingWorkqueueResponse? repairQueue = null;
                if (normalizedAction == "start")
                {
                    await DeletePendingCreatePoolAsync(connection, site.CpLogin, pool.Name);
                    repairQueue = await CreateHostingWorkqueueAsync(connection, cp, new HostingWorkqueueRequest(
                        site.CpId,
                        "createpool",
                        "createpool",
                        pool.Name,
                        site.ServerId,
                        "",
                        site.SiteName,
                        "application-pool"));
                }

                return new HostingSiteFunctionMutationResponse(true, $"Application Pool {normalizedAction} completed.", new { legacy = call, repairQueue });
            }

            if (normalizedAction is "update-pool-ram" or "memory" or "ram")
            {
                var memory = ClampInt(FieldValue(fields, "memory", FieldValue(fields, "newspace", pool.PrivateMemoryMb.ToString(CultureInfo.InvariantCulture))), 256, 40960, pool.PrivateMemoryMb);
                var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "IIS_Pools_AppPool_Memory",
                    ["AppPoolName"] = pool.Name,
                    ["memory"] = memory.ToString(CultureInfo.InvariantCulture),
                    ["privateMemory"] = memory.ToString(CultureInfo.InvariantCulture)
                });
                if (!call.Success)
                {
                    return new HostingSiteFunctionMutationResponse(false, call.Message, call);
                }

                await ExecuteNonQueryAsync(connection, "UPDATE dbo.cp_config_Pools SET privateMemory = @memory WHERE cpID = @cpId AND pool_id = @poolId", command =>
                {
                    command.Parameters.AddWithValue("@memory", memory);
                    command.Parameters.AddWithValue("@cpId", site.CpId);
                    command.Parameters.AddWithValue("@poolId", pool.Id);
                });
                return new HostingSiteFunctionMutationResponse(true, "Application Pool RAM updated.", new { legacy = call, memory });
            }

            if (normalizedAction is "32-bit" or "enable-32-bit" or "64-bit" or "disable-32-bit")
            {
                var enable32Bit = normalizedAction is "32-bit" or "enable-32-bit";
                var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "IIS_Pools_AppPool_Edit",
                    ["AppPoolName"] = pool.Name,
                    ["Properties"] = "enable32BitAppOnWin64",
                    ["Value"] = enable32Bit ? "True" : "False"
                });
                if (!call.Success)
                {
                    return new HostingSiteFunctionMutationResponse(false, call.Message, call);
                }

                await ExecuteNonQueryAsync(connection, "UPDATE dbo.cp_config_Pools SET enable32BitAppOnWin64 = @enabled WHERE cpID = @cpId AND pool_id = @poolId", command =>
                {
                    command.Parameters.AddWithValue("@enabled", enable32Bit);
                    command.Parameters.AddWithValue("@cpId", site.CpId);
                    command.Parameters.AddWithValue("@poolId", pool.Id);
                });
                return new HostingSiteFunctionMutationResponse(true, enable32Bit ? "Application Pool changed to 32-bit." : "Application Pool changed to 64-bit.", call);
            }

            if (normalizedAction is "enable-load-user-profile" or "disable-load-user-profile")
            {
                var enabled = normalizedAction == "enable-load-user-profile";
                var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "IIS_Pools_AppPool_processModel_Edit",
                    ["AppPoolName"] = pool.Name,
                    ["Properties"] = "loadUserProfile",
                    ["Value"] = enabled ? "True" : "False"
                });
                if (!call.Success)
                {
                    return new HostingSiteFunctionMutationResponse(false, call.Message, call);
                }

                await ExecuteNonQueryAsync(connection, "UPDATE dbo.cp_config_Pools SET loadUserProfile = @enabled WHERE cpID = @cpId AND pool_id = @poolId", command =>
                {
                    command.Parameters.AddWithValue("@enabled", enabled);
                    command.Parameters.AddWithValue("@cpId", site.CpId);
                    command.Parameters.AddWithValue("@poolId", pool.Id);
                });
                return new HostingSiteFunctionMutationResponse(true, enabled ? "Load User Profile enabled." : "Load User Profile disabled.", call);
            }

            return new HostingSiteFunctionMutationResponse(false, "Unsupported Application Pool action.", new
            {
                supportedActions = new[] { "create", "change", "start", "stop", "recycle", "ram", "enable-32-bit", "disable-32-bit", "enable-load-user-profile", "disable-load-user-profile" }
            });
        }

        private async Task<HostingPoolActionResponse> RunHostingPoolActionAsync(SqlConnection connection, SelectedHostingCp cp, OwnedApplicationPool pool, string action, Dictionary<string, string> fields)
        {
            var normalizedAction = NormalizeWebsiteAction(action);
            var legacySource = "/Users/erwinyu/Downloads/hosting/cp8/cp/apppoolmgr_action.asp";
            if (normalizedAction is "restart" or "recycle" or "recycle-pool")
            {
                var customerId = await LoadCustomerIdByCpIdAsync(connection, cp.CpId);
                var poolPrefix = cp.CpLogin.Split('-', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).FirstOrDefault();
                var matchName = string.IsNullOrWhiteSpace(poolPrefix) ? pool.Name : poolPrefix;
                var command = $"powershell Get-Process -IncludeUserName | Where UserName -match {matchName} | Stop-Process -force";
                var killCall = await PostLegacyRemoteCommandAsync(GetLegacyAgentSettings(), GetLegacyRemoteCommandSettings(), cp.ServerId, customerId, command);
                if (!killCall.Success)
                {
                    return new HostingPoolActionResponse(false, killCall.Message, new
                    {
                        legacySource = "/Users/erwinyu/Downloads/hosting/cp8/cp/box_info_meter_ajax.asp",
                        pool.Id,
                        pool.Name,
                        matchName,
                        killCall.Url,
                        killCall.Preview
                    });
                }

                var startCall = await PostLegacyAgentAsync(GetLegacyAgentSettings(), cp.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "IIS_Pools_AppPool_Start",
                    ["AppPoolName"] = pool.Name
                }, customerId);

                var startSuccess = startCall.Success && startCall.Preview.Contains("OK", StringComparison.OrdinalIgnoreCase);
                return new HostingPoolActionResponse(true, startSuccess ? "Recycle Pool completed." : $"Recycle Pool completed. Start Pool check returned: {startCall.Message}", new
                {
                    legacySource = "/Users/erwinyu/Downloads/hosting/cp8/cp/box_info_meter_ajax.asp",
                    pool.Id,
                    pool.Name,
                    matchName,
                    killCall = new { killCall.Url, killCall.Preview },
                    startCall = new { startCall.Url, startCall.Preview }
                });
            }

            if (normalizedAction is "start" or "stop")
            {
                var agentAction = normalizedAction switch
                {
                    "start" => "IIS_Pools_AppPool_Start",
                    "stop" => "IIS_Pools_AppPool_Stop",
                    _ => "IIS_Pools_AppPool_Recycle"
                };
                var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), cp.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = agentAction,
                    ["AppPoolName"] = pool.Name
                });

                var success = call.Success && call.Preview.Contains("OK", StringComparison.OrdinalIgnoreCase);
                if (normalizedAction == "start" && success)
                {
                    await DeletePendingCreatePoolAsync(connection, cp.CpLogin, pool.Name);
                    await CreateHostingWorkqueueAsync(connection, cp, new HostingWorkqueueRequest(
                        cp.CpId,
                        "createpool",
                        "createpool",
                        pool.Name,
                        cp.ServerId,
                        "",
                        cp.CpLogin,
                        "application-pool"));
                }

                return new HostingPoolActionResponse(success, success ? $"{PoolActionLabel(normalizedAction)} completed." : call.Message, new
                {
                    legacySource,
                    pool.Id,
                    pool.Name,
                    agentAction,
                    call.Url,
                    call.Preview
                });
            }

            if (normalizedAction is "environment-variables" or "env" or "environmentvariables")
            {
                return new HostingPoolActionResponse(false, "Environment Variables needs the environment-variable service before live changes are enabled.", new
                {
                    legacySource = "/Users/erwinyu/Downloads/hosting/cp8/cp/environment_variables_pool.asp",
                    pool.Id,
                    pool.Name
                });
            }

            if (normalizedAction is "view-log" or "view-pool-log" or "poollog" or "log")
            {
                var call = await PostLegacyPoolLogAsync(cp.ServerId, pool.Name);
                return new HostingPoolActionResponse(call.Success, call.Success ? "Application Pool log loaded." : call.Message, new
                {
                    legacySource = "/Users/erwinyu/Downloads/hosting/cp8/cp/apppoolmgradv.asp",
                    pool.Id,
                    pool.Name,
                    call.Url,
                    call.Preview,
                    logText = call.Success ? call.Body : ""
                });
            }

            if (normalizedAction is "delete" or "delete-pool" or "remove")
            {
                return new HostingPoolActionResponse(false, "Delete Pool needs the old appcmd + cp_config_Pools cleanup flow rebuilt with ownership checks before live deletion is enabled.", new
                {
                    legacySource = "/Users/erwinyu/Downloads/hosting/cp8/cp/apppoolmgr_action.asp",
                    pool.Id,
                    pool.Name
                });
            }

            if (normalizedAction is "1" or "aspnet-4-integrated" or "4.x-i" or "4x-integrated")
            {
                return await EditPoolRuntimeAsync(connection, cp, pool, "v4.0", "0", "4.x(i)", legacySource);
            }

            if (normalizedAction is "2" or "aspnet-4-classic" or "4.x-c" or "4x-classic")
            {
                return await EditPoolRuntimeAsync(connection, cp, pool, "v4.0", "1", "4.x(c)", legacySource);
            }

            if (normalizedAction is "3" or "aspnet-2-integrated" or "2.x-i" or "2x-integrated")
            {
                return await EditPoolRuntimeAsync(connection, cp, pool, "v2.0", "0", "2.x(i)", legacySource);
            }

            if (normalizedAction is "4" or "aspnet-2-classic" or "2.x-c" or "2x-classic")
            {
                return await EditPoolRuntimeAsync(connection, cp, pool, "v2.0", "1", "2.x(c)", legacySource);
            }

            if (normalizedAction is "9" or "net-core" or "dotnet-core")
            {
                return await EditPoolRuntimeAsync(connection, cp, pool, "", "0", "0(i)", legacySource);
            }

            if (normalizedAction is "5" or "32-bit" or "enable-32-bit" or "6" or "64-bit" or "disable-32-bit")
            {
                var enable32 = normalizedAction is "5" or "32-bit" or "enable-32-bit";
                var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), cp.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "IIS_Pools_AppPool_Edit",
                    ["AppPoolName"] = pool.Name,
                    ["Properties"] = "enable32BitAppOnWin64",
                    ["Value"] = enable32 ? "True" : "False"
                });
                if (!call.Success)
                {
                    return new HostingPoolActionResponse(false, call.Message, new { legacySource, call.Url, call.Preview });
                }

                await ExecuteNonQueryAsync(connection, "UPDATE dbo.cp_config_Pools SET enable32BitAppOnWin64 = @enabled WHERE cpID = @cpId AND pool_id = @poolId", command =>
                {
                    command.Parameters.AddWithValue("@enabled", enable32);
                    command.Parameters.AddWithValue("@cpId", cp.CpId);
                    command.Parameters.AddWithValue("@poolId", pool.Id);
                });
                return new HostingPoolActionResponse(true, enable32 ? "Application Pool changed to 32-bit." : "Application Pool changed to 64-bit.", new { legacySource, pool.Id, pool.Name, call.Url, call.Preview });
            }

            if (normalizedAction is "7" or "enable-load-user-profile" or "8" or "disable-load-user-profile")
            {
                var enabled = normalizedAction is "7" or "enable-load-user-profile";
                var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), cp.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "IIS_Pools_AppPool_processModel_Edit",
                    ["AppPoolName"] = pool.Name,
                    ["Properties"] = "loadUserProfile",
                    ["Value"] = enabled ? "True" : "False"
                });
                if (!call.Success)
                {
                    return new HostingPoolActionResponse(false, call.Message, new { legacySource, call.Url, call.Preview });
                }

                await ExecuteNonQueryAsync(connection, "UPDATE dbo.cp_config_Pools SET loadUserProfile = @enabled WHERE cpID = @cpId AND pool_id = @poolId", command =>
                {
                    command.Parameters.AddWithValue("@enabled", enabled);
                    command.Parameters.AddWithValue("@cpId", cp.CpId);
                    command.Parameters.AddWithValue("@poolId", pool.Id);
                });
                return new HostingPoolActionResponse(true, enabled ? "Load User Profile enabled." : "Load User Profile disabled.", new { legacySource, pool.Id, pool.Name, call.Url, call.Preview });
            }

            if (normalizedAction is "update-pool-ram" or "memory" or "ram")
            {
                var memory = ClampInt(FieldValue(fields, "memory", pool.PrivateMemoryMb.ToString(CultureInfo.InvariantCulture)), 256, 40960, pool.PrivateMemoryMb);
                var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), cp.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "IIS_Pools_AppPool_Memory",
                    ["AppPoolName"] = pool.Name,
                    ["memory"] = memory.ToString(CultureInfo.InvariantCulture),
                    ["privateMemory"] = memory.ToString(CultureInfo.InvariantCulture)
                });
                if (!call.Success)
                {
                    return new HostingPoolActionResponse(false, call.Message, new { legacySource, call.Url, call.Preview });
                }

                await ExecuteNonQueryAsync(connection, "UPDATE dbo.cp_config_Pools SET privateMemory = @memory WHERE cpID = @cpId AND pool_id = @poolId", command =>
                {
                    command.Parameters.AddWithValue("@memory", memory);
                    command.Parameters.AddWithValue("@cpId", cp.CpId);
                    command.Parameters.AddWithValue("@poolId", pool.Id);
                });
                return new HostingPoolActionResponse(true, "Application Pool RAM updated.", new { legacySource, pool.Id, pool.Name, memory, call.Url, call.Preview });
            }

            return new HostingPoolActionResponse(false, "Unsupported Application Pool action.", new
            {
                legacySource,
                supportedActions = new[] { "recycle", "start", "stop", "environment-variables", "net-core", "aspnet-4-integrated", "aspnet-4-classic", "aspnet-2-integrated", "aspnet-2-classic", "32-bit", "64-bit", "enable-load-user-profile", "disable-load-user-profile", "view-log", "delete", "ram" }
            });
        }

        private async Task<HostingPoolActionResponse> EditPoolRuntimeAsync(SqlConnection connection, SelectedHostingCp cp, OwnedApplicationPool pool, string runtimeVersion, string pipelineMode, string dbVersion, string legacySource)
        {
            var callRuntime = await PostLegacyAgentAsync(GetLegacyAgentSettings(), cp.ServerId, "/IIS_api.asp", new Dictionary<string, string>
            {
                ["action"] = "IIS_Pools_AppPool_Edit",
                ["AppPoolName"] = pool.Name,
                ["Properties"] = "ManagedRuntimeVersion",
                ["Value"] = runtimeVersion
            });
            var callPipeline = await PostLegacyAgentAsync(GetLegacyAgentSettings(), cp.ServerId, "/IIS_api.asp", new Dictionary<string, string>
            {
                ["action"] = "IIS_Pools_AppPool_Edit",
                ["AppPoolName"] = pool.Name,
                ["Properties"] = "ManagedPipelineMode",
                ["Value"] = pipelineMode
            });
            if (!callRuntime.Success || !callPipeline.Success)
            {
                return new HostingPoolActionResponse(false, !callRuntime.Success ? callRuntime.Message : callPipeline.Message, new
                {
                    legacySource,
                    runtime = callRuntime,
                    pipeline = callPipeline
                });
            }

            await ExecuteNonQueryAsync(connection, "UPDATE dbo.cp_config_Pools SET pool_version = @version WHERE cpID = @cpId AND pool_id = @poolId", command =>
            {
                command.Parameters.AddWithValue("@version", dbVersion);
                command.Parameters.AddWithValue("@cpId", cp.CpId);
                command.Parameters.AddWithValue("@poolId", pool.Id);
            });
            return new HostingPoolActionResponse(true, "Application Pool runtime updated.", new
            {
                legacySource,
                pool.Id,
                pool.Name,
                version = dbVersion,
                runtime = callRuntime.Preview,
                pipeline = callPipeline.Preview
            });
        }

        private static string PoolActionLabel(string normalizedAction) => normalizedAction switch
        {
            "start" => "Start Pool",
            "stop" => "Stop Pool",
            _ => "Recycle Pool"
        };

        private static string NormalizePoolVersion(string version)
        {
            return string.IsNullOrWhiteSpace(version) ? "4.x(i)" : version.Trim();
        }

        private static string PoolVersionLabel(string version)
        {
            return NormalizePoolVersion(version) switch
            {
                "4.x(i)" => "ASP.NET 4.x, Integrated",
                "4.x(c)" => "ASP.NET 4.x, Classic",
                "2.x(i)" => "ASP.NET 2.0/3.0/3.5 SP1, Integrated",
                "2.x(c)" => "ASP.NET 2.0/3.0/3.5 SP1, Classic",
                "0(i)" => ".Net Core(10.x/9.x/8.x/7.x/6.x/5.x/3.x/2.x)",
                var value => value
            };
        }

        private async Task<HostingSiteFunctionMutationResponse> RunWebDeployMutationAsync(SqlConnection connection, OwnedHostingSite site, string action)
        {
            if (action.Equals("fix-acl", StringComparison.OrdinalIgnoreCase) || action.Equals("fixacl", StringComparison.OrdinalIgnoreCase))
            {
                var call = await PostLegacySharedApiAsync(GetLegacySharedApiSettings(), "/tools/resetDefaultPermissionsBySiteUid.asp", new Dictionary<string, string>
                {
                    ["site_Uid"] = site.SiteUid.ToString(CultureInfo.InvariantCulture)
                });

                var processed = call.Success
                    || call.Body.Contains("processed file", StringComparison.OrdinalIgnoreCase)
                    || call.Body.Contains("processing", StringComparison.OrdinalIgnoreCase);

                return new HostingSiteFunctionMutationResponse(
                    processed,
                    processed ? "Fix ACL completed." : call.Message,
                    call);
            }

            var normalized = action.Trim().ToLowerInvariant();
            var siteFullName = $"{site.CpLogin}-{site.SiteName}";
            var agent = GetLegacyAgentSettings();

            if (normalized is "add" or "enable" or "on" or "addiismanageruser")
            {
                var encryptedPassword = await LoadCpPasswordHashAsync(connection, site.CpId);
                var plainPassword = await TryLegacyDecryptPwdApiAsync(
                    ConfigOrEnv("LegacyCrypto:DecryptPwdApiUrl", "LEGACY_DECRYPTPWD_API_URL").Trim(),
                    encryptedPassword);

                if (string.IsNullOrWhiteSpace(plainPassword))
                {
                    return new HostingSiteFunctionMutationResponse(
                        false,
                        "WebDeploy could not be enabled because the hosting account password could not be decrypted.",
                        new { site.SiteUid, siteName = siteFullName });
                }

                var passwordHash = HashHex(SHA256.HashData(Encoding.UTF8.GetBytes(plainPassword)));
                var setUserCall = await PostLegacyAgentAsync(agent, site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "SetIISManagerUser",
                    ["SetAction"] = "AddUser",
                    ["user"] = site.CpLogin,
                    ["pwd"] = passwordHash
                });

                if (!setUserCall.Success)
                {
                    return new HostingSiteFunctionMutationResponse(false, setUserCall.Message, setUserCall);
                }

                var addCall = await PostLegacyAgentAsync(agent, site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "AddIISManagerUser",
                    ["sitename"] = siteFullName,
                    ["user"] = site.CpLogin
                });

                return new HostingSiteFunctionMutationResponse(
                    addCall.Success,
                    addCall.Success ? "WebDeploy / Remote IIS enabled." : addCall.Message,
                    new { setUserCall, addCall });
            }

            if (normalized is "delete" or "disable" or "off" or "deliismanageruser")
            {
                var user = $"ifc\\{site.CpLogin}";
                var deleteCall = await PostLegacyAgentAsync(agent, site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "DelIISManagerUser",
                    ["sitename"] = siteFullName,
                    ["user"] = user
                });

                return new HostingSiteFunctionMutationResponse(
                    deleteCall.Success,
                    deleteCall.Success ? "WebDeploy / Remote IIS disabled." : deleteCall.Message,
                    deleteCall);
            }

            return new HostingSiteFunctionMutationResponse(false, "Choose Enable, Disable, or Fix ACL.", new { action });
        }

        private static async Task<string> LoadCpPasswordHashAsync(SqlConnection connection, long cpId)
        {
            return await ExecuteScalarAsync<string>(connection, @"
SELECT TOP 1 ISNULL(cpPasswordHash, '')
FROM dbo.cp_config
WHERE cpID = @cpId", command => command.Parameters.AddWithValue("@cpId", cpId)) ?? "";
        }

        private async Task<HostingSiteFunctionMutationResponse> RunDomainManagerMutationAsync(SqlConnection connection, OwnedHostingSite site, string action, Dictionary<string, string> fields)
        {
            var normalizedAction = NormalizeWebsiteAction(string.IsNullOrWhiteSpace(action) ? FieldValue(fields, "mode", "add") : action);
            var remove = normalizedAction is "remove" or "delete" or "deletedomain" or "remove-domain" or "deletetempurl";
            var add = normalizedAction is "add" or "create" or "adddomain" or "add-domain" or "save";
            var move = normalizedAction is "move" or "movedomain";
            if (!add && !remove && !move)
            {
                return new HostingSiteFunctionMutationResponse(false, "Domain Manager supports Add, Delete, and Move.", null);
            }

            var domain = NormalizeDomainName(FieldValue(fields, "domain", ""));
            if (!IsSafeDomainForRewrite(domain))
            {
                return new HostingSiteFunctionMutationResponse(false, "Enter a valid domain name.", null);
            }

            var legacySource = "/Users/erwinyu/Downloads/hosting/cp8/cp/domainbind_actions.asp";
            if (remove || move)
            {
                var requestedDomainUid = ParseLong(FieldValue(fields, "domainUid", FieldValue(fields, "DomainUid", "0")));
                var mappedDomain = await LoadSiteDomainMappingAsync(connection, site.SiteUid, requestedDomainUid, domain);
                if (mappedDomain == null)
                {
                    return new HostingSiteFunctionMutationResponse(false, "Domain is not mapped to this website.", null);
                }

                var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "IIS_Member_Binding_Domain_Delete",
                    ["IIS_ID"] = FullIisId(site),
                    ["domainname"] = mappedDomain.DomainName
                });
                if (!call.Success)
                {
                    return new HostingSiteFunctionMutationResponse(false, call.Message, call);
                }

                await ExecuteNonQueryAsync(connection, "DELETE FROM dbo.cp_config_Domains WHERE domain_Uid = @domainUid AND site_Uid = @siteUid", command =>
                {
                    command.Parameters.AddWithValue("@domainUid", mappedDomain.DomainUid);
                    command.Parameters.AddWithValue("@siteUid", site.SiteUid);
                });

                if (remove)
                {
                    return new HostingSiteFunctionMutationResponse(true, "Domain removed from IIS and account data.", new { legacySource, call, domainUid = mappedDomain.DomainUid });
                }

                var toSiteUid = ParseLong(FieldValue(fields, "toSiteUid", FieldValue(fields, "toSite", "0")));
                if (toSiteUid <= 0 || toSiteUid == site.SiteUid)
                {
                    return new HostingSiteFunctionMutationResponse(false, "Choose another website to move this domain to.", null);
                }

                var targetSite = (await LoadOwnedHostingSitesForCpAsync(connection, site.CpId))
                    .FirstOrDefault(candidate => candidate.SiteUid == toSiteUid && !candidate.IsSubdomain);
                if (targetSite == null)
                {
                    return new HostingSiteFunctionMutationResponse(false, "Target website was not found for this hosting account.", null);
                }

                var addMoveCall = await PostLegacyAgentAsync(GetLegacyAgentSettings(), targetSite.ServerId, "/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "IIS_Member_Domain_Add",
                    ["IIS_ID"] = FullIisId(targetSite),
                    ["NewDomain"] = mappedDomain.DomainName,
                    ["ServerComment"] = targetSite.SiteName,
                    ["DomainDir"] = targetSite.SitePath,
                    ["IUSR"] = targetSite.CpLogin,
                    ["NetVer"] = NormalizeSiteNetVersion(targetSite.Version)
                });
                if (!addMoveCall.Success)
                {
                    return new HostingSiteFunctionMutationResponse(false, addMoveCall.Message, new { legacySource, removeCall = call, addCall = addMoveCall });
                }

                var movedDomainUid = await InsertHostingDomainAsync(connection, targetSite.SiteUid, mappedDomain.DomainName);
                return new HostingSiteFunctionMutationResponse(true, "Domain moved to the selected website.", new
                {
                    legacySource,
                    fromSiteUid = site.SiteUid,
                    toSiteUid = targetSite.SiteUid,
                    oldDomainUid = mappedDomain.DomainUid,
                    newDomainUid = movedDomainUid,
                    removeCall = call,
                    addCall = addMoveCall
                });
            }

            var exists = await RowExistsAsync(connection, "SELECT COUNT(*) FROM dbo.cp_config_Domains WHERE LOWER(domain_name) = LOWER(@name)", domain);
            if (exists)
            {
                return new HostingSiteFunctionMutationResponse(false, "This domain is already mapped in the control panel.", null);
            }

            var callAdd = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
            {
                ["action"] = "IIS_Member_Domain_Add",
                ["IIS_ID"] = FullIisId(site),
                ["NewDomain"] = domain,
                ["ServerComment"] = site.SiteName,
                ["DomainDir"] = site.SitePath,
                ["IUSR"] = site.CpLogin,
                ["NetVer"] = NormalizeSiteNetVersion(site.Version)
            });
            if (!callAdd.Success)
            {
                return new HostingSiteFunctionMutationResponse(false, callAdd.Message, callAdd);
            }

            var domainUidAdded = await InsertHostingDomainAsync(connection, site.SiteUid, domain);
            return new HostingSiteFunctionMutationResponse(true, "Domain added to IIS and account data.", new { legacySource, domainUid = domainUidAdded, call = callAdd });
        }

        private async Task<HostingSiteFunctionMutationResponse> RunDeleteWebsiteMutationAsync(SqlConnection connection, OwnedHostingSite site, Dictionary<string, string> fields)
        {
            var confirm = FieldBool(fields, "confirmDelete", false);
            if (!confirm)
            {
                return new HostingSiteFunctionMutationResponse(false, "Please confirm deletion before deleting this website.", null);
            }

            var legacySource = "/Users/erwinyu/Downloads/hosting/cp8/cp/domainbind_actions.asp";
            var relatedDatabaseCount = await ExecuteScalarAsync<int>(connection, @"
SELECT
  (SELECT COUNT(1) FROM dbo.cp_config_mysqls WHERE isdeleted = 0 AND related_site_uid = @siteUid) +
  (SELECT COUNT(1) FROM dbo.cp_config_mssqls WHERE isdeleted = 0 AND related_site_uid = @siteUid)", command =>
            {
                command.Parameters.AddWithValue("@siteUid", site.SiteUid);
            });

            var siteDomains = new List<string>();
            await using (var domainCommand = new SqlCommand(@"
SELECT domain_name
FROM dbo.cp_config_Domains
WHERE site_Uid = @siteUid
ORDER BY domain_name", connection))
            {
                domainCommand.Parameters.AddWithValue("@siteUid", site.SiteUid);
                await using var reader = await domainCommand.ExecuteReaderAsync();
                while (await reader.ReadAsync())
                {
                    var domain = reader["domain_name"]?.ToString()?.Trim();
                    if (!string.IsNullOrWhiteSpace(domain))
                    {
                        siteDomains.Add(domain);
                    }
                }
            }

            var dnsCleanup = new List<object>();
            foreach (var domain in siteDomains)
            {
                var dnsResult = await DeleteTemporaryUrlDnsRecordAsync(domain);
                if (dnsResult == null)
                {
                    dnsCleanup.Add(new
                    {
                        domain,
                        skipped = true,
                        message = "Mapped customer domain DNS zone cleanup is skipped here; temporary URL DNS cleanup was handled."
                    });
                    continue;
                }

                dnsCleanup.Add(new
                {
                    domain,
                    success = dnsResult.Success,
                    message = dnsResult.Message
                });
            }

            var call = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/IIS_api.asp", new Dictionary<string, string>
            {
                ["action"] = "IIS_Member_Domain_Delete",
                ["IIS_ID"] = FullIisId(site)
            });
            if (!call.Success)
            {
                return new HostingSiteFunctionMutationResponse(false, call.Message, call);
            }

            await ExecuteNonQueryAsync(connection, "DELETE FROM dbo.cp_config_Domains WHERE site_Uid = @siteUid", command =>
            {
                command.Parameters.AddWithValue("@siteUid", site.SiteUid);
            });
            await ExecuteNonQueryAsync(connection, "DELETE FROM dbo.cp_config_Sites WHERE site_Uid = @siteUid AND cpID = @cpId", command =>
            {
                command.Parameters.AddWithValue("@siteUid", site.SiteUid);
                command.Parameters.AddWithValue("@cpId", site.CpId);
            });

            LegacyAgentCallResult? deleteFolderCall = null;
            if (FieldBool(fields, "deleteFiles", false))
            {
                deleteFolderCall = await PostLegacyAgentAsync(GetLegacyAgentSettings(), site.ServerId, "/acl_api_2.asp", new Dictionary<string, string>
                {
                    ["action"] = "Delete_Folder",
                    ["dir"] = site.SitePath
                });
            }

            return new HostingSiteFunctionMutationResponse(true, relatedDatabaseCount > 0
                ? $"Website deleted. {relatedDatabaseCount} related database row(s) still need database-section cleanup."
                : "Website deleted from IIS and account data.",
                new { legacySource, call, relatedDatabaseCount, domains = siteDomains, dnsCleanup, deleteFolderCall });
        }

        private async Task<HostingSiteFunctionMutationResponse> RunOutgoingPortMutationAsync(SqlConnection connection, OwnedHostingSite site, string action, Dictionary<string, string> fields)
        {
            var remove = action.Equals("remove", StringComparison.OrdinalIgnoreCase) || action.Equals("delete", StringComparison.OrdinalIgnoreCase);
            var ip = FieldValue(fields, "ip", "");
            var portText = FieldValue(fields, "port", "");
            if (!IPAddress.TryParse(ip, out _) || !int.TryParse(portText, NumberStyles.Integer, CultureInfo.InvariantCulture, out var port) || port is < 1 or > 65535)
            {
                return new HostingSiteFunctionMutationResponse(false, "Enter a valid remote IP address and TCP port.", null);
            }

            if (remove)
            {
                if (!long.TryParse(FieldValue(fields, "ipid", "0"), NumberStyles.Integer, CultureInfo.InvariantCulture, out var ipId) || ipId <= 0)
                {
                    return new HostingSiteFunctionMutationResponse(false, "Outgoing port delete needs the ipid from the existing rule row.", null);
                }

                var ruleName = FieldValue(fields, "rulename", "");
                if (!ruleName.Contains(site.CpLogin, StringComparison.OrdinalIgnoreCase))
                {
                    return new HostingSiteFunctionMutationResponse(false, "Outgoing port rule name does not belong to this hosting account.", null);
                }

                var deleteCall = await PostLegacySharedApiAsync(GetLegacySharedApiSettings(), "/api/firewall_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "del_rule",
                    ["ServerID"] = site.ServerId,
                    ["IP"] = ip,
                    ["port"] = port.ToString(CultureInfo.InvariantCulture),
                    ["rulename"] = ruleName
                });
                if (!deleteCall.Success)
                {
                    return new HostingSiteFunctionMutationResponse(false, deleteCall.Message, deleteCall);
                }

                await using var deleteCommand = new SqlCommand("DELETE FROM dbo.cp_config_db_out_ip WHERE ipid = @ipId AND cpID = @cpId", connection);
                deleteCommand.Parameters.AddWithValue("@ipId", ipId);
                deleteCommand.Parameters.AddWithValue("@cpId", site.CpId);
                await deleteCommand.ExecuteNonQueryAsync();
                return new HostingSiteFunctionMutationResponse(true, "Outgoing port rule deleted.", deleteCall);
            }

            await using var quotaCommand = new SqlCommand(@"
SELECT COUNT(1)
FROM dbo.cp_config_db_out_ip
WHERE cpID = @cpId", connection);
            quotaCommand.Parameters.AddWithValue("@cpId", site.CpId);
            var existingCount = Convert.ToInt32(await quotaCommand.ExecuteScalarAsync(), CultureInfo.InvariantCulture);
            var quota = site.CpLogin.Equals("hiemedia-001", StringComparison.OrdinalIgnoreCase) ? 200 : 100;
            if (existingCount >= quota)
            {
                return new HostingSiteFunctionMutationResponse(false, $"Outgoing port quota reached ({quota}).", null);
            }

            var ruleNameToAdd = $"{site.CpLogin}-{GenerateResetToken()[..4].ToLowerInvariant()}";
            var addCall = await PostLegacySharedApiAsync(GetLegacySharedApiSettings(), "/api/firewall_api.asp", new Dictionary<string, string>
            {
                ["action"] = "add_rule",
                ["ServerID"] = site.ServerId,
                ["IP"] = ip,
                ["port"] = port.ToString(CultureInfo.InvariantCulture),
                ["rulename"] = ruleNameToAdd
            });
            if (!addCall.Success)
            {
                return new HostingSiteFunctionMutationResponse(false, addCall.Message, addCall);
            }

            await using var insertCommand = new SqlCommand(@"
INSERT INTO dbo.cp_config_db_out_ip (cpid, remoteip, port, adddate, rulename)
VALUES (@cpId, @ip, @port, GETDATE(), @ruleName)", connection);
            insertCommand.Parameters.AddWithValue("@cpId", site.CpId);
            insertCommand.Parameters.AddWithValue("@ip", ip);
            insertCommand.Parameters.AddWithValue("@port", port);
            insertCommand.Parameters.AddWithValue("@ruleName", ruleNameToAdd);
            await insertCommand.ExecuteNonQueryAsync();
            return new HostingSiteFunctionMutationResponse(true, "Outgoing port rule added.", addCall);
        }

        private async Task<HostingSiteFunctionMutationResponse> RunScheduleTaskMutationAsync(SqlConnection ehbConnection, OwnedHostingSite site, string action, Dictionary<string, string> fields)
        {
            var scheduleConnectionString = GetScheduleTaskConnectionString();
            if (string.IsNullOrWhiteSpace(scheduleConnectionString))
            {
                return new HostingSiteFunctionMutationResponse(false, "Schedule Task database is not configured. Set SCHEDULE_TASK_CONNECTION_STRING.", null);
            }

            var normalizedAction = NormalizeWebsiteAction(action);
            await using var scheduleConnection = new SqlConnection(scheduleConnectionString);
            await scheduleConnection.OpenAsync();

            if (normalizedAction is "delete" or "remove")
            {
                if (!long.TryParse(FieldValue(fields, "id", FieldValue(fields, "taskId", "0")), NumberStyles.Integer, CultureInfo.InvariantCulture, out var deleteTaskId) || deleteTaskId <= 0)
                {
                    return new HostingSiteFunctionMutationResponse(false, "Schedule Task delete needs a valid task id.", null);
                }

                await using var loadCommand = new SqlCommand("SELECT TOP 1 id, ISNULL(wintask, 0) AS wintask FROM dbo.tasks WHERE id = @id AND cpid = @cpId", scheduleConnection);
                loadCommand.Parameters.AddWithValue("@id", deleteTaskId);
                loadCommand.Parameters.AddWithValue("@cpId", site.CpId);
                await using var reader = await loadCommand.ExecuteReaderAsync();
                if (!await reader.ReadAsync())
                {
                    return new HostingSiteFunctionMutationResponse(false, "Schedule Task was not found for this hosting plan.", null);
                }

                var isWindowsTask = Convert.ToBoolean(reader.GetValue(1), CultureInfo.InvariantCulture);
                await reader.CloseAsync();

                LegacyAgentCallResult? windowsDelete = null;
                if (isWindowsTask)
                {
                    var customerId = await LoadCustomerIdByCpIdAsync(ehbConnection, site.CpId);
                    windowsDelete = await PostLegacyRemoteCommandAsync(
                        GetLegacyAgentSettings(),
                        GetLegacyRemoteCommandSettings(),
                        "208.98.36.176",
                        customerId,
                        $@"cmd /c schtasks.exe /Delete /TN ""{site.CpLogin}-{deleteTaskId}"" /F");
                    if (!windowsDelete.Success)
                    {
                        return new HostingSiteFunctionMutationResponse(false, windowsDelete.Message, windowsDelete);
                    }
                }

                await using var deleteCommand = new SqlCommand("DELETE FROM dbo.tasks WHERE id = @id AND cpid = @cpId", scheduleConnection);
                deleteCommand.Parameters.AddWithValue("@id", deleteTaskId);
                deleteCommand.Parameters.AddWithValue("@cpId", site.CpId);
                await deleteCommand.ExecuteNonQueryAsync();
                return new HostingSiteFunctionMutationResponse(true, "Schedule Task removed.", new { taskId = deleteTaskId, windowsDelete });
            }

            if (normalizedAction is not ("create" or "add"))
            {
                return new HostingSiteFunctionMutationResponse(false, "Schedule Tasks support only add/create and delete/remove actions.", null);
            }

            var url = NormalizeScheduleTaskUrl(FieldValue(fields, "url", ""));
            if (string.IsNullOrWhiteSpace(url))
            {
                return new HostingSiteFunctionMutationResponse(false, "Enter a valid HTTP or HTTPS URL for the task.", null);
            }

            var timeout = ClampInt(FieldValue(fields, "timeout", "20"), 20, 300, 20);
            var taskType = FieldValue(fields, "taskType", FieldValue(fields, "task_type", "sharedtask"));
            var isWindowsTaskToCreate = taskType.Equals("wintask", StringComparison.OrdinalIgnoreCase) || taskType.Equals("windows", StringComparison.OrdinalIgnoreCase);
            var existingCount = await CountScheduleTasksAsync(scheduleConnection, site.CpId, isWindowsTaskToCreate);
            var quota = isWindowsTaskToCreate
                ? await LoadAddonQuotaAsync(ehbConnection, site.CpId, "AdditionalMassSMTP")
                : await LoadScheduleTaskQuotaAsync(ehbConnection, site.CpId);
            if (quota <= 0)
            {
                return new HostingSiteFunctionMutationResponse(false, isWindowsTaskToCreate ? "No Dedicated Windows Task quota is available." : "No Schedule Task quota is available.", null);
            }

            if (existingCount >= quota)
            {
                return new HostingSiteFunctionMutationResponse(false, $"Task quota reached ({existingCount} / {quota}).", null);
            }

            var mode = FieldValue(fields, "mode", FieldValue(fields, "type", "interval"));
            long taskId;
            if (mode.Equals("s", StringComparison.OrdinalIgnoreCase) || mode.Equals("specific", StringComparison.OrdinalIgnoreCase))
            {
                var hour = ClampInt(FieldValue(fields, "certainTime", FieldValue(fields, "ctime", "0")), 0, 23, 0);
                var minute = ClampInt(FieldValue(fields, "certainMin", "0"), 0, 59, 0);
                var day = FieldValue(fields, "certainDay", FieldValue(fields, "cday", "-1"));
                if (!IsSafeScheduleDay(day))
                {
                    return new HostingSiteFunctionMutationResponse(false, "Choose a valid task day value.", null);
                }

                taskId = await InsertSpecificScheduleTaskAsync(scheduleConnection, site.CpId, url, timeout, hour, minute, day, isWindowsTaskToCreate);
            }
            else
            {
                var everyMinutes = ClampInt(FieldValue(fields, "everyMinutes", FieldValue(fields, "emin", "30")), 5, 1440, 30);
                taskId = await InsertIntervalScheduleTaskAsync(scheduleConnection, site.CpId, url, timeout, everyMinutes, isWindowsTaskToCreate);

                if (isWindowsTaskToCreate)
                {
                    var customerId = await LoadCustomerIdByCpIdAsync(ehbConnection, site.CpId);
                    var command = $@"cmd /c schtasks /create /tn ""{site.CpLogin}-{taskId}"" /tr ""powershell.exe -NoProfile -ExecutionPolicy Bypass -File C:\hosting\SCHEDULER\win_task.ps1 -taskID {taskId}"" /sc minute /mo {everyMinutes} /ru System";
                    var windowsCreate = await PostLegacyRemoteCommandAsync(GetLegacyAgentSettings(), GetLegacyRemoteCommandSettings(), "208.98.36.176", customerId, command);
                    if (!windowsCreate.Success)
                    {
                        await using var rollbackCommand = new SqlCommand("DELETE FROM dbo.tasks WHERE id = @id AND cpid = @cpId", scheduleConnection);
                        rollbackCommand.Parameters.AddWithValue("@id", taskId);
                        rollbackCommand.Parameters.AddWithValue("@cpId", site.CpId);
                        await rollbackCommand.ExecuteNonQueryAsync();
                        return new HostingSiteFunctionMutationResponse(false, windowsCreate.Message, windowsCreate);
                    }

                    return new HostingSiteFunctionMutationResponse(true, "Dedicated Windows Task created.", new { taskId, url, timeout, windowsCreate });
                }
            }

            return new HostingSiteFunctionMutationResponse(true, "Schedule Task created.", new { taskId, url, timeout, isWindowsTask = isWindowsTaskToCreate });
        }

        private static string NormalizeScheduleTaskUrl(string value)
        {
            var url = (value ?? "").Trim().Replace(" ", "", StringComparison.Ordinal).Replace(";", "", StringComparison.Ordinal).Replace(",", "", StringComparison.Ordinal);
            if (string.IsNullOrWhiteSpace(url) || url.Length > 500)
            {
                return "";
            }

            if (!url.StartsWith("http://", StringComparison.OrdinalIgnoreCase) && !url.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
            {
                url = $"http://{url}";
            }

            if (!Uri.TryCreate(url, UriKind.Absolute, out var parsed) || parsed.Scheme is not ("http" or "https") || string.IsNullOrWhiteSpace(parsed.Host))
            {
                return "";
            }

            return parsed.ToString();
        }

        private static bool IsSafeScheduleDay(string value)
        {
            var day = (value ?? "").Trim();
            if (day == "-1")
            {
                return true;
            }

            return int.TryParse(day, NumberStyles.Integer, CultureInfo.InvariantCulture, out var number) && number is >= 0 and <= 6;
        }

        private static async Task<int> CountScheduleTasksAsync(SqlConnection connection, long cpId, bool windowsTask)
        {
            await using var command = new SqlCommand("SELECT COUNT(1) FROM dbo.tasks WHERE cpid = @cpId AND ISNULL(wintask, 0) = @windowsTask", connection);
            command.Parameters.AddWithValue("@cpId", cpId);
            command.Parameters.AddWithValue("@windowsTask", windowsTask ? 1 : 0);
            return Convert.ToInt32(await command.ExecuteScalarAsync(), CultureInfo.InvariantCulture);
        }

        private static async Task<long> InsertIntervalScheduleTaskAsync(SqlConnection connection, long cpId, string url, int timeout, int everyMinutes, bool windowsTask)
        {
            await using var command = new SqlCommand(@"
INSERT INTO dbo.tasks (cpid, enterdate, url, everynummin, lastrun, timeout, wintask)
OUTPUT INSERTED.id
VALUES (@cpId, GETDATE(), @url, @everyMinutes, DATEADD(hour, DATEDIFF(hour, 0, GETDATE()), 0), @timeout, @windowsTask)", connection);
            command.Parameters.AddWithValue("@cpId", cpId);
            command.Parameters.AddWithValue("@url", url);
            command.Parameters.AddWithValue("@everyMinutes", everyMinutes);
            command.Parameters.AddWithValue("@timeout", timeout);
            command.Parameters.AddWithValue("@windowsTask", windowsTask ? 1 : 0);
            return Convert.ToInt64(await command.ExecuteScalarAsync(), CultureInfo.InvariantCulture);
        }

        private static async Task<long> InsertSpecificScheduleTaskAsync(SqlConnection connection, long cpId, string url, int timeout, int hour, int minute, string day, bool windowsTask)
        {
            await using var command = new SqlCommand(@"
INSERT INTO dbo.tasks (cpid, enterdate, url, everynummin, lastrun, certainTime, Certainday, timeout, certainMin, wintask)
OUTPUT INSERTED.id
VALUES (@cpId, GETDATE(), @url, 60, '1/1/1999', @hour, @day, @timeout, @minute, @windowsTask)", connection);
            command.Parameters.AddWithValue("@cpId", cpId);
            command.Parameters.AddWithValue("@url", url);
            command.Parameters.AddWithValue("@hour", hour);
            command.Parameters.AddWithValue("@day", day);
            command.Parameters.AddWithValue("@timeout", timeout);
            command.Parameters.AddWithValue("@minute", minute);
            command.Parameters.AddWithValue("@windowsTask", windowsTask ? 1 : 0);
            return Convert.ToInt64(await command.ExecuteScalarAsync(), CultureInfo.InvariantCulture);
        }

        private static async Task<int> LoadAddonQuotaAsync(SqlConnection connection, long cpId, string columnName)
        {
            if (!IsKnownCpConfigQuotaColumn(columnName))
            {
                return 0;
            }

            await using var command = new SqlCommand($"SELECT ISNULL({columnName}, 0) FROM dbo.cp_config WHERE cpID = @cpId", connection);
            command.Parameters.AddWithValue("@cpId", cpId);
            var value = await command.ExecuteScalarAsync();
            return value == null || value == DBNull.Value ? 0 : Convert.ToInt32(value, CultureInfo.InvariantCulture);
        }

        private static bool IsKnownCpConfigQuotaColumn(string columnName) =>
            columnName is "AdditionalScheduleTask" or "AdditionalMassSMTP";

        private static async Task<int> LoadScheduleTaskQuotaAsync(SqlConnection connection, long cpId)
        {
            try
            {
                await using var command = new SqlCommand(@"
SELECT TOP 1 ISNULL(c.AdditionalScheduleTask, 0) + ISNULL(pc.TaskQuota, 0)
FROM dbo.cp_config c
LEFT JOIN dbo.customer_profile profile ON profile.customerID = c.customerID
OUTER APPLY (
    SELECT TOP 1 pc.TaskQuota
    FROM dbo.product_config pc
    INNER JOIN oms.dbo.product p ON pc.fk_oms_product = p.product_id
    WHERE pc.product_name = c.WebHostType
      AND (pc.product_type = profile.customer_type OR pc.product_type = 'individual')
      AND (p.active = 1 OR p.active = 0)
    ORDER BY CASE WHEN pc.product_type = profile.customer_type THEN 0 ELSE 1 END
) pc
WHERE c.cpID = @cpId", connection);
                command.Parameters.AddWithValue("@cpId", cpId);
                var value = await command.ExecuteScalarAsync();
                return value == null || value == DBNull.Value ? 0 : Convert.ToInt32(value, CultureInfo.InvariantCulture);
            }
            catch (SqlException)
            {
                return 0;
            }
        }

        private static async Task<List<Dictionary<string, object?>>> TryLoadFunctionRowsAsync(SqlConnection connection, List<string> warnings, string label, string sql, Action<SqlCommand> addParameters)
        {
            var rows = new List<Dictionary<string, object?>>();
            try
            {
                await using var command = new SqlCommand(sql, connection);
                addParameters(command);
                await using var reader = await command.ExecuteReaderAsync();
                while (await reader.ReadAsync())
                {
                    var row = new Dictionary<string, object?>(StringComparer.OrdinalIgnoreCase);
                    for (var i = 0; i < reader.FieldCount; i++)
                    {
                        row[reader.GetName(i)] = reader.IsDBNull(i) ? null : reader.GetValue(i);
                    }
                    rows.Add(row);
                }
            }
            catch (SqlException ex)
            {
                warnings.Add($"Unable to load {label}: {ex.Message}");
            }

            return rows;
        }

        private static async Task<string> LoadPoolNameAsync(SqlConnection connection, long cpId, int poolId)
        {
            if (poolId <= 0)
            {
                return "";
            }

            await using var command = new SqlCommand(@"
SELECT TOP 1 pool_name
FROM dbo.cp_config_Pools
WHERE cpID = @cpId AND pool_id = @poolId", connection);
            command.Parameters.AddWithValue("@cpId", cpId);
            command.Parameters.AddWithValue("@poolId", poolId);
            var value = await command.ExecuteScalarAsync();
            return value == null || value == DBNull.Value ? "" : Convert.ToString(value, CultureInfo.InvariantCulture)?.Trim() ?? "";
        }

        private static async Task<OwnedApplicationPool?> LoadOwnedPoolAsync(SqlConnection connection, long cpId, int poolId)
        {
            if (poolId <= 0)
            {
                return null;
            }

            await using var command = new SqlCommand(@"
SELECT TOP 1 pool_id,
       ISNULL(pool_name, ''),
       ISNULL(privateMemory, 0),
       ISNULL(pool_version, ''),
       ISNULL(enable32BitAppOnWin64, 0),
       ISNULL(loadUserProfile, 0)
FROM dbo.cp_config_Pools
WHERE cpID = @cpId AND pool_id = @poolId", connection);
            command.Parameters.AddWithValue("@cpId", cpId);
            command.Parameters.AddWithValue("@poolId", poolId);
            await using var reader = await command.ExecuteReaderAsync();
            if (!await reader.ReadAsync())
            {
                return null;
            }

            return new OwnedApplicationPool(
                reader.GetInt32(0),
                reader.GetString(1).Trim(),
                reader.GetInt32(2),
                reader.GetString(3).Trim(),
                reader.GetBoolean(4),
                reader.GetBoolean(5));
        }

        private static async Task<OwnedApplicationPool?> LoadDefaultOwnedPoolAsync(SqlConnection connection, SelectedHostingCp cp)
        {
            await using var command = new SqlCommand(@"
SELECT TOP 1 pool_id,
       ISNULL(pool_name, ''),
       ISNULL(privateMemory, 0),
       ISNULL(pool_version, ''),
       ISNULL(enable32BitAppOnWin64, 0),
       ISNULL(loadUserProfile, 0)
FROM dbo.cp_config_Pools
WHERE cpID = @cpId
ORDER BY CASE WHEN LOWER(pool_name) = LOWER(@cpLogin) THEN 0 ELSE 1 END, pool_id", connection);
            command.Parameters.AddWithValue("@cpId", cp.CpId);
            command.Parameters.AddWithValue("@cpLogin", cp.CpLogin);
            await using var reader = await command.ExecuteReaderAsync();
            if (!await reader.ReadAsync())
            {
                return null;
            }

            return new OwnedApplicationPool(
                reader.GetInt32(0),
                reader.GetString(1).Trim(),
                reader.GetInt32(2),
                reader.GetString(3).Trim(),
                reader.GetBoolean(4),
                reader.GetBoolean(5));
        }

        private static async Task<OwnedApplicationPool?> EnsureDefaultApplicationPoolAsync(SqlConnection connection, SelectedHostingCp cp)
        {
            var existing = await LoadDefaultOwnedPoolAsync(connection, cp);
            if (existing != null)
            {
                return existing;
            }

            var memory = await LoadRamQuotaMbAsync(connection, cp.CpId);
            if (memory <= 0)
            {
                memory = 1024;
            }

            if (memory is 3072 or 6144 or 9216 or 12288)
            {
                memory /= 3;
            }

            await using var command = new SqlCommand(@"
INSERT INTO dbo.cp_config_Pools (cpID, pool_name, privateMemory, create_date)
OUTPUT INSERTED.pool_id
VALUES (@cpId, @poolName, @memory, GETDATE())", connection);
            command.Parameters.AddWithValue("@cpId", cp.CpId);
            command.Parameters.AddWithValue("@poolName", cp.CpLogin);
            command.Parameters.AddWithValue("@memory", memory);
            var value = await command.ExecuteScalarAsync();
            var poolId = value == null || value == DBNull.Value ? 0 : Convert.ToInt32(value, CultureInfo.InvariantCulture);
            if (poolId <= 0)
            {
                return null;
            }

            await ExecuteNonQueryAsync(connection, "UPDATE dbo.cp_config_Sites SET pool_id = @poolId WHERE cpID = @cpId AND ISNULL(pool_id, 0) = 0", update =>
            {
                update.Parameters.AddWithValue("@poolId", poolId);
                update.Parameters.AddWithValue("@cpId", cp.CpId);
            });

            return await LoadOwnedPoolAsync(connection, cp.CpId, poolId);
        }

        private static async Task<List<OwnedApplicationPool>> LoadOwnedPoolsAsync(SqlConnection connection, long cpId)
        {
            var pools = new List<OwnedApplicationPool>();
            await using var command = new SqlCommand(@"
SELECT pool_id,
       ISNULL(pool_name, ''),
       ISNULL(privateMemory, 0),
       ISNULL(pool_version, ''),
       ISNULL(enable32BitAppOnWin64, 0),
       ISNULL(loadUserProfile, 0)
FROM dbo.cp_config_Pools
WHERE cpID = @cpId
ORDER BY pool_id", connection);
            command.Parameters.AddWithValue("@cpId", cpId);

            await using var reader = await command.ExecuteReaderAsync();
            while (await reader.ReadAsync())
            {
                pools.Add(new OwnedApplicationPool(
                    reader.GetInt32(0),
                    reader.GetString(1).Trim(),
                    reader.GetInt32(2),
                    reader.GetString(3).Trim(),
                    reader.GetBoolean(4),
                    reader.GetBoolean(5)));
            }

            return pools;
        }

