            return map.TryGetValue(key, out var spec)
                ? spec
                : new WebsiteFunctionSpec(key, "More Functions", "WEBSITE_MORE_FUNCTIONS_SPEC.md", "Not mapped", "This function still needs a spec mapping.", false, false, new List<string>());
        }

        private static WebsiteRemoteAction? BuildWebsiteFunctionRemoteAction(string key, OwnedHostingSite site, string action, Dictionary<string, string> fields)
        {
            var appPath = NormalizeIisAppPath(FieldValue(fields, "appPath", "/"));
            var enabled = FieldBool(fields, "enabled", !action.Equals("disable", StringComparison.OrdinalIgnoreCase));
            var iisId = FullIisId(site);

            if (key == "default-doc")
            {
                var docs = NormalizeDefaultDocs(FieldValue(fields, "documents", "index.aspx\r\nindex.php\r\nindex.asp\r\nDefault.htm\r\nDefault.asp\r\nindex.htm\r\nindex.html\r\niisstart.htm\r\ndefault.aspx"));
                if (string.IsNullOrWhiteSpace(docs))
                {
                    return null;
                }

                return new WebsiteRemoteAction("/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "IIS_Member_DefaultPage_Edit",
                    ["IIS_ID"] = iisId,
                    ["defaultDocs"] = docs
                });
            }

            if (key == "mime-type")
            {
                var remove = action.Equals("remove", StringComparison.OrdinalIgnoreCase) || action.Equals("delete", StringComparison.OrdinalIgnoreCase);
                var extension = remove
                    ? NormalizeExtensionWithoutDot(FieldValue(fields, "extension", ""))
                    : NormalizeExtension(FieldValue(fields, "extension", ""));
                if (string.IsNullOrWhiteSpace(extension))
                {
                    return null;
                }

                var form = new Dictionary<string, string>
                {
                    ["action"] = remove ? "del_mimeMap" : "add_mimeMap",
                    ["IIS_ID"] = iisId,
                    ["apppath"] = appPath,
                    ["fileExtension"] = extension
                };
                if (!remove)
                {
                    form["mimeType"] = FieldValue(fields, "mimeType", "application/octet-stream");
                }

                return new WebsiteRemoteAction("/IIS_api.asp", form);
            }

            if (key == "script-map")
            {
                var remove = action.Equals("remove", StringComparison.OrdinalIgnoreCase) || action.Equals("delete", StringComparison.OrdinalIgnoreCase);
                if (remove)
                {
                    var tagName = FieldValue(fields, "tagName", FieldValue(fields, "extension", ""));
                    if (string.IsNullOrWhiteSpace(tagName))
                    {
                        return null;
                    }

                    return new WebsiteRemoteAction("/IIS_api.asp", new Dictionary<string, string>
                    {
                        ["action"] = "IIS_Member_IISEntry_CustomScriptMap_Remove",
                        ["IIS_ID"] = iisId,
                        ["TagName"] = tagName
                    });
                }

                var extension = NormalizeScriptMapExtension(FieldValue(fields, "extension", ""));
                var scriptTypeIndex = FieldValue(fields, "scriptTypeIndex", FieldValue(fields, "processor", "1"));
                if (string.IsNullOrWhiteSpace(extension) || !int.TryParse(scriptTypeIndex, NumberStyles.Integer, CultureInfo.InvariantCulture, out var scriptIndex) || scriptIndex <= 0)
                {
                    return null;
                }

                return new WebsiteRemoteAction("/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "IIS_Member_IISEntry_CustomScriptMap_Add",
                    ["IIS_ID"] = iisId,
                    ["scriptTypeIndex"] = scriptIndex.ToString(CultureInfo.InvariantCulture),
                    ["extension"] = extension
                });
            }

            if (key == "site-guard")
            {
                return new WebsiteRemoteAction("/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "IIS_Filter_webknight",
                    ["IIS_ID"] = iisId,
                    ["FW_Action"] = enabled ? "enable" : "disable"
                });
            }

            if (key == "core-mode")
            {
                return new WebsiteRemoteAction("/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "set_HostingModel",
                    ["IIS_ID"] = iisId,
                    ["Mode"] = FieldValue(fields, "hostingModel", "inprocess"),
                    ["apppath"] = appPath
                });
            }

            if (key is "aspnet-version" or "php-version")
            {
                return new WebsiteRemoteAction("/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "IIS_Member_DotNetVersion_Edit_No_Mapping",
                    ["IIS_ID"] = iisId,
                    ["AppPath"] = appPath,
                    ["newversion"] = FieldValue(fields, "version", FieldValue(fields, "phpVersion", "v4.0")),
                    ["Classicmode"] = FieldValue(fields, "pipeline", "Integrated")
                });
            }

            return key switch
            {
                "custom-errors" => new WebsiteRemoteAction("/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "IIS_Member_ErrorPage_Edit",
                    ["IIS_ID"] = iisId,
                    ["errorType"] = FieldValue(fields, "statusCode", "404"),
                    ["filepath"] = FieldValue(fields, "path", "/404.html"),
                    ["defaultError"] = enabled ? "false" : "true"
                }),
                "force-https" => new WebsiteRemoteAction("/api/URLRewrite/create", new Dictionary<string, string>
                {
                    ["action"] = enabled ? "force_https" : "remove_force_https",
                    ["site_uid"] = site.SiteUid.ToString(CultureInfo.InvariantCulture),
                    ["IIS_ID"] = iisId,
                    ["domain"] = FieldValue(fields, "domain", "")
                }),
                "create-net-app" => new WebsiteRemoteAction("/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = action.Equals("delete", StringComparison.OrdinalIgnoreCase) ? "deleteIISApp" : "createIISApp",
                    ["IIS_ID"] = iisId,
                    ["AppPath"] = NormalizeIisAppPath(FieldValue(fields, "appPath", "app"))
                }),
                "virtual-dir" => new WebsiteRemoteAction("/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = action.Equals("delete", StringComparison.OrdinalIgnoreCase) ? "deleteIISVD" : "createIISVD",
                    ["IIS_ID"] = iisId,
                    ["VirtualPath"] = NormalizeIisAppPath(FieldValue(fields, "virtualPath", "vdir")),
                    ["PhysicalPath"] = FieldValue(fields, "physicalPath", site.SitePath)
                }),
                "detail-error" => new WebsiteRemoteAction("/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = "detailerror",
                    ["IIS_ID"] = iisId,
                    ["site_uid"] = site.SiteUid.ToString(CultureInfo.InvariantCulture),
                    ["apppath"] = appPath,
                    ["mode"] = enabled ? "On" : "Off"
                }),
                "ip-deny" => new WebsiteRemoteAction("/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = action.Equals("remove", StringComparison.OrdinalIgnoreCase) ? "remove_ipdeny" : "ipdeny",
                    ["IIS_ID"] = iisId,
                    ["ip"] = FieldValue(fields, "ip", ""),
                    ["mask"] = FieldValue(fields, "mask", "255.255.255.255")
                }),
                "domain-manager" => new WebsiteRemoteAction("/IIS_api.asp", new Dictionary<string, string>
                {
                    ["action"] = action.Equals("remove", StringComparison.OrdinalIgnoreCase) ? "IIS_Member_Domain_Remove" : "IIS_Member_Domain_Add",
                    ["IIS_ID"] = iisId,
                    ["domain"] = FieldValue(fields, "domain", "")
                }),
                _ => null
            };
        }

        private static string FieldValue(Dictionary<string, string> fields, string key, string fallback)
        {
            return fields.TryGetValue(key, out var value) && !string.IsNullOrWhiteSpace(value)
                ? value.Trim()
                : fallback;
        }

        private static bool FieldBool(Dictionary<string, string> fields, string key, bool fallback)
        {
            if (!fields.TryGetValue(key, out var value) || string.IsNullOrWhiteSpace(value))
            {
                return fallback;
            }

            return value.Equals("true", StringComparison.OrdinalIgnoreCase)
                || value.Equals("1", StringComparison.OrdinalIgnoreCase)
                || value.Equals("on", StringComparison.OrdinalIgnoreCase)
                || value.Equals("yes", StringComparison.OrdinalIgnoreCase);
        }

        private static string NormalizeWebsiteAction(string action) =>
            (action ?? "").Trim().ToLowerInvariant().Replace(" ", "-", StringComparison.Ordinal).Replace("_", "-", StringComparison.Ordinal);

        private static string NormalizeIisAppPath(string value)
        {
            var path = (value ?? "").Trim().Replace('\\', '/');
            if (string.IsNullOrWhiteSpace(path) || path == ".")
            {
                return "/";
            }

            return path.StartsWith("/", StringComparison.Ordinal) ? path : $"/{path}";
        }

        private static string NormalizeExtension(string value)
        {
            var extension = NormalizeExtensionWithoutDot(value);
            return string.IsNullOrWhiteSpace(extension) ? "" : $".{extension}";
        }

        private static string NormalizeExtensionWithoutDot(string value)
        {
            var extension = (value ?? "").Trim().TrimStart('.').ToLowerInvariant();
            if (extension.Length > 16)
            {
                extension = extension[..16];
            }

            return new string(extension.Where(ch => char.IsLetterOrDigit(ch) || ch is '-' or '_').ToArray());
        }

        private static List<Dictionary<string, string>> ParseMimeMaps(string body)
        {
            var rows = new List<Dictionary<string, string>>();
            if (string.IsNullOrWhiteSpace(body) || body.Contains("[[Error]]", StringComparison.OrdinalIgnoreCase))
            {
                return rows;
            }

            foreach (var item in body.Split("|+|", StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries))
            {
                var parts = item.Split('|', StringSplitOptions.TrimEntries);
                if (parts.Length < 2)
                {
                    continue;
                }

                var extension = NormalizeExtension(parts[0]);
                var mimeType = parts[1].Trim();
                if (string.IsNullOrWhiteSpace(extension) || string.IsNullOrWhiteSpace(mimeType))
                {
                    continue;
                }

                rows.Add(new Dictionary<string, string>
                {
                    ["extension"] = extension,
                    ["mimeType"] = mimeType
                });
            }

            return rows;
        }

        private static List<Dictionary<string, string>> ParseScriptMaps(string body)
        {
            var rows = new List<Dictionary<string, string>>();
            if (string.IsNullOrWhiteSpace(body) || body.Contains("[[Error]]", StringComparison.OrdinalIgnoreCase))
            {
                return rows;
            }

            foreach (var item in body.Split("|+|", StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries))
            {
                var parts = item.Split('|', StringSplitOptions.TrimEntries);
                if (parts.Length < 4)
                {
                    continue;
                }

                var tagName = parts[0].Trim();
                var extension = NormalizeExtension(parts[1]);
                var scriptTypeIndex = parts[2].Trim();
                var processor = TranslateScriptMapName(parts[3].Trim());
                if (string.IsNullOrWhiteSpace(tagName) || string.IsNullOrWhiteSpace(extension))
                {
                    continue;
                }

                rows.Add(new Dictionary<string, string>
                {
                    ["tagName"] = tagName,
                    ["extension"] = extension,
                    ["scriptTypeIndex"] = scriptTypeIndex,
                    ["processor"] = processor
                });
            }

            return rows
                .OrderBy(row => row["extension"], StringComparer.OrdinalIgnoreCase)
                .ToList();
        }

        private static string TranslateScriptMapName(string value)
        {
            var normalized = (value ?? "").Trim();
            if (string.IsNullOrWhiteSpace(normalized))
            {
                return "Custom Script";
            }

            var lower = normalized.ToLowerInvariant();
            if (lower.Contains("php85")) return "PHP 8.5.x";
            if (lower.Contains("php83")) return "PHP 8.3.x";
            if (lower.Contains("php82")) return "PHP 8.2.x";
            if (lower.Contains("php81")) return "PHP 8.1.x";
            if (lower.Contains("php80")) return "PHP 8.0.x";
            if (lower.Contains("php74")) return "PHP 7.4.x";
            if (lower.Contains("php73")) return "PHP 7.3.x";
            if (lower.Contains("php72")) return "PHP 7.2.x";
            if (lower.Contains("php70")) return "PHP 7.0.x";
            if (lower.Contains("php56")) return "PHP 5.6.x";
            if (lower.Contains("php55")) return "PHP 5.5.x";
            if (lower.Contains("php54")) return "PHP 5.4.x";
            if (lower.Contains("php52")) return "PHP 5.2.x";
            if (lower.Contains("perl")) return "Perl";
            if (lower.Contains("python")) return "Python";
            if (lower.Contains("fastcgi")) return "FastCGI";
            return normalized;
        }

        private static List<Dictionary<string, string>> ParseIisErrorPages(string body)
        {
            var allowed = new HashSet<string>(StringComparer.OrdinalIgnoreCase) { "401", "403", "404", "405", "406", "412", "500", "501" };
            var rows = new List<Dictionary<string, string>>();
            if (string.IsNullOrWhiteSpace(body) || body.Contains("[[Error]]", StringComparison.OrdinalIgnoreCase))
            {
                return rows;
            }

            foreach (var item in body.Split("[|]", StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries))
            {
                var parts = item.Split(',', StringSplitOptions.TrimEntries);
                if (parts.Length < 4 || !allowed.Contains(parts[0]))
                {
                    continue;
                }

                rows.Add(new Dictionary<string, string>
                {
                    ["statusCode"] = parts[0],
                    ["path"] = parts[3]
                });
            }

            return rows
                .OrderBy(row => row["statusCode"], StringComparer.OrdinalIgnoreCase)
                .ToList();
        }

        private static List<Dictionary<string, string>> ParseIisAppList(string body)
        {
            var rows = new List<Dictionary<string, string>>();
            if (string.IsNullOrWhiteSpace(body) || body.Contains("[[Error]]", StringComparison.OrdinalIgnoreCase))
            {
                return rows;
            }

            foreach (var item in body.Split('|', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries))
            {
                var appPath = item.Split(';', StringSplitOptions.TrimEntries)[0].Trim();
                if (string.IsNullOrWhiteSpace(appPath) || appPath.Equals("/_vti_bin", StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }

                rows.Add(new Dictionary<string, string>
                {
                    ["appPath"] = appPath.StartsWith("/", StringComparison.Ordinal) ? appPath : $"/{appPath}"
                });
            }

            return rows
                .DistinctBy(row => row["appPath"], StringComparer.OrdinalIgnoreCase)
                .OrderBy(row => row["appPath"], StringComparer.OrdinalIgnoreCase)
                .ToList();
        }

        private static List<Dictionary<string, string>> ParseIisVirtualDirs(string body, string cpLogin)
        {
            var rows = new List<Dictionary<string, string>>();
            if (string.IsNullOrWhiteSpace(body) || body.Contains("[[Error]]", StringComparison.OrdinalIgnoreCase))
            {
                return rows;
            }

            var homeMarker = $@"h:\root\home\{cpLogin}\www".ToLowerInvariant();
            foreach (var item in body.Split("||", StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries))
            {
                var parts = item.Split('|', StringSplitOptions.TrimEntries);
                if (parts.Length < 2)
                {
                    continue;
                }

                var name = parts[0].Trim();
                var fullPath = parts[1].Trim();
                var displayPath = fullPath.Replace('/', '\\');
                var lower = displayPath.ToLowerInvariant();
                if (lower.StartsWith(homeMarker, StringComparison.OrdinalIgnoreCase))
                {
                    displayPath = displayPath[homeMarker.Length..].TrimStart('\\');
                    displayPath = string.IsNullOrWhiteSpace(displayPath) ? "\\" : $@"\{displayPath}";
                }

                rows.Add(new Dictionary<string, string>
                {
                    ["name"] = name,
                    ["path"] = displayPath
                });
            }

            return rows
                .OrderBy(row => row["name"], StringComparer.OrdinalIgnoreCase)
                .ToList();
        }

        private static string NormalizeScriptMapExtension(string value)
        {
            var extension = new string((value ?? "").Trim().TrimStart('.').Where(char.IsLetterOrDigit).ToArray()).ToLowerInvariant();
            return extension.Length > 4 ? "" : extension;
        }

        private static string NormalizeDefaultDocs(string value)
        {
            var docs = (value ?? "")
                .Split(new[] { '\r', '\n', ',' }, StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .Where(doc =>
                    !string.IsNullOrWhiteSpace(doc)
                    && doc.Count(ch => ch == '.') <= 1
                    && doc.Length <= 80
                    && Regex.IsMatch(doc, @"^[A-Za-z0-9_.\-\s]+$"))
                .Take(40)
                .ToList();

            return string.Join(",", docs);
        }

        private static string FormatDefaultDocsForTextarea(string value)
        {
            var docs = NormalizeDefaultDocs(value)
                .Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);

            return string.Join(Environment.NewLine, docs);
        }

        private static string SafeRewriteRuleName(string value)
        {
            var cleaned = new string((value ?? "").Trim().Where(ch => char.IsLetterOrDigit(ch) || ch is '-' or '_' or '.').ToArray());
            return cleaned.Length > 64 ? cleaned[..64] : cleaned;
        }

        private static string NormalizeLegacyAppPath(string value)
        {
            var path = (value ?? "").Trim().Replace('\\', '/').Trim('/');
            if (string.IsNullOrWhiteSpace(path) || path.Contains("..", StringComparison.Ordinal) || path.Length > 180)
            {
                return "";
            }

            var segments = path.Split('/', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
            if (segments.Length == 0 || segments.Any(segment => segment.Length > 60 || !segment.All(ch => char.IsLetterOrDigit(ch) || ch is '-' or '_' or '.')))
            {
                return "";
            }

            return string.Join('/', segments);
        }

        private static string NormalizeVirtualDirName(string value)
        {
            var name = (value ?? "").Trim().Replace('\\', '/').Trim('/');
            if (string.IsNullOrWhiteSpace(name) || name.Contains('/', StringComparison.Ordinal) || name.Contains("..", StringComparison.Ordinal) || name.Length > 60)
            {
                return "";
            }

            return name.All(ch => char.IsLetterOrDigit(ch) || ch is '-' or '_' or '.') ? name : "";
        }

        private static bool IsSafeIisRelativeFilePath(string value)
        {
            var path = (value ?? "").Trim().Replace('\\', '/');
            if (string.IsNullOrWhiteSpace(path) || path.Length > 180 || path.Contains("..", StringComparison.Ordinal) || path.Contains(':', StringComparison.Ordinal))
            {
                return false;
            }

            if (!path.StartsWith("/", StringComparison.Ordinal))
            {
                return false;
            }

            var segments = path.Split('/', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
            return segments.Length > 0 && segments.All(segment => segment.Length <= 80 && segment.All(ch => char.IsLetterOrDigit(ch) || ch is '-' or '_' or '.' or ' '));
        }

        private static string NormalizeAspNetVersion(string value)
        {
            var normalized = (value ?? "").Trim().ToLowerInvariant();
            return normalized switch
            {
                "4" or "4.x" or "v4" or "v4.0" or "aspnet4" => "v4.0",
                "2" or "2/3.5" or "3.5" or "v2" or "v2.0" or "aspnet2" => "v2.0",
                "1" or "1.x" or "v1" or "v1.1" => "v1.1",
                "0" or "none" or "no-managed-code" => "",
                _ => ""
            };
        }

        private static string NormalizePipelineMode(string value)
        {
            var normalized = (value ?? "").Trim().ToLowerInvariant();
            return normalized.StartsWith("classic", StringComparison.Ordinal) || normalized is "c" or "1"
                ? "Classic"
                : "Integrated";
        }

        private static int NormalizePhpVersionIndex(string value)
        {
            var normalized = (value ?? "").Trim().ToLowerInvariant();
            if (int.TryParse(normalized, NumberStyles.Integer, CultureInfo.InvariantCulture, out var parsed))
            {
                return PhpDisplayVersion(parsed) == "" ? 0 : parsed;
            }

            return normalized switch
            {
                "5.2" or "5.2.x" => 1,
                "5.4" or "5.4.x" => 3,
                "5.5" or "5.5.x" => 4,
                "5.6" or "5.6.x" => 8,
                "7.0" or "7.0.x" => 9,
                "7.2" or "7.2.x" => 10,
                "7.3" or "7.3.x" => 11,
                "7.4" or "7.4.x" => 12,
                "8.0" or "8.0.x" => 13,
                "8.1" or "8.1.x" => 14,
                "8.2" or "8.2.x" => 82,
                "8.3" or "8.3.x" => 83,
                "8.5" or "8.5.x" => 85,
                "disable" or "disabled" or "disable php" => 250,
                _ => 0
            };
        }

        private static string PhpDisplayVersion(int versionIndex) => versionIndex switch
        {
            1 => "5.2.x",
            3 => "5.4.x",
            4 => "5.5.x",
            8 => "5.6.x",
            9 => "7.0.x",
            10 => "7.2.x",
            11 => "7.3.x",
            12 => "7.4.x",
            13 => "8.0.x",
            14 => "8.1.x",
            82 => "8.2.x",
            83 => "8.3.x",
            85 => "8.5.x",
            250 => "Disabled",
            _ => ""
        };

        private static string FormatIisId(string value)
        {
            var text = new string((value ?? "").Trim().Where(char.IsDigit).ToArray());
            if (string.IsNullOrWhiteSpace(text))
            {
                text = "0";
            }

            return text.Length >= 2 ? text[^2..] : text.PadLeft(2, '0');
        }

        private static bool IsSafeDomainForRewrite(string value)
        {
            var domain = (value ?? "").Trim().TrimEnd('/');
            if (string.IsNullOrWhiteSpace(domain) || domain.Length > 255)
            {
                return false;
            }

            return domain.All(ch => char.IsLetterOrDigit(ch) || ch is '-' or '.');
        }

        private static bool IsSafeSiteDisplayName(string value)
        {
            if (string.IsNullOrWhiteSpace(value) || value.Length > 80)
            {
                return false;
            }

            return value.All(ch => char.IsLetterOrDigit(ch) || ch is '-' or '_' or '.');
        }

        private static string DisplaySiteName(OwnedHostingSite site) =>
            string.IsNullOrWhiteSpace(site.DisplayName) ? site.SiteName : site.DisplayName;

        private static string FullIisId(OwnedHostingSite site) =>
            $"{site.CpId}{FormatIisId(ParseInt(site.IisId))}";

        private static int ParseInt(string value) =>
            int.TryParse(value, NumberStyles.Integer, CultureInfo.InvariantCulture, out var number) ? number : 0;

        private static long ParseLong(string value) =>
            long.TryParse(value, NumberStyles.Integer, CultureInfo.InvariantCulture, out var number) ? number : 0;

        private static int ParsePositiveInt(string value, int fallback) =>
            int.TryParse(value, NumberStyles.Integer, CultureInfo.InvariantCulture, out var number) && number > 0 ? number : fallback;

        private static List<Dictionary<string, string>> ParseIpDenyList(string body)
        {
            var rows = new List<Dictionary<string, string>>();
            if (string.IsNullOrWhiteSpace(body) || body.Contains("[[Error]]", StringComparison.OrdinalIgnoreCase))
            {
                return rows;
            }

            foreach (var item in body.Split("|+|", StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries))
            {
                var parts = item.Split('|', StringSplitOptions.TrimEntries);
                if (parts.Length < 2 || !IPAddress.TryParse(parts[0], out _) || !IPAddress.TryParse(parts[1], out _))
                {
                    continue;
                }

                rows.Add(new Dictionary<string, string>
                {
                    ["ipAddress"] = parts[0],
                    ["subnetMask"] = parts[1]
                });
            }

            return rows;
        }

        private static Dictionary<string, object> ParseDynamicIpRestriction(string body)
        {
            var parts = (body ?? "").Split('|', StringSplitOptions.TrimEntries);
            return new Dictionary<string, object>
            {
                ["denyConcurrent"] = parts.Length > 0 && parts[0].Equals("True", StringComparison.OrdinalIgnoreCase),
                ["maxDenyConcurrentNumber"] = parts.Length > 1 && !string.IsNullOrWhiteSpace(parts[1]) ? parts[1] : "5",
                ["denyOverPeriod"] = parts.Length > 2 && parts[2].Equals("True", StringComparison.OrdinalIgnoreCase),
                ["maxDenyNumber"] = parts.Length > 3 && !string.IsNullOrWhiteSpace(parts[3]) ? parts[3] : "20",
                ["timePeriod"] = parts.Length > 4 && !string.IsNullOrWhiteSpace(parts[4]) ? parts[4] : "200"
            };
        }

        private static async Task<HostingSitesDashboard> LoadHostingSitesAsync(SqlConnection connection, long customerId, long requestedCpId = 0)
        {
            const string sql = @"
WITH SelectedCp AS (
    SELECT TOP 1 cpID, cpLogin
    FROM dbo.cp_config
    WHERE customerID = @customerId
      AND ISNULL(hideit, 0) = 0
      AND status <> 3
      AND (@requestedCpId = 0 OR cpID = @requestedCpId)
    ORDER BY CASE WHEN status = 1 THEN 0 ELSE 1 END, cpID
)
SELECT cp.cpID, cp.cpLogin,
       s.site_Uid, s.site_name, s.Display_name, s.site_path, s.iis_status, s.running_status,
       s.version, s.phpversion, s.is_secure, s.isSubdomain, s.create_date,
       d.domain_Uid, d.domain_name, d.cdn, d.isDefault,
       CASE WHEN d.domain_name IS NOT NULL AND (
            EXISTS (
                SELECT 1
                FROM dbo.ssl_order so
                INNER JOIN oms.dbo.client_product product ON product.client_product_id = so.client_product_id
                WHERE product.client_id = @customerId
                  AND so.status <> 'expired'
                  AND so.status <> 'deleted'
                  AND (
                      LOWER(ISNULL(so.CN, '')) = LOWER(d.domain_name)
                      OR LOWER(ISNULL(so.DNSNames, '')) LIKE '%' + LOWER(d.domain_name) + '%'
                  )
            )
            OR EXISTS (
                SELECT 1
                FROM dbo.LetsSSL lets
                WHERE lets.cpID = cp.cpID
                  AND LOWER(ISNULL(lets.cn, '')) = LOWER(d.domain_name)
                  AND ISNULL(lets.status, '') <> 'deleted'
            )
       ) THEN CAST(1 AS bit) ELSE CAST(0 AS bit) END AS ssl_installed
FROM SelectedCp cp
INNER JOIN dbo.cp_config_Sites s ON s.cpID = cp.cpID
LEFT JOIN dbo.cp_config_Domains d ON d.site_Uid = s.site_Uid
ORDER BY s.site_Uid, ISNULL(d.isDefault, 0) DESC, d.create_date, d.domain_Uid";

            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@customerId", customerId);
            command.Parameters.AddWithValue("@requestedCpId", requestedCpId);

            long cpId = 0;
            var cpLogin = "";
            var sites = new Dictionary<int, HostingSiteSummary>();

            await using var reader = await command.ExecuteReaderAsync();
            while (await reader.ReadAsync())
            {
                cpId = reader.GetInt64(0);
                cpLogin = reader.GetString(1);
                var siteUid = reader.GetInt32(2);

                if (!sites.TryGetValue(siteUid, out var site))
                {
                    var displayName = reader.IsDBNull(4) ? "" : reader.GetString(4).Trim();
                    var siteName = reader.GetString(3).Trim();
                    var isSecure = !reader.IsDBNull(10) && reader.GetBoolean(10);
                    var isSubdomain = !reader.IsDBNull(11) && reader.GetBoolean(11);

                    site = new HostingSiteSummary(
                        siteUid,
                        string.IsNullOrWhiteSpace(displayName) ? siteName : displayName,
                        siteName,
                        reader.IsDBNull(5) ? "" : reader.GetString(5).Trim(),
                        reader.IsDBNull(6) || reader.GetBoolean(6) ? "Active" : "Stopped",
                        reader.IsDBNull(7) ? "" : reader.GetString(7).Trim(),
                        reader.IsDBNull(8) ? "" : reader.GetString(8).Trim(),
                        reader.IsDBNull(9) ? "" : reader.GetString(9).Trim(),
                        isSecure,
                        isSubdomain,
                        reader.IsDBNull(12) ? null : DateOnly.FromDateTime(reader.GetDateTime(12)),
                        new List<HostingSiteDomainSummary>()
                    );
                    sites.Add(siteUid, site);
                }

                if (!reader.IsDBNull(13) && !reader.IsDBNull(14))
                {
                    var domain = reader.GetString(14).Trim();
                    if (!string.IsNullOrWhiteSpace(domain))
                    {
                        site.MappedDomains.Add(new HostingSiteDomainSummary(
                            reader.GetInt32(13),
                            domain,
                            $"{(site.IsSecure ? "https" : "http")}://{domain}/",
                            !reader.IsDBNull(15) && reader.GetBoolean(15),
                            !reader.IsDBNull(16) && reader.GetBoolean(16),
                            domain.EndsWith("tempurl.com", StringComparison.OrdinalIgnoreCase) || (!reader.IsDBNull(17) && reader.GetBoolean(17))
                        ));
                    }
                }
            }

            return new HostingSitesDashboard(cpId, cpLogin, new List<HostingSiteSummary>(sites.Values));
        }

        private async Task<HostingDashboardSummary> LoadHostingDashboardAsync(SqlConnection connection, long customerId, long requestedCpId = 0)
        {
            const string cpSql = @"
SELECT TOP 1 cpID, cpLogin, WebHostType, ServerID, status, firstDomain
FROM dbo.cp_config
WHERE customerID = @customerId
  AND ISNULL(hideit, 0) = 0
  AND status <> 3
  AND (@requestedCpId = 0 OR cpID = @requestedCpId)
ORDER BY CASE WHEN status = 1 THEN 0 ELSE 1 END, cpID";

            long cpId = 0;
            var cpLogin = "";
            var webHostType = "";
            var serverId = "";
            var status = "Unknown";
            var primaryDomain = "";

            await using (var command = new SqlCommand(cpSql, connection))
            {
                command.Parameters.AddWithValue("@customerId", customerId);
                command.Parameters.AddWithValue("@requestedCpId", requestedCpId);
                await using var reader = await command.ExecuteReaderAsync();
                if (await reader.ReadAsync())
                {
                    cpId = reader.GetInt64(0);
                    cpLogin = reader.GetString(1).Trim();
                    webHostType = reader.IsDBNull(2) ? "" : reader.GetString(2).Trim();
                    serverId = reader.IsDBNull(3) ? "" : reader.GetString(3).Trim();
                    status = StatusLabel(reader.IsDBNull(4) ? -1 : reader.GetInt32(4));
                    primaryDomain = reader.IsDBNull(5) ? "" : reader.GetString(5).Trim();
                }
            }

            if (cpId == 0)
            {
                return new HostingDashboardSummary(
                    0,
                    "",
                    "",
                    "",
                    "Unknown",
                    "",
                    GetDefaultDnsServers(),
                    GetDefaultHostingIp(),
                    0,
                    0,
                    0,
                    0,
                    0,
                    new List<HostingDashboardMetric>(),
                    new List<HostingHealthLogEntry>(),
                    new HostingHealthLogSummary(0, 0, 0)
                );
            }

            var counts = await LoadDashboardCountsAsync(connection, cpId);
            var siteCount = counts.SiteCount;
            var domainCount = counts.DomainCount;
            var mssqlCount = counts.MssqlCount;
            var mysqlCount = counts.MysqlCount;
            var staticIp = counts.StaticIp;
            var ramQuotaMb = counts.RamQuotaMb;
            var auditConnectionString = GetAuditConnectionString();
            var usedRamTask = LoadRamUsedMbAsync(ramQuotaMb, serverId, cpLogin, webHostType, customerId);
            var auditUsageTask = LoadAuditUsageSafeAsync(auditConnectionString, cpId, cpLogin);
            var realtimeDiskUsageTask = LoadServerDiskUsageTextAsync(serverId, cpLogin);
            var healthLogsTask = LoadPoolHealthLogsAsync(connection, cpId, serverId, cpLogin);

            await Task.WhenAll(usedRamTask, auditUsageTask, realtimeDiskUsageTask, healthLogsTask);

            var usedRamMb = await usedRamTask;
            var auditUsage = await auditUsageTask;
            var bandwidthUsage = auditUsage.BandwidthUsage;
            var diskUsage = auditUsage.DiskUsage;
            var fileUsage = auditUsage.FileUsage;
            var realtimeDiskUsage = await realtimeDiskUsageTask;
            if (!string.IsNullOrWhiteSpace(realtimeDiskUsage))
            {
                diskUsage = realtimeDiskUsage;
            }

            var metrics = new List<HostingDashboardMetric>
            {
                new("Ram Quota", $"{ramQuotaMb} MB", ramQuotaMb),
                new("Bandwidth Usage", bandwidthUsage, null),
                new("Disk Usage", diskUsage, null),
                new("File Usage", fileUsage, null)
            };
            var healthLogs = await healthLogsTask;
            var healthSummary = BuildHealthLogSummary(healthLogs);

            return new HostingDashboardSummary(
                cpId,
                cpLogin,
                string.IsNullOrWhiteSpace(primaryDomain) || primaryDomain.Equals("-NONE-", StringComparison.OrdinalIgnoreCase) ? "" : primaryDomain,
                webHostType,
                status,
                serverId,
                GetDefaultDnsServers(),
                string.IsNullOrWhiteSpace(staticIp) ? GetDefaultHostingIp() : staticIp,
                ramQuotaMb,
                usedRamMb,
                siteCount,
                domainCount,
                mssqlCount + mysqlCount,
                metrics,
                healthLogs,
                healthSummary
            );
        }

        private async Task<List<HostingHealthLogEntry>> LoadPoolHealthLogsAsync(SqlConnection connection, long cpId, string serverId, string cpLogin)
        {
            var pools = await LoadOwnedPoolsAsync(connection, cpId);
            var logTasks = pools.Select(async pool =>
            {
                var poolName = string.IsNullOrWhiteSpace(pool.Name) ? cpLogin : pool.Name;
                var call = await PostLegacyPoolLogAsync(serverId, poolName);
                if (!call.Success)
                {
                    return new List<HostingHealthLogEntry>
                    {
                        new(
                        DateTime.Now.ToString("M/d/yyyy h:mm:ss tt", CultureInfo.InvariantCulture),
                        poolName,
                        call.Message)
                    };
                }

                return ParsePoolHealthLog(poolName, call.Body);
            }).ToList();

            var poolLogs = await Task.WhenAll(logTasks);
            return poolLogs
                .SelectMany(log => log)
                .OrderByDescending(log => TryParseFlexibleDate(log.TimeCreated, out var parsed) ? parsed : DateTime.MinValue)
                .ThenBy(log => log.PoolName, StringComparer.OrdinalIgnoreCase)
                .Take(20)
                .ToList();
        }

        private static List<HostingHealthLogEntry> ParsePoolHealthLog(string poolName, string body)
        {
            var entries = new List<HostingHealthLogEntry>();
            var currentTime = "";
            var currentMessage = new StringBuilder();

            foreach (var rawLine in (body ?? "").Replace("\r\n", "\n", StringComparison.Ordinal).Split('\n'))
            {
                var line = rawLine.TrimEnd();
                if (string.IsNullOrWhiteSpace(line) ||
                    line.StartsWith("TimeCreated", StringComparison.OrdinalIgnoreCase) ||
                    line.StartsWith("-----------", StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }

                if (TrySplitPoolLogLine(line, out var timeCreated, out var message))
                {
                    AddCurrent();
                    currentTime = timeCreated;
                    currentMessage.Append(message.Trim());
                    continue;
                }

                if (currentMessage.Length > 0)
                {
                    currentMessage.Append(' ').Append(line.Trim());
                }
            }

            AddCurrent();
            return entries;

            void AddCurrent()
            {
                var message = currentMessage.ToString().Trim();
                if (!string.IsNullOrWhiteSpace(currentTime) && !string.IsNullOrWhiteSpace(message))
                {
                    entries.Add(new HostingHealthLogEntry(currentTime, poolName, message));
                }

                currentTime = "";
                currentMessage.Clear();
            }
        }

        private static bool TrySplitPoolLogLine(string line, out string timeCreated, out string message)
        {
            timeCreated = "";
            message = "";
            var match = Regex.Match(line, @"^(?<date>\d{1,2}/\d{1,2}/\d{4}\s+\d{1,2}:\d{2}:\d{2}\s+[AP]M)\s+(?<message>.*)$", RegexOptions.IgnoreCase);
            if (!match.Success)
            {
                return false;
            }

            timeCreated = match.Groups["date"].Value.Trim();
            message = match.Groups["message"].Value.Trim();
            return true;
        }

        private static bool TryParseFlexibleDate(string value, out DateTime parsed)
        {
            return DateTime.TryParse(value, CultureInfo.InvariantCulture, DateTimeStyles.AssumeLocal, out parsed)
                || DateTime.TryParse(value, CultureInfo.CurrentCulture, DateTimeStyles.AssumeLocal, out parsed);
        }

        private static HostingHealthLogSummary BuildHealthLogSummary(List<HostingHealthLogEntry> logs)
        {
            var cutoff = DateTime.Now.AddDays(-7);
            var recent = logs.Where(log => TryParseFlexibleDate(log.TimeCreated, out var parsed) && parsed >= cutoff).ToList();
            var communicationErrors = recent.Count(log => log.Message.Contains("communication error", StringComparison.OrdinalIgnoreCase));
            var recycles = recent.Count(log =>
                log.Message.Contains("recycle", StringComparison.OrdinalIgnoreCase) ||
                log.Message.Contains("recycled", StringComparison.OrdinalIgnoreCase) ||
                log.Message.Contains("recycling", StringComparison.OrdinalIgnoreCase));

            return new HostingHealthLogSummary(recent.Count, communicationErrors, recycles);
        }

        private static async Task<int> LoadCountAsync(SqlConnection connection, string sql, long cpId)
        {
            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@cpId", cpId);
