        private static async Task<LegacyAgentCallResult> PostLegacySharedApiAsync(LegacySharedApiSettings settings, string path, Dictionary<string, string> form)
        {
            if (!settings.IsConfigured)
            {
                return new LegacyAgentCallResult(false, settings.MissingMessage, "", "", null);
            }

            var url = $"{settings.Scheme}://{settings.Host}:{settings.Port}{path}";
            try
            {
                using var httpClient = new HttpClient { Timeout = TimeSpan.FromSeconds(30) };
                ApplyLegacySharedApiAuth(httpClient, settings);
                using var content = new FormUrlEncodedContent(form);
                var response = await httpClient.PostAsync(url, content);
                var body = await response.Content.ReadAsStringAsync();
                var accepted = response.IsSuccessStatusCode &&
                    !body.TrimStart().StartsWith("[[Error]]", StringComparison.OrdinalIgnoreCase) &&
                    !body.Contains("error", StringComparison.OrdinalIgnoreCase);

                return accepted
                    ? new LegacyAgentCallResult(true, "Shared API accepted the request.", url, Preview(body), new { status = (int)response.StatusCode }, body)
                    : new LegacyAgentCallResult(false, $"Shared API rejected the request: {Preview(body)}", url, Preview(body), new { status = (int)response.StatusCode }, body);
            }
            catch (Exception ex) when (ex is HttpRequestException or TaskCanceledException)
            {
                return new LegacyAgentCallResult(false, $"Shared API call failed: {ex.Message}", url, "", null);
            }
        }

        private async Task<LegacyAgentCallResult> PostLegacyPoolLogAsync(string serverId, string poolName)
        {
            var settings = GetLegacySharedApiSettings();
            if (!settings.IsConfigured)
            {
                return new LegacyAgentCallResult(false, settings.MissingMessage, "", "", null);
            }

            var url = $"{settings.Scheme}://{settings.Host}:{settings.Port}/api/remote_cmd.asp";
            try
            {
                using var httpClient = new HttpClient { Timeout = TimeSpan.FromSeconds(60) };
                ApplyLegacySharedApiAuth(httpClient, settings);
                using var content = new FormUrlEncodedContent(new Dictionary<string, string>
                {
                    ["ServerID"] = serverId,
                    ["action"] = "poollog",
                    ["poolName"] = poolName
                });
                var response = await httpClient.PostAsync(url, content);
                var body = await response.Content.ReadAsStringAsync();
                var accepted = response.IsSuccessStatusCode && !body.TrimStart().StartsWith("[[Error]]", StringComparison.OrdinalIgnoreCase);
                if (response.StatusCode == HttpStatusCode.Unauthorized)
                {
                    return new LegacyAgentCallResult(false, $"Pool log returned 401 Unauthorized for {url}. The shared API is rejecting this app server/request before the poollog action runs.", url, Preview(body), new { status = (int)response.StatusCode }, body);
                }

                return accepted
                    ? new LegacyAgentCallResult(true, "Pool log loaded.", url, Preview(body), new { status = (int)response.StatusCode }, body)
                    : new LegacyAgentCallResult(false, $"Pool log rejected the request: {Preview(body)}", url, Preview(body), new { status = (int)response.StatusCode }, body);
            }
            catch (Exception ex) when (ex is HttpRequestException or TaskCanceledException)
            {
                return new LegacyAgentCallResult(false, $"Pool log call failed: {ex.Message}", url, "", null);
            }
        }

        private static void ApplyLegacySharedApiAuth(HttpClient httpClient, LegacySharedApiSettings settings)
        {
            if (!settings.HasCredentials)
            {
                return;
            }

            var token = Convert.ToBase64String(Encoding.ASCII.GetBytes($"{settings.Username}:{settings.Password}"));
            httpClient.DefaultRequestHeaders.Authorization = new AuthenticationHeaderValue("Basic", token);
        }

        private static async Task<LegacyAgentCallResult> PostLegacyRemoteCommandAsync(LegacyAgentSettings agentSettings, LegacyRemoteCommandSettings commandSettings, string serverId, long customerId, string command)
        {
            if (!commandSettings.IsConfigured)
            {
                return new LegacyAgentCallResult(false, commandSettings.MissingMessage, "", "", null);
            }

            var tokenHost = $"{serverId}{GenerateResetToken()[..10]}";
            var tokenSetUrl = $"http://{commandSettings.TokenHost}:80/api.asp";
            var host = BuildLegacyHost(agentSettings, serverId);
            var path = string.IsNullOrWhiteSpace(commandSettings.Path) ? "/remotefunc.asp" : commandSettings.Path;
            var remoteUrl = $"{commandSettings.Scheme}://{host}:{commandSettings.Port}{path}";
            try
            {
                using var httpClient = new HttpClient { Timeout = TimeSpan.FromSeconds(100) };
                var tokenSetResponse = await httpClient.PostAsync(tokenSetUrl, new FormUrlEncodedContent(new Dictionary<string, string>
                {
                    ["action"] = "tokenSet",
                    ["serverid"] = tokenHost
                }));
                var stoken3 = (await tokenSetResponse.Content.ReadAsStringAsync()).Trim();
                if (!tokenSetResponse.IsSuccessStatusCode || string.IsNullOrWhiteSpace(stoken3))
                {
                    return new LegacyAgentCallResult(false, $"Remote command token setup failed: {Preview(stoken3)}", tokenSetUrl, Preview(stoken3), new { status = (int)tokenSetResponse.StatusCode });
                }

                var now = DateTime.Now;
                var stoken2 = HashHex(MD5.HashData(Encoding.UTF8.GetBytes($"{commandSettings.Md5Seed}{customerId}{now.Year}{now.Day}")));
                var form = new Dictionary<string, string>
                {
                    ["action"] = "remote_cmd",
                    ["stoken"] = commandSettings.StaticToken,
                    ["stoken2"] = stoken2,
                    ["cid"] = customerId.ToString(CultureInfo.InvariantCulture),
                    ["stoken3"] = stoken3,
                    ["serverid"] = tokenHost,
                    ["cmd"] = command
                };

                var response = await httpClient.PostAsync(remoteUrl, new FormUrlEncodedContent(form));
                var body = await response.Content.ReadAsStringAsync();
                var accepted = response.IsSuccessStatusCode && !body.TrimStart().StartsWith("[[Error]]", StringComparison.OrdinalIgnoreCase);
                return accepted
                    ? new LegacyAgentCallResult(true, "Remote command accepted the request.", remoteUrl, Preview(body), new { status = (int)response.StatusCode })
                    : new LegacyAgentCallResult(false, $"Remote command rejected the request: {Preview(body)}", remoteUrl, Preview(body), new { status = (int)response.StatusCode });
            }
            catch (Exception ex) when (ex is HttpRequestException or TaskCanceledException)
            {
                return new LegacyAgentCallResult(false, $"Remote command failed: {ex.Message}", remoteUrl, "", null);
            }
        }

        private static async Task<OwnedSslOrder?> LoadOwnedSslOrderAsync(SqlConnection connection, long customerId, Dictionary<string, string> fields)
        {
            var orderIdText = GetField(fields, "sslOrderId", GetField(fields, "orderId", ""));
            var commonName = GetField(fields, "domain", GetField(fields, "commonName", ""));
            var hasOrderId = long.TryParse(orderIdText, NumberStyles.Integer, CultureInfo.InvariantCulture, out var orderId) && orderId > 0;
            if (!hasOrderId && string.IsNullOrWhiteSpace(commonName))
            {
                return null;
            }

            const string sql = @"
SELECT TOP 1 so.id,
       so.CN,
       ISNULL(so.email, ''),
       ISNULL(so.CertificateID, ''),
       ISNULL(so.status, '')
FROM dbo.ssl_order so
LEFT JOIN oms.dbo.client_product cp ON so.client_product_id = cp.client_product_id
WHERE so.status <> 'expired'
  AND so.status <> 'deleted'
  AND (cp.client_id = @customerId OR so.customerid = @customerIdText)
  AND (@orderId = 0 OR so.id = @orderId)
  AND (@commonName = '' OR LOWER(so.CN) = LOWER(@commonName))
ORDER BY so.id DESC";

            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@customerId", customerId);
            command.Parameters.AddWithValue("@customerIdText", customerId.ToString(CultureInfo.InvariantCulture));
            command.Parameters.AddWithValue("@orderId", hasOrderId ? orderId : 0);
            command.Parameters.AddWithValue("@commonName", commonName);
            await using var reader = await command.ExecuteReaderAsync();
            if (!await reader.ReadAsync())
            {
                return null;
            }

            return new OwnedSslOrder(
                Convert.ToInt64(reader.GetValue(0), CultureInfo.InvariantCulture),
                reader.IsDBNull(1) ? "" : Convert.ToString(reader.GetValue(1), CultureInfo.InvariantCulture)?.Trim() ?? "",
                reader.IsDBNull(2) ? "" : Convert.ToString(reader.GetValue(2), CultureInfo.InvariantCulture)?.Trim() ?? "",
                reader.IsDBNull(3) ? "" : Convert.ToString(reader.GetValue(3), CultureInfo.InvariantCulture)?.Trim() ?? "",
                reader.IsDBNull(4) ? "" : Convert.ToString(reader.GetValue(4), CultureInfo.InvariantCulture)?.Trim() ?? ""
            );
        }

        private static async Task<OwnedSslRootFtp?> LoadRootFtpForSslExportAsync(SqlConnection connection, SelectedHostingCp cp)
        {
            const string sql = @"
SELECT TOP 1 ftp_login,
       ISNULL(pp1, ''),
       ISNULL(cpurl, '')
FROM dbo.cp_config_FTP
WHERE cpID = @cpId
  AND LOWER(ftp_login) = LOWER(@cpLogin)
ORDER BY ftp_uid DESC";

            await using var command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@cpId", cp.CpId);
            command.Parameters.AddWithValue("@cpLogin", cp.CpLogin);
